        // Get active challenge
        function getActiveChallenge() {
            const profileId = getCurrentProfileId();
            const key = profileId ? `challenge_${profileId}` : 'activeChallenge';
            const saved = localStorage.getItem(key);
            try { return saved ? JSON.parse(saved) : null; } catch(e) { return null; }
        }

        // Save active challenge
        function saveActiveChallenge(challengeData) {
            const profileId = getCurrentProfileId();
            const key = profileId ? `challenge_${profileId}` : 'activeChallenge';
            if (challengeData) {
                localStorage.setItem(key, JSON.stringify(challengeData));
            } else {
                localStorage.removeItem(key);
            }
        }

        // Start a challenge
        function startChallenge(challengeId) {
            const challenge = challengesDatabase.find(c => c.id === challengeId);
            if (!challenge) return;

            const challengeData = {
                ...challenge,
                startDate: new Date().toISOString(),
                completedDays: [],
                currentStreak: 0,
                bestStreak: 0
            };

            saveActiveChallenge(challengeData);
            speak(`Défi ${challenge.name} démarré`);
            renderChallengesTab();
        }

        // Complete today's challenge
        function completeTodayChallenge() {
            const activeChallenge = getActiveChallenge();
            if (!activeChallenge) return;

            const today = new Date().toISOString().split('T')[0];
            
            if (activeChallenge.completedDays.includes(today)) {
                showToast('Vous avez déjà complété le défi aujourd\'hui !', 'info');
                return;
            }

            activeChallenge.completedDays.push(today);

            // Update streak — vérifier si hier était complété
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = yesterday.toISOString().split('T')[0];
            const yesterdayDone = activeChallenge.completedDays.includes(yesterdayStr);
            // Reset streak si un jour a été manqué (sauf 1er jour)
            if (!yesterdayDone && activeChallenge.completedDays.length > 1) {
                activeChallenge.currentStreak = 1;
            } else {
                activeChallenge.currentStreak++;
            }
            if (activeChallenge.currentStreak > activeChallenge.bestStreak) {
                activeChallenge.bestStreak = activeChallenge.currentStreak;
            }

            saveActiveChallenge(activeChallenge);
            speak('Bravo ! Jour complété');
            
            // Confetti effect
            if (activeChallenge.completedDays.length === activeChallenge.duration) {
                showToast('🎉 FÉLICITATIONS ! Vous avez terminé le défi ! 🏆', 'success', 6000);
                speak('Défi terminé avec succès !');
            }
            
            renderChallengesTab();
        }

        // Abandon challenge
        function abandonChallenge() {
            showConfirm('Votre progression sur ce défi sera réinitialisée.', function() {
                saveActiveChallenge(null);
                speak('Défi abandonné');
                renderChallengesTab();
            }, null, { title: 'Abandonner le défi ?', icon: '🏆', confirmLabel: 'Abandonner', danger: true });
        }

