        // ========== FAVORITE EXERCISES SYSTEM ==========
        
        // Get favorite exercises for current profile
        function getFavoriteExercises() {
            const profileId = getCurrentProfileId();
            const key = profileId ? `favorites_${profileId}` : 'favoriteExercises';
            const saved = localStorage.getItem(key);
            try { return saved ? JSON.parse(saved) : []; } catch(e) { return []; }
        }

        // Save favorite exercises
        function saveFavoriteExercises(favorites) {
            const profileId = getCurrentProfileId();
            const key = profileId ? `favorites_${profileId}` : 'favoriteExercises';
            localStorage.setItem(key, JSON.stringify(favorites));
        }

        // Toggle favorite
        function toggleFavorite(exerciseName) {
            favoriteExercises = getFavoriteExercises();
            const index = favoriteExercises.indexOf(exerciseName);
            
            if (index > -1) {
                favoriteExercises.splice(index, 1);
                showToast(`${exerciseName} retiré des favoris`, 'info');
            } else {
                favoriteExercises.push(exerciseName);
                showToast(`${exerciseName} ajouté aux favoris ⭐`, 'success');
            }
            
            saveFavoriteExercises(favoriteExercises);
            filterExercises(); // Refresh display
        }

        // Check if exercise is favorite
        function isFavorite(exerciseName) {
            favoriteExercises = getFavoriteExercises();
            return favoriteExercises.includes(exerciseName);
        }

        // Show only favorite exercises
        function showOnlyFavorites() {
            favoriteExercises = getFavoriteExercises();
            
            if (favoriteExercises.length === 0) {
                showToast('Vous n\'avez aucun exercice favori ! Cliquez sur ⭐ pour en ajouter.', 'info', 4000);
                return;
            }
            
            // Reset filters
            document.getElementById('searchInput').value = '';
            document.getElementById('muscleFilter').value = '';
            document.getElementById('difficultyFilter').value = '';
            document.getElementById('equipmentFilter').value = '';
            
            // Set favorites-only mode
            isShowingFavoritesOnly = true;
            
            // Filter only favorites
            filteredExercises = exerciseDatabase.filter(ex => 
                favoriteExercises.includes(ex.name)
            );
            
            displayExercises(filteredExercises);
            
            // Scroll to results
            const grid = document.getElementById('exercisesGrid');
            if (grid) {
                grid.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
        }

