        function openYouTubeVideo(youtubeId, exerciseName) {
            const query = encodeURIComponent((exerciseName || youtubeId || '') + ' exercice tutoriel forme correcte');
            window.open('https://www.youtube.com/results?search_query=' + query, '_blank');
        }

