            if (mb) mb.style.display = 'none';
            var eb = document.getElementById('equipmentBadges');
            if (eb) { eb.style.display = 'none'; eb.innerHTML = ''; }
            var sb = document.getElementById('swapBtn');
            if (sb) sb.style.display = 'none';
            var nep = document.getElementById('nextExercisePreview');
            if (nep) nep.style.display = 'none';
