            if (repsTracking) repsTracking.style.display = 'none';
            
            // Update buttons
            const pauseBtn = document.getElementById('pauseBtn');
            if (pauseBtn) pauseBtn.textContent = '⏸️ Pause';
            
            // Change "Suivant" button to "Terminer" for cardio
            const skipBtn = document.querySelector('button[onclick="skipExercise()"]');
            if (skipBtn) {
                skipBtn.innerHTML = '🏁 Terminer';
                skipBtn.style.background = 'linear-gradient(135deg, #10b981 0%, #059669 100%)';
            }
            
            // Render initial stats
            renderLiveCardioStats();
