        function renderMusclesChart() {
            const history = getWorkoutHistory();
            const muscleCount = {};
            
            // Count exercises by muscle group
            history.forEach(workout => {
                if (workout.exercises) {
                    workout.exercises.forEach(ex => {
                        if (ex.muscle && ex.muscle !== 'Corps entier' && !ex.isRest) {
                            muscleCount[ex.muscle] = (muscleCount[ex.muscle] || 0) + 1;
                        }
                    });
                }
            });
            
            const sortedMuscles = Object.entries(muscleCount)
                .sort((a, b) => b[1] - a[1])
                .slice(0, 10); // Top 10
            
            if (sortedMuscles.length === 0) {
                showToast('Pas encore de données pour ce graphique', 'info');
                return;
            }
            
            const colors = [
                '#ef4444', '#f59e0b', '#10b981', '#3b82f6', '#22c55e',
                '#ec4899', '#14b8a6', '#f97316', '#06b6d4', '#a855f7'
            ];
            
            const ctx = document.getElementById('progressChart');
            if (!ctx) return;
            
            if (currentChart) currentChart.destroy();
            
            currentChart = new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: sortedMuscles.map(m => m[0]),
                    datasets: [{
                        data: sortedMuscles.map(m => m[1]),
                        backgroundColor: colors,
                        borderWidth: 3,
                        borderColor: '#fff'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: {
                            position: 'right',
                            labels: { 
                                font: { size: 12 },
                                padding: 15
                            }
                        },
                        title: {
                            display: true,
                            text: 'Répartition des muscles travaillés',
                            font: { size: 16, weight: 'bold' },
                            color: '#16a34a'
                        }
                    }
                }
            });
        }

        function renderVolumeChart() {
            const history = getWorkoutHistory();
            const last8Weeks = [];
            const today = new Date();
            
            // Calculate total exercise count per week
            for (let i = 7; i >= 0; i--) {
                const weekStart = new Date(today);
                weekStart.setDate(today.getDate() - (i * 7));
                const weekEnd = new Date(weekStart);
                weekEnd.setDate(weekStart.getDate() + 6);
                
                const weekLabel = `S${8-i}`;
                let totalExercises = 0;
                
                history.forEach(w => {
                    const workoutDate = new Date(w.date);
                    if (workoutDate >= weekStart && workoutDate <= weekEnd && w.exercises) {
                        totalExercises += w.exercises.filter(ex => !ex.isRest && ex.muscle !== 'Cardio').length;
                    }
                });
                
                last8Weeks.push({ label: weekLabel, volume: totalExercises });
            }
            
            const ctx = document.getElementById('progressChart');
            if (!ctx) return;
            
            if (currentChart) currentChart.destroy();
            
            currentChart = new Chart(ctx, {
                type: 'line',
                data: {
                    labels: last8Weeks.map(w => w.label),
                    datasets: [{
                        label: 'Exercices',
                        data: last8Weeks.map(w => w.volume),
                        backgroundColor: 'rgba(16, 185, 129, 0.2)',
                        borderColor: 'rgba(16, 185, 129, 1)',
                        borderWidth: 3,
                        tension: 0.4,
                        fill: true,
                        pointRadius: 5,
                        pointHoverRadius: 7,
                        pointBackgroundColor: 'rgba(16, 185, 129, 1)'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: { display: false },
                        title: {
                            display: true,
                            text: 'Volume d\'entraînement total par semaine',
                            font: { size: 16, weight: 'bold' },
                            color: '#16a34a'
                        }
                    },
                    scales: {
                        y: {
                            beginAtZero: true,
                            ticks: { stepSize: 5 }
                        }
                    }
                }
            });
        }

        // ========== ADVANCED STATISTICS ==========

        function calculateAdvancedStats() {
            const history = getWorkoutHistory();
            
            const stats = {
                totalVolume: 0,
                totalSessions: history.length,
                exerciseCount: {},
                muscleCount: {},
                longestStreak: 0,
                bestWeek: { sessions: 0, week: null }
            };
            
            // Calculate volume and counts
            history.forEach(workout => {
                if (workout.exercises) {
                    workout.exercises.forEach(ex => {
                        if (!ex.isRest && ex.muscle !== 'Cardio') {
                            // Volume (count each exercise)
                            stats.totalVolume += 1;
                            
                            // Exercise count
                            if (ex.name) {
                                stats.exerciseCount[ex.name] = (stats.exerciseCount[ex.name] || 0) + 1;
                            }
                            
                            // Muscle count
                            if (ex.muscle && ex.muscle !== 'Corps entier') {
                                stats.muscleCount[ex.muscle] = (stats.muscleCount[ex.muscle] || 0) + 1;
                            }
                        }
                    });
                }
            });
            
            // Calculate streaks
            stats.longestStreak = calculateLongestStreak(history);
            
            // Find best week
            stats.bestWeek = findBestWeek(history);
            
            // Find top exercises
            stats.topExercises = Object.entries(stats.exerciseCount)
                .sort((a, b) => b[1] - a[1])
                .slice(0, 10);
            
            // Calculate muscle distribution
            const totalMuscle = Object.values(stats.muscleCount).reduce((sum, count) => sum + count, 0);
            stats.muscleDistribution = Object.entries(stats.muscleCount)
                .map(([muscle, count]) => ({
                    muscle,
                    count,
                    percentage: totalMuscle > 0 ? Math.round((count / totalMuscle) * 100) : 0
                }))
                .sort((a, b) => b.count - a.count);
            
            return stats;
        }

        function calculateLongestStreak(history) {
            if (history.length === 0) return 0;
            
            // Sort by date
            const dates = history.map(w => {
                const d = new Date(w.date);
                return new Date(d.getFullYear(), d.getMonth(), d.getDate());
            }).sort((a, b) => a - b);
            
            // Remove duplicates (same day)
            const uniqueDates = [...new Set(dates.map(d => d.getTime()))].map(t => new Date(t));
            
            if (uniqueDates.length === 0) return 0;
            
            let longestStreak = 1;
            let currentStreak = 1;
            
            for (let i = 1; i < uniqueDates.length; i++) {
                const daysDiff = Math.floor((uniqueDates[i] - uniqueDates[i-1]) / (1000 * 60 * 60 * 24));
                
                if (daysDiff === 1) {
                    currentStreak++;
                    longestStreak = Math.max(longestStreak, currentStreak);
                } else if (daysDiff > 1) {
                    currentStreak = 1;
                }
            }
            
            return longestStreak;
        }

        function findBestWeek(history) {
            if (history.length === 0) return { sessions: 0, week: null };
            
            const weekCounts = {};
            
            history.forEach(workout => {
                const date = new Date(workout.date);
                const weekStart = new Date(date);
                weekStart.setDate(date.getDate() - date.getDay());
                const weekKey = weekStart.toISOString().split('T')[0];
                
                weekCounts[weekKey] = (weekCounts[weekKey] || 0) + 1;
            });
            
            let bestWeek = { sessions: 0, week: null };
            
            Object.entries(weekCounts).forEach(([week, count]) => {
                if (count > bestWeek.sessions) {
                    bestWeek = { sessions: count, week };
                }
            });
            
            return bestWeek;
        }

