        // ========== SUPERSETS, CIRCUITS & AMRAP ==========

        function suggestIntelligentSuperset() {
            const equipment = getSelectedEquipmentNames();
            const blacklist = getExerciseBlacklist();
            const allPerformances = JSON.parse(localStorage.getItem('exercisePerformance') || '{}');
            
            // Find exercises where user performs well (success rate >60%)
            const goodExercises = Object.entries(allPerformances)
                .filter(([name, perf]) => {
                    const successRate = perf.history ? 
                        perf.history.filter(h => h.difficulty <= 3).length / perf.history.length : 0.5;
                    return successRate > 0.6;
                })
                .map(([name]) => exerciseDatabase.find(ex => ex.name === name))
                .filter(ex => ex && 
                    !blacklist.includes(ex.name) &&
                    ex.equipment.some(eq => equipment.includes(eq))
                );
            
            if (goodExercises.length < 2) {
                showToast('💡 Faites plus d\'exercices pour obtenir des suggestions', 'info', 3000);
                return null;
            }
            
            // Try antagonist superset (push/pull)
            const pushExercises = goodExercises.filter(ex => 
                ['Pectoraux', 'Épaules', 'Triceps'].includes(ex.muscle)
            );
            const pullExercises = goodExercises.filter(ex => 
                ['Dos', 'Biceps'].includes(ex.muscle)
            );
            
            if (pushExercises.length > 0 && pullExercises.length > 0) {
                const suggestion = {
                    type: 'antagonist',
                    name: '💪 Superset Push/Pull Recommandé',
                    exercises: [
                        { exercise: pushExercises[0], reps: 10 },
                        { exercise: pullExercises[0], reps: 10 }
                    ],
                    sets: 3,
                    restAfter: 90,
                    reason: 'Superset antagoniste basé sur vos performances'
                };
                return suggestion;
            }
            
            // Try agonist superset (same muscle group)
            const legExercises = goodExercises.filter(ex => 
                ['Quadriceps', 'Ischio-jambiers', 'Fessiers'].includes(ex.muscle)
            );
            
            if (legExercises.length >= 2) {
                const suggestion = {
                    type: 'agonist',
                    name: '🦵 Superset Jambes Recommandé',
                    exercises: [
                        { exercise: legExercises[0], reps: 12 },
                        { exercise: legExercises[1], reps: 12 }
                    ],
                    sets: 3,
                    restAfter: 120,
                    reason: 'Superset jambes basé sur vos performances'
                };
                return suggestion;
            }
            
            // Default: any 2 good exercises
            if (goodExercises.length >= 2) {
                const suggestion = {
                    type: 'mixed',
                    name: '⚡ Superset Personnalisé',
                    exercises: [
                        { exercise: goodExercises[0], reps: 10 },
                        { exercise: goodExercises[1], reps: 10 }
                    ],
                    sets: 3,
                    restAfter: 90,
                    reason: 'Basé sur vos meilleurs exercices'
                };
                return suggestion;
            }
            
            return null;
        }
        
        function showSupersetSuggestion() {
            const suggestion = suggestIntelligentSuperset();
            if (!suggestion) return;

            showConfirm(
                `${suggestion.name} — ${suggestion.exercises[0].exercise.name} + ${suggestion.exercises[1].exercise.name} · ${suggestion.sets} séries · ${suggestion.restAfter}s repos`,
                function() {
                    currentSupersetWorkout = {
                        type: 'superset',
                        name: suggestion.name,
                        sets: suggestion.sets,
                        restAfter: suggestion.restAfter,
                        exercises: suggestion.exercises.map(item => ({
                            ...item.exercise,
                            reps: item.reps
                        })),
                        currentSet: 1,
                        currentExerciseIndex: 0
                    };
                
                switchTab('workouts');
                document.getElementById('workoutSelection').style.display = 'none';
                document.getElementById('exerciseView').classList.remove('hidden'); document.body.classList.add('in-session');
                
                speak('Démarrage superset suggéré');
                showToast(`🔗 ${suggestion.name} démarré !`, 'success', 3000);
                startSupersetExercise();
            }, null, { title: 'Démarrer ce superset ?', icon: '🔗', confirmLabel: 'Démarrer' });
        }

        const predefinedSupersets = {
            'push-pull': {
                name: 'Push/Pull Upper',
                exercises: [
                    { name: 'Pompes classiques', reps: 12 },
                    { name: 'Tractions pronation', reps: 8 }
                ],
                sets: 3,
                rest: 90
            },
            'pecs-dos': {
                name: 'Pecs/Dos Haltères',
                exercises: [
                    { name: 'Développé couché haltères', reps: 10 },
                    { name: 'Rowing haltère un bras', reps: 10 }
                ],
                sets: 3,
                rest: 90
            },
            'bras': {
                name: 'Biceps/Triceps',
                exercises: [
                    { name: 'Curl biceps haltères', reps: 12 },
                    { name: 'Extensions nuque haltère', reps: 12 }
                ],
                sets: 3,
                rest: 60
            },
            'jambes': {
                name: 'Jambes Explosif',
                exercises: [
                    { name: 'Squats', reps: 15 },
                    { name: 'Fentes avant', reps: 12 },
                    { name: 'Jump squats', reps: 10 }
                ],
                sets: 3,
                rest: 120
            }
        };

        function startPredefinedSuperset(supersetId) {
            const preset = predefinedSupersets[supersetId];
            if (!preset) return;

            showConfirm(`Démarrer le superset "${preset.name}" ? ${preset.sets} séries • ${preset.rest}s repos`, function() {
                const exercises = preset.exercises.map(item => {
                    const ex = exerciseDatabase.find(e => e.name === item.name);
                    return ex ? { ...ex, reps: item.reps, sets: preset.sets } : null;
                }).filter(ex => ex);

                if (exercises.length !== preset.exercises.length) {
                    showToast('⚠️ Certains exercices ne sont pas disponibles', 'error');
                    return;
                }

                const workoutExercises = [];
                for (let set = 1; set <= preset.sets; set++) {
                    exercises.forEach((ex, idx) => {
                        workoutExercises.push({ ...ex, duration: 60 });
                        if (idx < exercises.length - 1 || set < preset.sets) {
                            workoutExercises.push({ name: "Repos", duration: preset.rest, isRest: true, mode: 'timer' });
                        }
                    });
                }

                const workout = {
                    type: 'superset',
                    name: preset.name,
                    exercises: workoutExercises,
                    badgeHTML: `🔗 Superset : ${preset.name}`,
                    badgeStyle: 'linear-gradient(135deg, #22c55e 0%, #166534 100%)'
                };
                showWorkoutPreparation(workout);
            }, null, { title: 'Démarrer le superset ?', icon: '🔗', confirmLabel: 'Démarrer' });
        }

        let supersetExercisesList = [];
        let circuitExercisesList = [];
        let amrapExercisesList = [];
        let currentSupersetWorkout = null;
        let currentCircuitWorkout = null;
        let currentAMRAPWorkout = null;

        // ===== SUPERSET FUNCTIONS =====

        function openSupersetBuilder() {
            supersetExercisesList = [
                { exercise: null, reps: 10 },
                { exercise: null, reps: 10 }
            ];
            // Reset filters
            const sf = document.getElementById('supersetSearchFilter');
            const sm = document.getElementById('supersetMuscleFilter');
            const se = document.getElementById('supersetEquipFilter');
            const sd = document.getElementById('supersetDiffFilter');
            if (sf) sf.value = '';
            if (sm) sm.value = '';
            if (se) se.value = '';
            if (sd) sd.value = '';
            document.getElementById('supersetModal').classList.add('active');
            renderSupersetExercises();
        }

        function closeSupersetModal() {
            document.getElementById('supersetModal').classList.remove('active');
            supersetExercisesList = [];
        }

        function addSupersetExercise() {
            if (supersetExercisesList.length >= 3) {
                showToast('Maximum 3 exercices par superset', 'warning');
                return;
            }
            supersetExercisesList.push({ exercise: null, reps: 10 });
            renderSupersetExercises();
        }

        function removeSupersetExercise(index) {
            supersetExercisesList.splice(index, 1);
            renderSupersetExercises();
        }

        function renderSupersetExercises() {
            const container = document.getElementById('supersetExercises');
            if (!container) return;
            const letters = ['A', 'B', 'C'];
            
            container.innerHTML = supersetExercisesList.map((item, idx) => `
                <div style="background: #f9fafb; padding: 15px; border-radius: 8px; border-left: 4px solid #22c55e;">
                    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;">
                        <span style="font-weight: bold; color: #22c55e; font-size: 1.2em;">${letters[idx]})</span>
                        ${supersetExercisesList.length > 2 ? `
                            <button onclick="removeSupersetExercise(${idx})" style="background: #ef4444; color: white; border: none; padding: 5px 10px; border-radius: 5px; cursor: pointer;">✕</button>
                        ` : ''}
                    </div>
                    <select id="supersetSelect_${idx}" onchange="supersetExercisesList[${idx}].exercise = this.value" style="width: 100%; padding: 10px; border: 2px solid #bbf7d0; border-radius: 8px; margin-bottom: 10px; background: #fff8f6; color: #166534;">
                        <option value="">Choisir un exercice...</option>
                    </select>
                    <div style="display: flex; gap: 10px; align-items: center;">
                        <label style="color: #666;">Répétitions :</label>
                        <input type="number" value="${item.reps}" min="1" max="50" 
                               onchange="supersetExercisesList[${idx}].reps = parseInt(this.value)"
                               style="width: 80px; padding: 8px; border: 2px solid #e0e0e0; border-radius: 8px;">
                    </div>
                </div>
            `).join('');

            // Populate options without losing selections
            updateSupersetOptions();
        }

        function updateSupersetOptions() {
            const searchVal = (document.getElementById('supersetSearchFilter')?.value || '').toLowerCase();
            const muscleVal = document.getElementById('supersetMuscleFilter')?.value || '';
            const equipVal  = document.getElementById('supersetEquipFilter')?.value  || '';
            const diffVal   = document.getElementById('supersetDiffFilter')?.value   || '';

            const filteredDB = exerciseDatabase.filter(ex => {
                if (ex.type !== 'exercise') return false;
                if (searchVal && !ex.name.toLowerCase().includes(searchVal) && !(ex.muscle||'').toLowerCase().includes(searchVal)) return false;
                if (muscleVal && ex.muscle !== muscleVal) return false;
                if (equipVal  && !(ex.equipment || ['Poids du corps']).some(e => e === equipVal)) return false;
                if (diffVal   && ex.difficulty !== diffVal) return false;
                return true;
            });

            supersetExercisesList.forEach((item, idx) => {
                const sel = document.getElementById(`supersetSelect_${idx}`);
                if (!sel) return;
                const currentVal = item.exercise || '';
                let options = `<option value="">Choisir... (${filteredDB.length} dispo)</option>`;
                // If selected exercise is outside the filter, keep it visible at top
                if (currentVal && !filteredDB.find(ex => ex.name === currentVal)) {
                    const ex = exerciseDatabase.find(e => e.name === currentVal);
                    if (ex) options += `<option value="${ex.name}" selected>✓ ${ex.name} — ${ex.muscle}</option>`;
                }
                options += filteredDB.map(ex =>
                    `<option value="${ex.name}" ${ex.name === currentVal ? 'selected' : ''}>${ex.name} — ${ex.muscle}${ex.equipment?.length ? ' · ' + ex.equipment[0] : ''}</option>`
                ).join('');
                sel.innerHTML = options;
            });
        }

        function startSuperset() {
            const name = document.getElementById('supersetName').value || 'Mon Superset';
            const sets = parseInt(document.getElementById('supersetSets').value);
            const rest = parseInt(document.getElementById('supersetRest').value);
            
            // Validate
            const validExercises = supersetExercisesList.filter(item => item.exercise);
            if (validExercises.length < 2) {
                showToast('Sélectionnez au moins 2 exercices', 'error');
                return;
            }
            
            // Create workout
            const exercises = validExercises.map(item => {
                const ex = exerciseDatabase.find(e => e.name === item.exercise);
                return {
                    ...ex,
                    reps: item.reps,
                    sets: sets
                };
            });
            
            // Build workout with exercises and rest periods
            const workoutExercises = [];
            for (let set = 1; set <= sets; set++) {
                exercises.forEach((ex, idx) => {
                    workoutExercises.push({ ...ex, duration: 60 });
                    if (idx < exercises.length - 1 || set < sets) {
                        workoutExercises.push({
                            name: "Repos",
                            duration: rest,
                            isRest: true, mode: 'timer'
                        });
                    }
                });
            }
            
            const workout = {
                type: 'superset',
                name: name,
                exercises: workoutExercises,
                badgeHTML: `🔗 Superset : ${name}`,
                badgeStyle: 'linear-gradient(135deg, #22c55e 0%, #166534 100%)'
            };
            
            closeSupersetModal();
            startQuickCheck(workout); // ✅ AI Workout DJ
        }

        function startSupersetExercise() {
            if (!currentSupersetWorkout) return;
            
            const ex = currentSupersetWorkout.exercises[currentSupersetWorkout.currentExerciseIndex];
            const letters = ['A', 'B', 'C'];
            const letter = letters[currentSupersetWorkout.currentExerciseIndex];
            
            // Update UI
            document.getElementById('exerciseName').textContent = `${letter}) ${ex.name}`;
            document.getElementById('exerciseInstructions').innerHTML = ex.instructions.map(inst => 
                `<li>${inst}</li>`
            ).join('');
            
            // Update set info
            const setInfo = document.getElementById('exerciseSetInfo');
            if (setInfo) {
                setInfo.textContent = `Série ${currentSupersetWorkout.currentSet}/${currentSupersetWorkout.sets}`;
            }
            
            // Show reps info
            const repsInfo = document.createElement('div');
            repsInfo.style.cssText = 'text-align: center; font-size: 2em; font-weight: bold; color: #22c55e; margin: 20px 0;';
            repsInfo.textContent = `${ex.reps} répétitions`;
            
            const instructionsContainer = document.getElementById('exerciseInstructions').parentElement;
            const existingReps = instructionsContainer.querySelector('.reps-display');
            if (existingReps) existingReps.remove();
            repsInfo.className = 'reps-display';
            instructionsContainer.insertBefore(repsInfo, document.getElementById('exerciseInstructions'));
            
            speak(`${letter} ${ex.name}. ${ex.reps} répétitions`);
        }

        function nextSupersetExercise() {
            if (!currentSupersetWorkout) return;
            
            currentSupersetWorkout.currentExerciseIndex++;
            
            if (currentSupersetWorkout.currentExerciseIndex >= currentSupersetWorkout.exercises.length) {
                // Superset round completed
                currentSupersetWorkout.currentExerciseIndex = 0;
                currentSupersetWorkout.currentSet++;
                
                if (currentSupersetWorkout.currentSet > currentSupersetWorkout.sets) {
                    // All sets completed
                    completeSuperset();
                    return;
                }
                
                // Rest after superset
                showToast(`✅ Série ${currentSupersetWorkout.currentSet - 1} terminée !`, 'success');
                speak(`Repos ${currentSupersetWorkout.restAfter} secondes`);
                
                // Show rest timer
                isPaused = false;
                timeLeft = currentSupersetWorkout.restAfter;
                startTimer();
            } else {
                // Next exercise in superset (no rest)
                speak('Enchaînez !');
                setTimeout(() => startSupersetExercise(), 1000);
            }
        }

        function completeSuperset() {
            if (!currentSupersetWorkout) return;
            
            showToast(`🎉 Superset "${currentSupersetWorkout.name}" terminé ! Bravo !`, 'success', 5000);
            speak('Superset terminé ! Félicitations !');
            
            // Save to history
            const workout = {
                name: currentSupersetWorkout.name,
                type: 'superset',
                date: new Date().toISOString(),
                duration: currentSupersetWorkout.sets * currentSupersetWorkout.exercises.length * 60,
                exercises: currentSupersetWorkout.exercises
            };
            saveWorkoutToHistory(workout);
            
            currentSupersetWorkout = null;
            
            setTimeout(() => {
                document.getElementById('exerciseView').classList.add('hidden'); document.body.classList.remove('in-session');
                document.getElementById('workoutSelection').style.display = 'block';
                switchTab('home');
            }, 3000);
        }

