        function updateCircuitOptions() {
            const searchVal = (document.getElementById('circuitSearchFilter')?.value || '').toLowerCase();
            const muscleVal = document.getElementById('circuitMuscleFilter')?.value || '';
            const equipVal  = document.getElementById('circuitEquipFilter')?.value  || '';
            const diffVal   = document.getElementById('circuitDiffFilter')?.value   || '';

            const filteredDB = exerciseDatabase.filter(ex => {
                if (ex.type !== 'exercise') return false;
                if (searchVal && !ex.name.toLowerCase().includes(searchVal) && !(ex.muscle||'').toLowerCase().includes(searchVal)) return false;
                if (muscleVal && ex.muscle !== muscleVal) return false;
                if (equipVal  && !(ex.equipment || ['Poids du corps']).some(e => e === equipVal)) return false;
                if (diffVal   && ex.difficulty !== diffVal) return false;
                return true;
            });

            circuitExercisesList.forEach((item, idx) => {
                const sel = document.getElementById(`circuitSelect_${idx}`);
                if (!sel) return;
                const currentVal = item.exercise || '';
                let options = `<option value="">Choisir... (${filteredDB.length} dispo)</option>`;
                if (currentVal && !filteredDB.find(ex => ex.name === currentVal)) {
                    const ex = exerciseDatabase.find(e => e.name === currentVal);
                    if (ex) options += `<option value="${ex.name}" selected>✓ ${ex.name} — ${ex.muscle}</option>`;
                }
                options += filteredDB.map(ex =>
                    `<option value="${ex.name}" ${ex.name === currentVal ? 'selected' : ''}>${ex.name} — ${ex.muscle}${ex.equipment?.length ? ' · ' + ex.equipment[0] : ''}</option>`
                ).join('');
                sel.innerHTML = options;
            });
        }

        function startCircuit() {
            const name = document.getElementById('circuitName').value || 'Mon Circuit';
            const rounds = parseInt(document.getElementById('circuitRounds').value);
            const rest = parseInt(document.getElementById('circuitRest').value);
            
            const validExercises = circuitExercisesList.filter(item => item.exercise);
            if (validExercises.length < 4) {
                showToast('Sélectionnez au moins 4 exercices', 'error');
                return;
            }
            
            const exercises = validExercises.map(item => {
                const ex = exerciseDatabase.find(e => e.name === item.exercise);
                return { ...ex, reps: item.reps };
            });
            
            // Build workout with rounds and rest
            const workoutExercises = [];
            for (let round = 1; round <= rounds; round++) {
                exercises.forEach((ex, idx) => {
                    workoutExercises.push({ ...ex, duration: 60 });
                    if (idx === exercises.length - 1 && round < rounds) {
                        // Rest between rounds
                        workoutExercises.push({
                            name: "Repos entre rounds",
                            duration: rest,
                            isRest: true, mode: 'timer'
                        });
                    }
                });
            }
            
            const workout = {
                type: 'circuit',
                name: name,
                exercises: workoutExercises,
                badgeHTML: `🔄 Circuit : ${name}`,
                badgeStyle: 'linear-gradient(135deg, #15803d 0%, #166534 100%)'
            };
            
            closeCircuitModal();
            startQuickCheck(workout); // ✅ AI Workout DJ
        }

        function startCircuitExercise() {
            if (!currentCircuitWorkout) return;
            
            const ex = currentCircuitWorkout.exercises[currentCircuitWorkout.currentExerciseIndex];
            
            document.getElementById('exerciseName').textContent = ex.name;
            document.getElementById('exerciseInstructions').innerHTML = ex.instructions.map(inst => 
                `<li>${inst}</li>`
            ).join('');
            
            const setInfo = document.getElementById('exerciseSetInfo');
            if (setInfo) {
                setInfo.textContent = `Round ${currentCircuitWorkout.currentRound}/${currentCircuitWorkout.rounds} • Ex ${currentCircuitWorkout.currentExerciseIndex + 1}/${currentCircuitWorkout.exercises.length}`;
            }
            
            const repsInfo = document.createElement('div');
            repsInfo.style.cssText = 'text-align: center; font-size: 2em; font-weight: bold; color: #10b981; margin: 20px 0;';
            repsInfo.textContent = `${ex.reps} répétitions`;
            
            const instructionsContainer = document.getElementById('exerciseInstructions').parentElement;
            const existingReps = instructionsContainer.querySelector('.reps-display');
            if (existingReps) existingReps.remove();
            repsInfo.className = 'reps-display';
            instructionsContainer.insertBefore(repsInfo, document.getElementById('exerciseInstructions'));
            
            speak(`${ex.name}. ${ex.reps} répétitions`);
        }

        function nextCircuitExercise() {
            if (!currentCircuitWorkout) return;
            
            currentCircuitWorkout.currentExerciseIndex++;
            
            if (currentCircuitWorkout.currentExerciseIndex >= currentCircuitWorkout.exercises.length) {
                // Round completed
                currentCircuitWorkout.currentExerciseIndex = 0;
                currentCircuitWorkout.currentRound++;
                
                if (currentCircuitWorkout.currentRound > currentCircuitWorkout.rounds) {
                    completeCircuit();
                    return;
                }
                
                showToast(`✅ Round ${currentCircuitWorkout.currentRound - 1} terminé !`, 'success');
                speak(`Repos ${currentCircuitWorkout.restBetweenRounds} secondes`);
                
                isPaused = false;
                timeLeft = currentCircuitWorkout.restBetweenRounds;
                startTimer();
            } else {
                speak('Enchaînez !');
                setTimeout(() => startCircuitExercise(), 1000);
            }
        }

        function completeCircuit() {
            if (!currentCircuitWorkout) return;
            
            showToast(`🎉 Circuit "${currentCircuitWorkout.name}" terminé ! Excellent travail !`, 'success', 5000);
            speak('Circuit terminé ! Bravo !');
            
            const workout = {
                name: currentCircuitWorkout.name,
                type: 'circuit',
                date: new Date().toISOString(),
                duration: currentCircuitWorkout.rounds * currentCircuitWorkout.exercises.length * 60,
                exercises: currentCircuitWorkout.exercises
            };
            saveWorkoutToHistory(workout);
            
            currentCircuitWorkout = null;
            
            setTimeout(() => {
                document.getElementById('exerciseView').classList.add('hidden'); document.body.classList.remove('in-session');
                document.getElementById('workoutSelection').style.display = 'block';
                switchTab('home');
            }, 3000);
        }

