        let amrapTimerInterval = null;

        function startAMRAPTimer() {
            amrapTimerInterval = setInterval(() => {
                if (!isPaused && currentAMRAPWorkout) {
                    currentAMRAPWorkout.timeRemaining--;
                    updateAMRAPDisplay();
                    
                    if (currentAMRAPWorkout.timeRemaining <= 0) {
                        completeAMRAP();
                    }
                }
            }, 1000);
        }

        function updateAMRAPDisplay() {
            const minutes = Math.floor(currentAMRAPWorkout.timeRemaining / 60);
            const seconds = currentAMRAPWorkout.timeRemaining % 60;
            
            const timerDisplay = document.getElementById('timerDisplay');
            if (timerDisplay) {
                timerDisplay.querySelector('.timer').innerHTML = `
                    <div style="font-size: 3em; font-weight: bold; color: #ef4444;">
                        ${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}
                    </div>
                    <div style="margin-top: 10px; color: #ef4444; font-size: 1.2em;">
                        ${currentAMRAPWorkout.roundsCompleted} rounds complétés
                    </div>
                `;
            }
        }

        function startAMRAPExercise() {
            if (!currentAMRAPWorkout) return;
            
            const ex = currentAMRAPWorkout.exercises[currentAMRAPWorkout.currentExerciseIndex];
            
            document.getElementById('exerciseName').textContent = ex.name;
            document.getElementById('exerciseInstructions').innerHTML = ex.instructions.map(inst => 
                `<li>${inst}</li>`
            ).join('');
            
            const setInfo = document.getElementById('exerciseSetInfo');
            if (setInfo) {
                setInfo.textContent = `AMRAP • Ex ${currentAMRAPWorkout.currentExerciseIndex + 1}/${currentAMRAPWorkout.exercises.length}`;
            }
            
            const repsInfo = document.createElement('div');
            repsInfo.style.cssText = 'text-align: center; font-size: 2em; font-weight: bold; color: #ef4444; margin: 20px 0;';
            repsInfo.textContent = `${ex.reps} répétitions`;
            
            const instructionsContainer = document.getElementById('exerciseInstructions').parentElement;
            const existingReps = instructionsContainer.querySelector('.reps-display');
            if (existingReps) existingReps.remove();
            repsInfo.className = 'reps-display';
            instructionsContainer.insertBefore(repsInfo, document.getElementById('exerciseInstructions'));
            
            speak(`${ex.name}`);
            updateAMRAPDisplay();
        }

        function nextAMRAPExercise() {
            if (!currentAMRAPWorkout) return;
            
            currentAMRAPWorkout.currentExerciseIndex++;
            
            if (currentAMRAPWorkout.currentExerciseIndex >= currentAMRAPWorkout.exercises.length) {
                currentAMRAPWorkout.currentExerciseIndex = 0;
                currentAMRAPWorkout.roundsCompleted++;
                showToast(`✅ ${currentAMRAPWorkout.roundsCompleted} rounds complétés !`, 'success', 2000);
            }
            
            setTimeout(() => startAMRAPExercise(), 500);
        }

        function completeAMRAP() {
            if (!currentAMRAPWorkout) return;
            
            clearInterval(amrapTimerInterval);
            
            showToast(`🎉 AMRAP terminé ! ${currentAMRAPWorkout.roundsCompleted} rounds complétés ! 💪`, 'success', 6000);
            speak(`AMRAP terminé ! ${currentAMRAPWorkout.roundsCompleted} rounds`);
            
            const workout = {
                name: currentAMRAPWorkout.name,
                type: 'amrap',
                date: new Date().toISOString(),
                duration: currentAMRAPWorkout.duration,
                rounds: currentAMRAPWorkout.roundsCompleted,
                exercises: currentAMRAPWorkout.exercises
            };
            saveWorkoutToHistory(workout);
            
            currentAMRAPWorkout = null;
            
            setTimeout(() => {
                document.getElementById('exerciseView').classList.add('hidden'); document.body.classList.remove('in-session');
                document.getElementById('workoutSelection').style.display = 'block';
                switchTab('home');
            }, 4000);
        }

