        // Returns {current, total} counting only real exercises (excludes rests & info)
        function getExerciseProgress() {
            if (!currentWorkout) return { current: 0, total: 0 };
            const exercises = currentWorkout.exercises;
            const total = exercises.filter(ex => !ex.isRest && !ex.isInfo).length;
            // Count how many real exercises have been reached up to current index (inclusive)
            let current = 0;
            for (let i = 0; i <= currentExerciseIndex && i < exercises.length; i++) {
                if (!exercises[i].isRest && !exercises[i].isInfo) current++;
            }
            return { current, total };
        }
        
