        // ========== PRO ENHANCEMENT - STRUCTURED WORKOUT GENERATION ==========
        function generateStructuredWorkout(availableExercises, targetCount, profile) {
            // Charger historique performances pour le scoring
            let performanceHistory = {};
            try { performanceHistory = JSON.parse(localStorage.getItem('exercisePerformance') || '{}'); } catch(e) {}

            // Charger exercices récents (3 dernières séances)
            const recentExercises = new Set();
            try {
                getWorkoutHistory().slice(0, 3).forEach(w => {
                    (w.exercises || []).forEach(ex => recentExercises.add(typeof ex === 'string' ? ex : ex.name));
                });
            } catch(e) {}

            // Muscles fatigués
            let fatiguedMuscles = [];
            try {
                const recovery = JSON.parse(localStorage.getItem('muscleRecoveryTracking') || '{}');
                fatiguedMuscles = Object.entries(recovery).filter(([,v]) => v === 'fatigued').map(([k]) => k);
            } catch(e) {}

            // Scorer et trier tous les exercices disponibles
            const scored = availableExercises.map(ex => ({
                ...ex,
                _score: scoreExercise(ex, profile, recentExercises, performanceHistory, fatiguedMuscles)
            })).sort((a, b) => b._score - a._score);

            // Séparer par type (en conservant l'ordre de score)
            const classified = { compound: [], isolation: [], finisher: [] };
            scored.forEach(ex => classified[classifyExercise(ex)].push(ex));

            // Structure selon niveau
            let structure;
            if (profile.level === 'beginner') {
                structure = { compound: Math.round(targetCount * 0.35), isolation: Math.round(targetCount * 0.55), finisher: Math.floor(targetCount * 0.10) };
            } else if (profile.level === 'advanced') {
                structure = { compound: Math.round(targetCount * 0.40), isolation: Math.round(targetCount * 0.35), finisher: Math.floor(targetCount * 0.25) };
            } else {
                structure = { compound: Math.round(targetCount * 0.38), isolation: Math.round(targetCount * 0.42), finisher: Math.floor(targetCount * 0.20) };
            }

            // Garantir que le total ne dépasse pas targetCount
            const structTotal = structure.compound + structure.isolation + structure.finisher;
            if (structTotal > targetCount) {
                const excess = structTotal - targetCount;
                structure.finisher = Math.max(0, structure.finisher - excess);
            }

            const structured = [];
            const used = new Set();

            // Fonction pour piocher les N meilleurs d'une catégorie (avec légère randomisation du top)
            function pickBest(pool, count) {
                const topN = pool.filter(ex => !used.has(ex.name)).slice(0, Math.max(count * 2, 6));
                // Shuffler légèrement le top pour variété sans perdre la pertinence
                for (let i = topN.length - 1; i > 0; i--) {
                    const j = Math.floor(Math.random() * Math.min(i + 1, 3)); // ne shuffler que dans une fenêtre de 3
                    [topN[i], topN[j]] = [topN[j], topN[i]];
                }
                return topN.slice(0, count);
            }

            // Polyarticulaires d'abord (muscles frais)
            pickBest(classified.compound, structure.compound).forEach(ex => {
                structured.push({ ...ex, structureType: 'compound' });
                used.add(ex.name);
            });

            // Isolation (ciblage)
            pickBest(classified.isolation, structure.isolation).forEach(ex => {
                structured.push({ ...ex, structureType: 'isolation' });
                used.add(ex.name);
            });

            // Finishers (burnout)
            pickBest(classified.finisher, structure.finisher).forEach(ex => {
                structured.push({ ...ex, structureType: 'finisher' });
                used.add(ex.name);
            });

            // Compléter si on n'a pas atteint targetCount
            if (structured.length < targetCount) {
                const remaining = scored.filter(ex => !used.has(ex.name)).slice(0, targetCount - structured.length);
                structured.push(...remaining);
            }

            return structured;
        }

        function generateIntelligentWorkout() {
            const profile = getUserProfile();
            const fitnessIndex = getFitnessIndex();
            const equipmentNames = getSelectedEquipmentNames();
            const blacklist = getExerciseBlacklist();

            // ── Muscles : override manuel/plan > réglages > tous ──────────
            const _overrideMuscles = window._overrideSessionMuscles || null;
            if (_overrideMuscles) window._overrideSessionMuscles = null;

            const selectedMuscles = _overrideMuscles || getSelectedMuscleNames();

            // ✅ If no muscles selected, use ALL muscles
            const allMuscles = ['Pectoraux', 'Dos', 'Épaules', 'Biceps', 'Triceps', 'Abdominaux', 'Quadriceps', 'Ischio-jambiers', 'Fessiers', 'Mollets', 'Avant-bras', 'Trapèzes', 'Obliques'];
            let workingMuscles = selectedMuscles.length > 0 ? selectedMuscles : allMuscles;
            
            // ✅ NEW: Get recent exercises to avoid repetition
            const recentHistory = getWorkoutHistory().slice(0, 3); // Last 3 workouts
            const recentExercises = new Set();
            recentHistory.forEach(w => {
                if (w.exercises && Array.isArray(w.exercises)) {
                    w.exercises.forEach(ex => {
                        if (typeof ex === 'string') {
                            recentExercises.add(ex);
                        } else if (ex.name) {
                            recentExercises.add(ex.name);
                        }
                    });
                }
            });
            
            // ✅ NEW: Check muscle recovery before selection
            const recoveryWarnings = getRecoveryWarnings(workingMuscles);
            const fatiguedMuscles = recoveryWarnings
                .filter(w => w.level === 'high')
                .map(w => w.muscle);
            
            // ✅ NEW: Check injured muscles
            const injuredMuscleNames = getInjuredMuscleNames();
            
            // Adjust muscle selection if fatigue or injury detected
            let removedReasons = [];
            
            if (fatiguedMuscles.length > 0) {
                // Filter out highly fatigued muscles
                workingMuscles = workingMuscles.filter(m => !fatiguedMuscles.includes(m));
                removedReasons.push(`Fatigués : ${fatiguedMuscles.join(', ')}`);
            }
            
            if (injuredMuscleNames.length > 0) {
                // Filter out injured muscles
                workingMuscles = workingMuscles.filter(m => !injuredMuscleNames.includes(m));
                removedReasons.push(`🤕 Blessés : ${injuredMuscleNames.join(', ')}`);
            }
            
            // If all muscles fatigued or injured, suggest recovery workout
            if (workingMuscles.length === 0) {
                showToast('⚠️ Tous vos muscles sont fatigués ou blessés. Séance de récupération recommandée.', 'warning', 4000);
                return generateRecoveryWorkout();
            }
            
            if (removedReasons.length > 0) {
                showToast(`💡 Muscles évités : ${removedReasons.join(' • ')}`, 'info', 3500);
            }
            
            // Show which muscles are being used
            if (selectedMuscles.length > 0) {
                showToast(`🎯 Muscles ciblés : ${workingMuscles.join(', ')}`, 'info', 3000);
            }
            
            // Calculate intensity adjustment
            let intensity = 1.0;
            if (fitnessIndex <= 3) intensity = 0.6;
            else if (fitnessIndex <= 5) intensity = 0.8;
            else if (fitnessIndex >= 8) intensity = 1.2;
            
            // ✅ DEBUG: Log equipment selection
            
            // Normaliser les noms d'équipements (DB a des noms FR et EN mélangés)
            const EQ_NORM = {
                'barbell':'Barre','barre':'Barre',
                'dumbbells':'Haltères','haltères':'Haltères',
                'bodyweight':'Poids du corps','poids du corps':'Poids du corps',
                'machine':'Machine',
                'bench':'Banc','banc':'Banc',
                'kettlebell':'Kettlebell',
                'resistance':'Élastique','élastique':'Élastique',
                'parallelbars':'Barres parallèles','barres parallèles':'Barres parallèles',
                'jumprope':'Corde à sauter','corde à sauter':'Corde à sauter',
                'trx':'TRX',
            };
            const normalizeEq = eq => EQ_NORM[eq.toLowerCase()] || eq;

            // Noms équipements sélectionnés normalisés
            const normEquipNames = equipmentNames.map(normalizeEq);

            // Mode gym machines seulement ? (gymBodyweightMode = false)
            const machinesOnly = (sessionMode === 'gym' && !gymBodyweightMode);

            // Filter exercises ET blacklist
            const availableExercises = exerciseDatabase.filter(ex => {
                // Skip non-exercises
                if (ex.type !== 'exercise') return false;

                // Check muscle match
                if (!workingMuscles.includes(ex.muscle)) return false;

                // Check blacklist
                if (blacklist.includes(ex.name)) return false;

                // Normaliser l'équipement de l'exercice
                const exEq = (ex.equipment || []).map(normalizeEq);

                // Mode machines seulement → exclure les exercices poids du corps
                if (machinesOnly) {
                    const isBodyweight = exEq.every(e => e === 'Poids du corps' || e === 'Aucun');
                    if (isBodyweight) return false;
                }

                // Equipment filter logic
                if (normEquipNames.length === 0) {
                    // Aucun équipement sélectionné → poids du corps seulement
                    return exEq.some(e => e === 'Poids du corps' || e === 'Aucun');
                } else {
                    // Équipements sélectionnés → l'exercice doit utiliser UNIQUEMENT ces équipements
                    return exEq.every(e => normEquipNames.includes(e) || e === 'Poids du corps' || e === 'Aucun');
                }
            });

            // ✅ DEBUG: Log filtered exercises
            if (availableExercises.length > 0) {
            }
            
            // ✅ NEW: Separate fresh vs recent exercises
            const freshExercises = availableExercises.filter(ex => !recentExercises.has(ex.name));
            const exercisePool = freshExercises.length >= 5 ? freshExercises : availableExercises;
            
            // Calculate number of exercises based on duration and intensity
            let targetExerciseCount;
            if (selectedDuration <= 15) targetExerciseCount = Math.floor(4 * intensity);
            else if (selectedDuration <= 30) targetExerciseCount = Math.floor(8 * intensity);
            else if (selectedDuration <= 45) targetExerciseCount = Math.floor(12 * intensity);
            else targetExerciseCount = Math.floor(15 * intensity);
            
            // PRO ENHANCEMENT: Use structured workout generation instead of random
            const targetCount = Math.min(targetExerciseCount, exercisePool.length);
            let selectedExercises = generateStructuredWorkout(exercisePool, targetCount, profile);
            
            // ✅ NEW: Ensure muscle balance (no muscle >40%)
            selectedExercises = ensureMuscleBalance(selectedExercises);
            
            // ✅ EXPERT SYSTEM : Prévenir sur-sollicitation
            selectedExercises = preventOverload(selectedExercises, 3);
            
            // ✅ EXPERT SYSTEM : Équilibrer agoniste/antagoniste
            selectedExercises = balanceAgonistAntagonist(selectedExercises, availableExercises);
            
            // Apply progression levels and stored progressions
            selectedExercises.forEach((ex, index) => {
                const performance = getExercisePerformance(ex.name);
                
                // ✅ ENHANCED: Apply stored progressions first
                let adjustedExercise = applyStoredProgressions(ex);
                
                // ✅ ENHANCED: Auto-adjust difficulty based on performance
                // If consistently easy (3+ times), increase difficulty
                if (performance.level === 'easy' && performance.history && 
                    performance.history.slice(-3).every(h => h.difficulty <= 2)) {
                    
                    // Check if there's a harder variant available
                    const variant = findExerciseVariant(ex.name, 'harder');
                    if (variant && !adjustedExercise.progressionApplied) {
                        // Suggest variant during workout
                        adjustedExercise.suggestedVariant = variant;
                        adjustedExercise.progressionNote = `💡 Variante ${variant.difficulty} disponible`;
                    } else if (!adjustedExercise.progressionApplied) {
                        adjustedExercise.duration = Math.round(adjustedExercise.duration * 1.15); // +15%
                        adjustedExercise.progressionNote = '📈 +15% (progression auto)';
                    }
                }
                
                // If consistently hard (3+ times), decrease difficulty
                else if (performance.level === 'hard' && performance.history && 
                         performance.history.slice(-3).every(h => h.difficulty >= 4)) {
                    
                    // Check if there's an easier variant available
                    const variant = findExerciseVariant(ex.name, 'easier');
                    if (variant && !adjustedExercise.progressionApplied) {
                        // Suggest variant during workout
                        adjustedExercise.suggestedVariant = variant;
                        adjustedExercise.progressionNote = `💡 Variante ${variant.difficulty} disponible`;
                    } else if (!adjustedExercise.progressionApplied) {
                        adjustedExercise.duration = Math.round(adjustedExercise.duration * 0.85); // -15%
                        adjustedExercise.progressionNote = '💡 -15% (adaptation auto)';
                    }
                }
                
                adjustedExercise.progressionLevel = performance.level;
                selectedExercises[index] = adjustedExercise;
            });
            
            // ✅ EXPERT SYSTEM : Ordre optimal (gros → petits)
            selectedExercises = sortExercisesOptimally(selectedExercises);
            
            // Build workout structure
            const workout = {
                name: `Séance intelligente ${userGoals[profile.goal].icon}`,
                mode: selectedWorkoutMode, // 'timer', 'reps', 'hybrid'
                exercises: []
            };
            
            // ✅ EXPERT SYSTEM : Échauffement progressif 3 phases
            if (includeWarmup) {
                const expertWarmup = generateProgressiveWarmup(workingMuscles, intensity);
                workout.exercises.push(...expertWarmup);
            }
            
            // Add main exercises with adaptive rest
            selectedExercises.forEach(ex => {
                // Determine mode for this exercise
                const exerciseMode = determineExerciseMode(ex.name, selectedWorkoutMode);
                const lastPerf = getLastPerformance(ex.name);
                
                const exerciseObj = {
                    ...ex,
                    duration: 60,
                    mode: exerciseMode, // 'timer' or 'reps'
                    exerciseType: getExerciseType(ex.name) // 'force', 'cardio', 'hybrid'
                };
                
                // Add last performance data if in reps mode
                if (exerciseMode === 'reps' && lastPerf) {
                    exerciseObj.lastPerformance = lastPerf;
                }
                
                workout.exercises.push(exerciseObj);
                
                // Repos adaptatif selon intensité
                const levelData = userLevels[profile.level] || userLevels['intermediate'];
                let restDuration = levelData.rest;
                if (intensity >= 1.1) restDuration += 30;
                workout.exercises.push({ name: "Repos", duration: restDuration, isRest: true, mode: 'timer' });
            });
            
            // ✅ EXPERT SYSTEM : Étirements intelligents ciblés
            if (includeStretch) {
                const expertStretches = generateIntelligentStretches(selectedExercises, intensity);
                workout.exercises.push(...expertStretches);
            }
            
            return workout;
        }

        // ========== SMART RECOMMENDATIONS SYSTEM ==========
        
        function ensureMuscleBalance(selectedExercises) {
            if (selectedExercises.length < 4) return selectedExercises;
            
            // Count exercises per muscle
            const muscleCount = {};
            selectedExercises.forEach(ex => {
                muscleCount[ex.muscle] = (muscleCount[ex.muscle] || 0) + 1;
            });
            
            const total = selectedExercises.length;
            const balanced = [];
            const used = new Set();
            
            // Check for over-representation (>40% of total)
            selectedExercises.forEach(ex => {
                const count = muscleCount[ex.muscle];
                const percentage = count / total;
                
                // If muscle is over-represented and not yet added
                if (percentage > 0.4 && !used.has(ex.name)) {
                    // Find under-represented muscle
                    const underrepresented = Object.entries(muscleCount)
                        .sort((a, b) => a[1] - b[1])
                        .filter(([muscle]) => muscle !== ex.muscle)[0];
                    
                    if (underrepresented && muscleCount[ex.muscle] > 1) {
                        // Try to replace with alternative
                        const _equipNames = getEquipmentNames ? getEquipmentNames() : [];
                        const alternatives = exerciseDatabase.filter(e => 
                            e.muscle === underrepresented[0] &&
                            e.type === 'exercise' &&
                            !balanced.find(b => b.name === e.name) &&
                            (_equipNames.length === 0 || e.equipment.every(eq => _equipNames.includes(eq)))
                        );
                        
                        if (alternatives.length > 0 && balanced.length < total) {
                            const alt = alternatives[Math.floor(Math.random() * alternatives.length)];
                            balanced.push(alt);
                            used.add(alt.name);
                            muscleCount[ex.muscle]--;
                            muscleCount[underrepresented[0]]++;
                            return;
                        }
                    }
                }
                
                // Add exercise normally
                if (!used.has(ex.name) && balanced.length < total) {
                    balanced.push(ex);
                    used.add(ex.name);
                }
            });
            
            return balanced.length > 0 ? balanced : selectedExercises;
        }
        
        function getSmartRecommendations() {
            const profile = getUserProfile();
            const history = getWorkoutHistory();
            const selectedMuscles = getSelectedMuscleNames();
            const recovery = getRecoveryWarnings(selectedMuscles);
            const time = new Date().getHours();
            const day = new Date().getDay(); // 0 = Sunday, 6 = Saturday
            
            const recommendations = [];
            
            // Time-based recommendation
            if (time >= 6 && time < 12) {
                recommendations.push({
                    type: 'time',
                    icon: '🌅',
                    title: 'Morning Boost',
                    message: 'Parfait pour une séance énergisante !',
                    suggestion: 'HIIT ou Full Body',
                    action: 'start_hiit',
                    priority: 'high'
                });
            } else if (time >= 12 && time < 18) {
                recommendations.push({
                    type: 'time',
                    icon: '☀️',
                    title: 'Après-midi',
                    message: 'Idéal pour une séance de force',
                    suggestion: 'Force ou Musculation',
                    action: 'start_strength',
                    priority: 'medium'
                });
            } else if (time >= 18 && time < 22) {
                recommendations.push({
                    type: 'time',
                    icon: '🌆',
                    title: 'After Work',
                    message: 'Parfait pour évacuer le stress',
                    suggestion: 'Cardio ou Endurance',
                    action: 'start_cardio',
                    priority: 'medium'
                });
            } else {
                recommendations.push({
                    type: 'time',
                    icon: '🌙',
                    title: 'Soirée tardive',
                    message: 'Séance légère ou stretching conseillé',
                    suggestion: 'Yoga ou Stretching',
                    action: 'start_stretch',
                    priority: 'low'
                });
            }
            
            // Frequency-based recommendation
            if (history.length > 0) {
                const lastWorkout = history[0];
                const daysSince = (Date.now() - new Date(lastWorkout.date)) / (1000 * 60 * 60 * 24);
                
                if (daysSince > 3) {
                    recommendations.push({
                        type: 'frequency',
                        icon: '⚠️',
                        title: 'Reprise suggérée',
                        message: `${Math.floor(daysSince)} jours depuis dernière séance`,
                        suggestion: 'Séance légère de reprise',
                        action: 'start_light',
                        priority: 'high'
                    });
                } else if (daysSince < 1 && history.length > 1) {
                    const beforeLast = history[1];
                    const daysBetween = (new Date(lastWorkout.date) - new Date(beforeLast.date)) / (1000 * 60 * 60 * 24);
                    if (daysBetween < 1) {
                        recommendations.push({
                            type: 'frequency',
                            icon: '⚡',
                            title: 'Rythme intense !',
                            message: 'Attention à la récupération',
                            suggestion: 'Repos ou séance légère',
                            action: 'start_recovery',
                            priority: 'medium'
                        });
                    }
                }
            } else {
                recommendations.push({
                    type: 'frequency',
                    icon: '🎯',
                    title: 'Première séance',
                    message: 'Commencez en douceur',
                    suggestion: 'Programme débutant',
                    action: 'start_beginner',
                    priority: 'high'
                });
            }
            
            // Recovery-based recommendation
            const highFatigue = recovery.filter(r => r.level === 'high');
            if (highFatigue.length > 0) {
                recommendations.push({
                    type: 'recovery',
                    icon: '😴',
                    title: 'Récupération nécessaire',
                    message: `Muscles fatigués : ${highFatigue.map(r => r.muscle).join(', ')}`,
                    suggestion: 'Stretching ou repos actif',
                    action: 'start_recovery',
                    priority: 'high'
                });
            } else if (recovery.length === 0) {
                recommendations.push({
                    type: 'recovery',
                    icon: '💪',
                    title: 'Prêt pour l\'action !',
                    message: 'Tous vos muscles sont récupérés',
                    suggestion: 'Séance intensive possible',
                    action: 'start_intense',
                    priority: 'medium'
                });
            }
            
            // Goal-based recommendation
            if (profile.goal === 'weight_loss') {
                recommendations.push({
                    type: 'goal',
                    icon: '🔥',
                    title: 'Perte de poids',
                    message: 'Circuit HIIT recommandé',
                    suggestion: 'HIIT 30 min',
                    action: 'start_hiit',
                    priority: 'medium'
                });
            } else if (profile.goal === 'strength') {
                recommendations.push({
                    type: 'goal',
                    icon: '🏋️',
                    title: 'Force maximale',
                    message: 'Exercices composés recommandés',
                    suggestion: 'Programme Force',
                    action: 'start_strength',
                    priority: 'medium'
                });
            } else if (profile.goal === 'muscle_gain' || profile.goal === 'muscle') {
                recommendations.push({
                    type: 'goal',
                    icon: '💪',
                    title: 'Prise de masse',
                    message: 'Volume et hypertrophie',
                    suggestion: 'Séance hypertrophie',
                    action: 'start_hypertrophy',
                    priority: 'medium'
                });
            }
            
            // Weekend recommendation
            if (day === 0 || day === 6) {
                recommendations.push({
                    type: 'schedule',
                    icon: '🎊',
                    title: 'Weekend',
                    message: 'Temps pour une séance complète',
                    suggestion: 'Séance longue 60 min',
                    action: 'start_long',
                    priority: 'medium'
                });
            }
            
            // Sort by priority
            const priorityOrder = { high: 3, medium: 2, low: 1 };
            return recommendations.sort((a, b) => 
                priorityOrder[b.priority] - priorityOrder[a.priority]
            );
        }
        
