        // ========== DATA MANAGEMENT SYSTEM ==========
        
        function exportAllData() {
            try {
                const allData = {};
                let totalBytes = 0;
                for (let i = 0; i < localStorage.length; i++) {
                    const key = localStorage.key(i);
                    const val = localStorage.getItem(key);
                    allData[key] = val;
                    totalBytes += (key.length + val.length) * 2;
                }

                // Métadonnées de backup
                allData['_backupMeta'] = JSON.stringify({
                    version: '2.0',
                    date: new Date().toISOString(),
                    appName: 'FitPro Elite',
                    keys: Object.keys(allData).length,
                    sizeMB: (totalBytes / 1024 / 1024).toFixed(2)
                });

                const dataStr  = JSON.stringify(allData, null, 2);
                const dataBlob = new Blob([dataStr], { type: 'application/json' });
                const url      = URL.createObjectURL(dataBlob);
                const link     = document.createElement('a');
                link.href      = url;
                link.download  = `FitProElite-Backup-${new Date().toISOString().split('T')[0]}.json`;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                URL.revokeObjectURL(url);

                const sizeMB = (totalBytes / 1024 / 1024).toFixed(2);
                showToast(`💾 Export réussi — ${Object.keys(allData).length} clés, ${sizeMB} MB`, 'success', 4000);
            } catch (error) {
                showToast('❌ Erreur lors de l\'export', 'error', 3000);
            }
        }
        
        function importAllData(event) {
            const file = event.target.files[0];
            if (!file) return;

            showConfirm('Importer des données remplacera TOUTES vos données actuelles. Cette action est irréversible.', function() {
                event.target.value = ''; // Reset file input
                const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    
                    // Clear current localStorage
                    localStorage.clear();
                    
                    // Import all data
                    Object.keys(importedData).forEach(key => {
                        localStorage.setItem(key, importedData[key]);
                    });
                    
                    showToast('📥 Données importées avec succès ! Rechargement...', 'success', 2000);
                    speak('Données importées');
                    
                    // Reload page to apply changes
                    setTimeout(() => {
                        location.reload();
                    }, 2000);
                } catch (error) {
                    showToast('❌ Erreur : fichier invalide', 'error', 3000);
                }
            };
            reader.readAsText(file);
            }, null, { title: 'Importer des données ?', icon: '⚠️', confirmLabel: 'Importer', danger: true });
        }
        
        function deleteCurrentProfile() {
            const currentProfileId = getCurrentProfileId();
            const allProfiles = getAllProfiles();

            if (allProfiles.length === 1) {
                showAlert('Veuillez créer un nouveau profil avant de supprimer celui-ci.', 'error', 'Impossible de supprimer');
                return;
            }

            const profile = allProfiles.find(p => p.id === currentProfileId);
            const profileName = profile ? profile.name : 'ce profil';

            showConfirm(`Supprimer définitivement le profil "${profileName}" ? Toutes les données seront perdues.`, function() {
                try {
                // Remove profile from profiles list
                const updatedProfiles = allProfiles.filter(p => p.id !== currentProfileId);
                localStorage.setItem('allProfiles', JSON.stringify(updatedProfiles));
                
                // Delete all profile-specific data
                const profileKeys = [
                    `profile_${currentProfileId}_userProfile`,
                    `profile_${currentProfileId}_workoutHistory`,
                    `profile_${currentProfileId}_workoutStats`,
                    `profile_${currentProfileId}_unlockedBadges`,
                    `profile_${currentProfileId}_favoriteWorkouts`,
                    `profile_${currentProfileId}_weeklyPlan`,
                    `profile_${currentProfileId}_muscleRecoveryTracking`,
                    `profile_${currentProfileId}_activePlan`,
                    `profile_${currentProfileId}_fitnessIndex`,
                    `profile_${currentProfileId}_exercisePerformance`
                ];
                
                profileKeys.forEach(key => localStorage.removeItem(key));
                
                // Switch to first remaining profile
                const firstProfile = updatedProfiles[0];
                localStorage.setItem('currentProfileId', firstProfile.id);
                
                showToast(`🗑️ Profil "${profileName}" supprimé. Rechargement...`, 'success', 2000);
                speak('Profil supprimé');
                
                // Reload page
                setTimeout(() => {
                    location.reload();
                }, 2000);
                } catch (error) {
                    showToast('❌ Erreur lors de la suppression', 'error', 3000);
                }
            }, null, { title: 'Supprimer le profil ?', icon: '🗑️', confirmLabel: 'Supprimer', danger: true });
        }
        
