        function getWeeklyPlanToday() {
            // Utilise getTodayPlanMuscles qui a la bonne structure
            try {
                const plan = getTodayPlanMuscles();
                if (!plan) return null;
                if (plan.focus) return plan.focus;
                if (plan.muscles && plan.muscles.length > 0) return plan.muscles.join(' · ');
                return null;
            } catch(e) { return null; }
        }

        function onMuscleChoiceAI() {
            const overlay = document.getElementById('muscleChoiceOverlay');
            if (overlay) overlay.remove();

            // Récupérer les muscles du plan du jour
            const todayPlan = getTodayPlanMuscles();
            if (todayPlan && todayPlan.muscles && todayPlan.muscles.length > 0) {
                // Filtrer les muscles fatigués ou blessés
                const fatigued = JSON.parse(localStorage.getItem('muscleRecoveryTracking') || '{}');
                const injured  = JSON.parse(localStorage.getItem('injuredMuscles') || '[]');
                const available = todayPlan.muscles.filter(m =>
                    !injured.includes(m) && (fatigued[m] === undefined || fatigued[m] !== 'fatigued')
                );
                if (available.length > 0) {
                    window._overrideSessionMuscles = available;
                    showToast(`📅 Plan du jour : ${todayPlan.focus || available.join(', ')}`, 'info', 2500);
                } else {
                    // Tous fatigués/blessés → laisser l'IA décider librement
                    window._overrideSessionMuscles = null;
                    showToast('⚠️ Muscles du plan fatigués — l\'IA adapte la séance', 'info', 2500);
                }
            } else {
                // Pas de plan → l'IA utilise les muscles des réglages + historique
                window._overrideSessionMuscles = null;
            }

            openWorkoutModeModal();
        }

        function onMuscleChoiceManual() {
            const overlay = document.getElementById('muscleChoiceOverlay');
            if (overlay) overlay.remove();
            // Afficher le sélecteur de muscles
            showManualMusclePickerModal();
        }

