        function saveNewRoutine() {
            const nameInput = document.getElementById('newRoutineName');
            const descInput = document.getElementById('newRoutineDescription');
            const dayInput = document.getElementById('newRoutineDay');
            
            const name = nameInput ? nameInput.value.trim() : '';
            const description = descInput ? descInput.value.trim() : '';
            const day = dayInput ? dayInput.value : '';
            
            if (!name) {
                showAlert('Veuillez entrer un nom pour cette routine.', 'warning', 'Nom requis');
                if (nameInput) nameInput.focus();
                return;
            }
            
            // Create new routine
            const newRoutine = {
                name: name,
                description: description,
                day: day,
                exercises: [], // Empty for now - will add later
                createdAt: new Date().toISOString()
            };
            
            // Save to routines
            const routines = getRoutines();
            routines.push(newRoutine);
            saveRoutines(routines);
            
            // Close modal
            closeCreateRoutineModal();
            
            // Refresh list
            renderRoutinesList();
            
            // Show success
            showToast(`✅ Routine "${name}" créée ! Vous pouvez maintenant y ajouter des exercices.`);
        }
        
        function startRoutine(index) {
            
            const routines = getRoutines();
            
            const routine = routines[index];
            
            if (!routine) {
                showAlert('Routine introuvable.', 'error', 'Erreur');
                return;
            }
            
            
            // Switch to workouts tab FIRST
            switchTab('workouts');
            
            // Create workout from routine
            const workout = {
                name: routine.name,
                description: routine.description || `Routine personnalisée`,
                exercises: routine.exercises.map((ex, i) => {
                    
                    // Find full exercise data from database
                    const fullEx = exerciseDatabase.find(e => e.name === ex.name);
                    
                    if (fullEx) {
                        // Clone exercise and add routine-specific data
                        // IMPORTANT: le mode sauvegardé dans la routine prime sur le mode de la DB
                        const result = {
                            ...fullEx,
                            sets: ex.sets || fullEx.sets || 3,
                            reps: ex.reps || fullEx.reps || 10,
                            duration: ex.duration || fullEx.duration || 45,
                            mode: ex.mode || 'reps'  // respecter le mode choisi à la création
                        };
                        return result;
                    }
                    // If not found, create minimal exercise object with defaults
                    return {
                        ...ex,
                        type: 'exercise',
                        muscle: 'Autre',
                        difficulty: 'Intermédiaire',
                        equipment: ['Matériel divers'],
                        description: ex.name,
                        instructions: ['Exercice personnalisé'],
                        duration: ex.duration || 60,
                        sets: ex.sets || 3,
                        reps: ex.reps || 10,
                        mode: ex.mode || 'reps'
                    };
                }),
                type: 'routine',
                fromRoutine: true,
                routineName: routine.name,
                mode: 'mixed'  // exercices peuvent avoir des modes différents
            };
            
            
            
            // Check if function exists
            if (typeof showWorkoutPreparation === 'function') {
                try {
                    showWorkoutPreparation(workout);
                    showToast(`🔄 Routine "${routine.name}" démarrée !`);
                } catch (error) {
                    showAlert('Erreur lors du démarrage : ' + error.message, 'error', 'Erreur');
                }
            } else {
                showAlert('Erreur interne. Rechargez la page.', 'error', 'Erreur');
            }
        }
        
        function showRoutineOptions(index) {
            const routines = getRoutines();
            const routine = routines[index];
            
            if (!routine) return;
            
            // Create options modal
            const overlay = document.createElement('div');
            overlay.id = 'routineOptionsOverlay';
            overlay.style.cssText = `
                position: fixed;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                background: rgba(0,0,0,0.7);
                z-index: 10000;
                display: flex;
                align-items: center;
                justify-content: center;
                padding: 20px;
                animation: fadeIn 0.2s;
            `;
            
            const modal = document.createElement('div');
            modal.style.cssText = `
                background: white;
                border-radius: 20px;
                max-width: 400px;
                width: 100%;
                box-shadow: 0 20px 60px rgba(0,0,0,0.3);
                animation: slideUp 0.2s;
            `;
            
            modal.innerHTML = `
                <div style="padding: 25px;">
                    <h3 style="color: #16a34a; margin: 0 0 20px 0;">${routine.name}</h3>
                    
                    <button onclick="editRoutine(${index}); document.getElementById('routineOptionsOverlay').remove();" 
                            class="btn" 
                            style="width: 100%; background: linear-gradient(135deg, #16a34a 0%, #15803d 100%); margin-bottom: 10px; padding: 15px; font-size: 1em;">
                        ✏️ Éditer la routine
                    </button>
                    
                    <button onclick="duplicateRoutine(${index}); document.getElementById('routineOptionsOverlay').remove();" 
                            class="btn btn-secondary" 
                            style="width: 100%; margin-bottom: 10px; padding: 15px; font-size: 1em;">
                        📋 Dupliquer
                    </button>
                    
                    <button onclick="deleteRoutine(${index}); document.getElementById('routineOptionsOverlay').remove();" 
                            class="btn" 
                            style="width: 100%; background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%); margin-bottom: 15px; padding: 15px; font-size: 1em;">
                        🗑️ Supprimer
                    </button>
                    
                    <button onclick="document.getElementById('routineOptionsOverlay').remove();" 
                            class="btn btn-secondary" 
                            style="width: 100%; padding: 12px;">
                        Annuler
                    </button>
                </div>
            `;
            
            overlay.appendChild(modal);
            document.body.appendChild(overlay);
        }
        
        function deleteRoutine(index) {
            const routines = getRoutines();
            const routine = routines[index];
            
            if (!routine) return;
            
            showConfirm(`Supprimer la routine "${routine.name}" ? Cette action est irréversible.`, function() {
                routines.splice(index, 1);
                saveRoutines(routines);
                renderRoutinesList();
                showToast(`🗑️ Routine "${routine.name}" supprimée !`);
            }, null, { title: 'Supprimer la routine ?', icon: '🗑️', confirmLabel: 'Supprimer', danger: true });
        }
        
        function duplicateRoutine(index) {
            const routines = getRoutines();
            const routine = routines[index];
            
            if (!routine) return;
            
            // Create copy
            const copy = {
                ...routine,
                name: routine.name + ' (Copie)',
                createdAt: new Date().toISOString()
            };
            
            routines.push(copy);
            saveRoutines(routines);
            renderRoutinesList();
            showToast(`📋 Routine dupliquée : "${copy.name}"`);
        }
        
        function editRoutine(index) {
            const routines = getRoutines();
            const routine = routines[index];
            
            if (!routine) return;
            
            // Store current editing routine
            window.currentEditingRoutineIndex = index;
            
            // Create edit modal
            const overlay = document.createElement('div');
            overlay.id = 'editRoutineOverlay';
            overlay.style.cssText = `
                position: fixed;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                background: rgba(0,0,0,0.85);
                z-index: 10001;
                display: flex;
                align-items: center;
                justify-content: center;
                padding: 20px;
                animation: fadeIn 0.3s;
                overflow-y: auto;
            `;
            
            const modal = document.createElement('div');
            modal.style.cssText = `
                background: white;
                border-radius: 20px;
                max-width: 700px;
                width: 100%;
                max-height: 90vh;
                overflow-y: auto;
                box-shadow: 0 20px 60px rgba(0,0,0,0.3);
                animation: slideUp 0.3s;
                margin: 20px 0;
            `;
            
            modal.innerHTML = `
                <div style="padding: 30px;">
                    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 25px;">
                        <h2 style="color: #16a34a; margin: 0;">✏️ Éditer ${routine.name}</h2>
                        <button onclick="closeEditRoutine()" style="background: none; border: none; font-size: 1.5em; cursor: pointer; color: #999;">✕</button>
                    </div>
                    
                    <!-- Routine Info -->
                    <div style="margin-bottom: 25px;">
                        <label style="display: block; font-weight: 600; margin-bottom: 8px; color: #333;">Nom de la routine</label>
                        <input type="text" id="editRoutineName" value="${routine.name}" 
                               style="width: 100%; padding: 12px; border-radius: 8px; border: 2px solid #e5e7eb; font-size: 1em;">
                    </div>
                    
                    <div style="margin-bottom: 25px;">
                        <label style="display: block; font-weight: 600; margin-bottom: 8px; color: #333;">Description</label>
                        <textarea id="editRoutineDescription" 
                                  style="width: 100%; padding: 12px; border-radius: 8px; border: 2px solid #e5e7eb; font-size: 1em; min-height: 60px; resize: vertical;">${routine.description || ''}</textarea>
                    </div>
                    
                    <!-- Exercises List -->
                    <div style="margin-bottom: 25px;">
                        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
                            <h3 style="color: #16a34a; margin: 0;">Exercices (${routine.exercises.length})</h3>
                            <button onclick="addExerciseToRoutine()" class="btn" 
                                    style="background: linear-gradient(135deg, #10b981 0%, #059669 100%); padding: 10px 20px; font-size: 0.9em;">
                                ➕ Ajouter
                            </button>
                        </div>
                        
                        <div id="editRoutineExercisesList" style="display: flex; flex-direction: column; gap: 10px;">
                            <!-- Exercises will be rendered here -->
                        </div>
                        
                        <div id="noExercisesInRoutine" style="display: none; text-align: center; padding: 40px; color: #999;">
                            <div style="font-size: 3em; margin-bottom: 10px;">📋</div>
                            <div style="font-size: 1em;">Aucun exercice dans cette routine</div>
                            <div style="font-size: 0.9em; margin-top: 5px;">Cliquez sur "➕ Ajouter" pour commencer</div>
                        </div>
                    </div>
                    
                    <!-- Save/Cancel -->
                    <div style="display: flex; gap: 10px; margin-top: 25px;">
                        <button onclick="closeEditRoutine()" class="btn btn-secondary" style="flex: 1; padding: 15px;">
                            Annuler
                        </button>
                        <button onclick="saveEditedRoutine()" class="btn" 
                                style="background: linear-gradient(135deg, #16a34a 0%, #15803d 100%); flex: 1; padding: 15px;">
                            ✅ Enregistrer
                        </button>
                    </div>
                </div>
            `;
            
            overlay.appendChild(modal);
            document.body.appendChild(overlay);
            
            // Render exercises
            renderEditRoutineExercises();
        }
        
        function renderEditRoutineExercises() {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            
            if (!routine) return;
            
            const container = document.getElementById('editRoutineExercisesList');
            const noExercisesMsg = document.getElementById('noExercisesInRoutine');
            
            if (!container) return;
            
            if (routine.exercises.length === 0) {
                container.style.display = 'none';
                if (noExercisesMsg) noExercisesMsg.style.display = 'block';
                return;
            }
            
            container.style.display = 'flex';
            if (noExercisesMsg) noExercisesMsg.style.display = 'none';
            
            container.innerHTML = routine.exercises.map((ex, exIndex) => {
                const isTimer = (ex.mode === 'timer');
                const modeColor = isTimer ? '#0ea5e9' : '#16a34a';
                const modeLabel = isTimer ? '⏱️ Timer' : '💪 Reps';
                return `
                <div style="background: #f9fafb; padding: 15px; border-radius: 12px; border-left: 4px solid ${modeColor};">
                    <div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 10px;">
                        <div style="flex: 1;">
                            <div style="font-weight: 600; color: #333; margin-bottom: 5px;">${ex.name}</div>
                            <div style="margin-bottom:8px;">
                                <button onclick="toggleRoutineExMode(${exIndex})"
                                    style="background:${isTimer?'#0ea5e920':'#16a34a20'};color:${modeColor};border:1.5px solid ${modeColor};border-radius:99px;padding:3px 12px;font-size:0.78em;font-weight:700;cursor:pointer;">
                                    ${modeLabel}
                                </button>
                            </div>
                            <div style="display: flex; gap: 15px; font-size: 0.9em; color: #666;">
                                <div>
                                    <label style="font-size: 0.8em; color: #999; display: block; margin-bottom: 3px;">Séries</label>
                                    <input type="number" value="${ex.sets || 3}" min="1" max="10" 
                                           onchange="updateExerciseConfig(${exIndex}, 'sets', this.value)"
                                           style="width: 60px; padding: 5px; border-radius: 6px; border: 1px solid #e5e7eb; text-align: center;">
                                </div>
                                ${isTimer ? `
                                <div>
                                    <label style="font-size: 0.8em; color: #999; display: block; margin-bottom: 3px;">Durée (sec)</label>
                                    <input type="number" value="${ex.duration || 45}" min="5" max="300" 
                                           onchange="updateExerciseConfig(${exIndex}, 'duration', this.value)"
                                           style="width: 70px; padding: 5px; border-radius: 6px; border: 1px solid #e5e7eb; text-align: center;">
                                </div>` : `
                                <div>
                                    <label style="font-size: 0.8em; color: #999; display: block; margin-bottom: 3px;">Reps</label>
                                    <input type="number" value="${ex.reps || 10}" min="1" max="50" 
                                           onchange="updateExerciseConfig(${exIndex}, 'reps', this.value)"
                                           style="width: 60px; padding: 5px; border-radius: 6px; border: 1px solid #e5e7eb; text-align: center;">
                                </div>`}
                            </div>
                        </div>
                        <div style="display: flex; flex-direction: column; gap: 5px;">
                            ${exIndex > 0 ? `<button onclick="moveExerciseUp(${exIndex})" class="btn btn-secondary" style="padding: 5px 10px; font-size: 0.9em;">⬆️</button>` : ''}
                            ${exIndex < routine.exercises.length - 1 ? `<button onclick="moveExerciseDown(${exIndex})" class="btn btn-secondary" style="padding: 5px 10px; font-size: 0.9em;">⬇️</button>` : ''}
                            <button onclick="removeExerciseFromRoutine(${exIndex})" class="btn" style="background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%); padding: 5px 10px; font-size: 0.9em;">❌</button>
                        </div>
                    </div>
                </div>`;
            }).join('');
        }
        

        function toggleRoutineExMode(exIndex) {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            if (!routine || !routine.exercises[exIndex]) return;
            const ex = routine.exercises[exIndex];
            ex.mode = (ex.mode === 'timer') ? 'reps' : 'timer';
            if (ex.mode === 'timer' && !ex.duration) ex.duration = 45;
            if (ex.mode === 'reps'  && !ex.reps)     ex.reps = 10;
            saveRoutines(routines);
            renderEditRoutineExercises();
        }

        function updateExerciseConfig(exIndex, field, value) {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            
            if (!routine || !routine.exercises[exIndex]) return;
            
            routine.exercises[exIndex][field] = parseInt(value);
            saveRoutines(routines);
        }
        
        function moveExerciseUp(exIndex) {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            
            if (!routine || exIndex === 0) return;
            
            // Swap with previous
            [routine.exercises[exIndex - 1], routine.exercises[exIndex]] = 
            [routine.exercises[exIndex], routine.exercises[exIndex - 1]];
            
            saveRoutines(routines);
            renderEditRoutineExercises();
        }
        
        function moveExerciseDown(exIndex) {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            
            if (!routine || exIndex === routine.exercises.length - 1) return;
            
            // Swap with next
            [routine.exercises[exIndex], routine.exercises[exIndex + 1]] = 
            [routine.exercises[exIndex + 1], routine.exercises[exIndex]];
            
            saveRoutines(routines);
            renderEditRoutineExercises();
        }
        
        function removeExerciseFromRoutine(exIndex) {
            const routines = getRoutines();
            const index = window.currentEditingRoutineIndex;
            const routine = routines[index];
            
            if (!routine) return;
            
            const exerciseName = routine.exercises[exIndex].name;
            showConfirm(`Retirer "${exerciseName}" de la routine ?`, function() {
                routine.exercises.splice(exIndex, 1);
                saveRoutines(routines);
                renderEditRoutineExercises();
                showToast('❌ Exercice retiré');
            }, null, { title: 'Retirer l\'exercice ?', icon: '❌', confirmLabel: 'Retirer', danger: true });
        }
        
