        function checkEarlyBird() {
            const history = getWorkoutHistory();
            return history.some(entry => {
                const hour = new Date(entry.date).getHours();
                return hour < 8;
            });
        }

        function getUnlockedBadges() {
            const saved = localStorage.getItem('unlockedBadges');
            try { return saved ? JSON.parse(saved) : []; } catch(e) { return []; }
        }

        function checkAndUnlockBadges() {
            const stats = loadStats();
            const unlocked = getUnlockedBadges();
            const newlyUnlocked = [];
            
            badges.forEach(badge => {
                if (!unlocked.includes(badge.id) && badge.condition(stats)) {
                    unlocked.push(badge.id);
                    newlyUnlocked.push(badge);
                }
            });
            
            if (newlyUnlocked.length > 0) {
                localStorage.setItem('unlockedBadges', JSON.stringify(unlocked));
                showBadgeUnlockNotification(newlyUnlocked);
            }
            
            renderBadges();
        }

        function showBadgeUnlockNotification(newBadges) {
            newBadges.forEach(badge => {
                // Simple alert for now - could be enhanced with a custom modal
                setTimeout(() => {
                    showToast(`🏆 ${badge.icon} ${badge.name} — ${badge.description}`, 'success', 5000);
                }, 500);
            });
        }

        // ========== ACCORDION SYSTEM FOR HISTORY TAB ==========
        
        function toggleAccordion(headerElement) {
            const accordionSection = headerElement.parentElement;
            const accordionBody = headerElement.nextElementSibling;
            const allSections = document.querySelectorAll('#historyTab .accordion-section');
            
            // If clicking on already open section, just close it
            if (headerElement.classList.contains('active')) {
                headerElement.classList.remove('active');
                accordionBody.classList.remove('open');
                return;
            }
            
            // Close all other sections
            allSections.forEach(section => {
                const header = section.querySelector('.accordion-header');
                const body = section.querySelector('.accordion-body');
                if (header && body) {
                    header.classList.remove('active');
                    body.classList.remove('open');
                }
            });
            
            // Open clicked section
            headerElement.classList.add('active');
            accordionBody.classList.add('open');
            
            // Scroll into view smoothly
            setTimeout(() => {
                accordionSection.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }, 100);
        }
        
        function openAccordionByIndex(index) {
            const sections = document.querySelectorAll('#historyTab .accordion-section');
            if (sections[index]) {
                const header = sections[index].querySelector('.accordion-header');
                if (header) {
                    toggleAccordion(header);
                }
            }
        }
        
        function openAllAccordions() {
            const headers = document.querySelectorAll('#historyTab .accordion-header');
            headers.forEach(header => {
                header.classList.add('active');
                const body = header.nextElementSibling;
                if (body) body.classList.add('open');
            });
        }
        
        function closeAllAccordions() {
            const headers = document.querySelectorAll('#historyTab .accordion-header');
            headers.forEach(header => {
                header.classList.remove('active');
                const body = header.nextElementSibling;
                if (body) body.classList.remove('open');
            });
        }
        
        // Auto-convert remaining .card sections in historyTab to accordions
        function initializeHistoryAccordions() {
            const historyTab = document.getElementById('historyTab');
            if (!historyTab) return;
            
            // Find all .card divs that are not already in accordions
            const cards = historyTab.querySelectorAll('.card');
            
            cards.forEach(card => {
                // Skip if already in an accordion
                if (card.closest('.accordion-section')) return;
                
                // Extract title from h2 or h3
                const titleElement = card.querySelector('h2, h3');
                if (!titleElement) return;
                
                const titleText = titleElement.textContent.trim();
                const titleIcon = titleText.match(/^[\u{1F300}-\u{1F9FF}]/u)?.[0] || '📊';
                const titleWithoutIcon = titleText.replace(/^[\u{1F300}-\u{1F9FF}\s]+/u, '');
                
                // Remove the h2/h3 as it will be in the header
                titleElement.remove();
                
                // Create accordion structure
                const accordionSection = document.createElement('div');
                accordionSection.className = 'accordion-section';
                
                const accordionHeader = document.createElement('div');
                accordionHeader.className = 'accordion-header';
                accordionHeader.onclick = function() { toggleAccordion(this); };
                
                accordionHeader.innerHTML = `
                    <div class="accordion-title">
                        <span>${titleIcon}</span>
                        <span>${titleWithoutIcon}</span>
                    </div>
                    <div class="accordion-icon">▼</div>
                `;
                
                const accordionBody = document.createElement('div');
                accordionBody.className = 'accordion-body';
                
                const accordionContent = document.createElement('div');
                accordionContent.className = 'accordion-content';
                
                // Move card content into accordion
                while (card.firstChild) {
                    accordionContent.appendChild(card.firstChild);
                }
                
                accordionBody.appendChild(accordionContent);
                accordionSection.appendChild(accordionHeader);
                accordionSection.appendChild(accordionBody);
                
                // Replace card with accordion
                card.parentNode.replaceChild(accordionSection, card);
            });
            
        }

