        // Tab switching
        // ── SWIPE GESTURES ─────────────────────────────────────────
        const TAB_ORDER = ['home','workouts','routines','history','exercises','calculators','challenges','settings','game'];

        function initSwipeGestures() {
            let startX = 0, startY = 0, startTime = 0;
            const SWIPE_THRESHOLD  = 60;   // px min
            const SWIPE_MAX_Y      = 80;   // px max vertical drift
            const SWIPE_MAX_TIME   = 400;  // ms max

            document.addEventListener('touchstart', e => {
                // Ignorer si l'utilisateur touche un input, slider ou bouton
                if (['INPUT','SELECT','TEXTAREA','BUTTON'].includes(e.target.tagName)) return;
                startX    = e.touches[0].clientX;
                startY    = e.touches[0].clientY;
                startTime = Date.now();
            }, { passive: true });

            document.addEventListener('touchend', e => {
                if (!startX) return;
                const dx   = e.changedTouches[0].clientX - startX;
                const dy   = e.changedTouches[0].clientY - startY;
                const dt   = Date.now() - startTime;

                // Seulement swipe horizontal rapide
                if (Math.abs(dx) < SWIPE_THRESHOLD) return;
                if (Math.abs(dy) > SWIPE_MAX_Y)     return;
                if (dt > SWIPE_MAX_TIME)             return;
                // Ignorer si l'utilisateur scrolle verticalement
                if (Math.abs(dy) > Math.abs(dx) * 0.7) return;

                // Swipe pendant une séance → exercice suivant/précédent
                const inSession = document.getElementById('exerciseView')?.classList.contains('active')
                               || document.getElementById('exerciseView')?.style.display !== 'none';
                if (inSession) {
                    if (dx < 0 && typeof skipExercise   === 'function') skipExercise();
                    if (dx > 0 && typeof prevExercise   === 'function') prevExercise();
                    return;
                }

                // Swipe dans les onglets
                const idx = TAB_ORDER.indexOf(currentTab);
                if (dx < 0 && idx < TAB_ORDER.length - 1) switchTab(TAB_ORDER[idx + 1]);
                if (dx > 0 && idx > 0)                    switchTab(TAB_ORDER[idx - 1]);

                startX = 0;
            }, { passive: true });
        }

        function switchTab(tabName) {
            if (tabName === 'history' && rpgEnabled()) setTimeout(renderRPGPanel, 50);
            if (tabName === 'game') setTimeout(() => {
                renderGameTab();
            }, 50);
            // Scroll en haut à chaque changement d'onglet
            window.scrollTo({ top: 0, behavior: 'smooth' });

            // Auto-expand nav on mobile when switching tabs
            if (window.innerWidth <= 640) {
                const nav = document.getElementById('mobileNavBar');
                const btn = document.getElementById('navCollapseBtn');
                if (nav) { nav.classList.remove('nav-collapsed'); }
                if (btn) { btn.innerHTML = '⌃'; localStorage.setItem('navCollapsed', false); }
            }
            // Hide all tabs
            document.querySelectorAll('.tab-content').forEach(tab => {
                tab.classList.remove('active');
            });
            document.querySelectorAll('.nav-tab').forEach(tab => {
                tab.classList.remove('active');
            });

            // Show selected tab
            const tabElement = document.getElementById(tabName + 'Tab');
            if (tabElement) {
                tabElement.classList.add('active');
            }
            
            // Highlight nav button
            const navButtons = document.querySelectorAll('.nav-tab');
            navButtons.forEach((btn, index) => {
                const tabs = ['home', 'workouts', 'routines', 'history', 'exercises', 'calculators', 'challenges', 'settings', 'custom', 'game'];
                if (tabs[index] === tabName) {
                    btn.classList.add('active');
                }
            });
            
            currentTab = tabName;

            // Initialize tab-specific content
            if (tabName === 'home') {
                updateHomeStats(); renderWeeklyMuscleVolume();
            } else if (tabName === 'workouts') {
                renderActivePlan();
                renderLocationBtns();
                renderDeloadBanner();
            } else if (tabName === 'exercises') {
                // Check if filters are active, if not show welcome screen
                filterExercises();
                updateProgressGraphExerciseList(); // ✅ Populate progress graphs dropdown
            } else if (tabName === 'calculators') {
                // Initialize accordions
                initializeCalculatorsAccordions();
                // Initialize calculators
                populate1RMExercises(); // ✅ Populate 1RM exercise dropdown
                render1RMHistory(); // ✅ Render 1RM history
            } else if (tabName === 'routines') {
                // Initialize routines
                renderRoutinesList();
                renderTemplatesList();
            } else if (tabName === 'settings') {
                // Initialize accordions
                initializeSettingsAccordions();
                renderEquipmentGrid();
                renderMuscleGrid();
                renderNotificationSettings(); // ✅ Render notification settings
                updateAIWorkoutDJUI(); // ✅ Update AI Workout DJ UI
                setTimeout(updateWeightUnitLabels, 200); // ✅ Colorer les boutons unité
                setTimeout(loadAvailableWeightsUI, 250); // ✅ Charger les poids disponibles
                setTimeout(initGlobalRestUI, 280); // ✅ Init repos global
                // Update current profile name in settings
                const profile = getUserProfile();
                const profileNameElement = document.getElementById('currentProfileNameSettings');
                if (profileNameElement && profile) {
                    profileNameElement.textContent = profile.name || 'Athlète';
                }
            } else if (tabName === 'challenges') {
                renderChallengesTab();
            } else if (tabName === 'history') {
                
                // Initialize accordions (convert all .card to accordions)
                initializeHistoryAccordions();
                
                renderBadges();
                renderCalendar();
                renderWorkoutHistory();
                renderFavoriteWorkouts();
                renderProgressPhotos(); // ✅ Render progress photos
                renderBodyMeasurements(); // ✅ Render body measurements
                renderPRList(); // ✅ Render PR list
                renderRPEAnalytics(); // ✅ Render RPE analytics
                renderCardioStats(); // ✅ Render cardio statistics
                
                // Initialize Chart.js graphs
                setTimeout(() => {
                    showChart('sessions');
                }, 100);
                
                // Render advanced statistics
                renderAdvancedStats();
                
                // Update stats in history tab
                const stats = loadStats();
                const _hW = document.getElementById('historyTotalWorkouts');
                const _hM = document.getElementById('historyTotalMinutes');
                const _hS = document.getElementById('historyCurrentStreak');
                if (_hW) _hW.textContent = stats.workouts;
                if (_hM) _hM.textContent = stats.minutes;
                if (_hS) _hS.textContent = stats.streak;
            }
        }

        // Stats management
        // ══════════════════════════════════════════════════════════════════
        // 🚀 SURCHARGE PROGRESSIVE
        // ══════════════════════════════════════════════════════════════════
        function getProgressiveSuggestion(exerciseName) {
            if (!exerciseName) return null;
            const perfs = getExercisePerformances();
            const history = (perfs[exerciseName] || []).filter(p => !p.warmup && p.reps > 0);
            if (history.length < 3) return null;

            const last3 = history.slice(-3);
            const allSameWeight = last3.every(p => p.weight === last3[0].weight);
            const avgReps = last3.reduce((s, p) => s + p.reps, 0) / 3;
            const minReps = Math.min(...last3.map(p => p.reps));

            // Suggest +weight if 3 sessions with same weight & avg reps >= target (12)
            if (allSameWeight && last3[0].weight > 0 && minReps >= 10) {
                const currentW = last3[0].weight;
                const inc = currentW < 10 ? 1 : currentW < 30 ? 2.5 : 5;
                const suggestedW = Math.round((currentW + inc) * 2) / 2;
                return { type: 'weight', currentW, suggestedW, unit: useKg ? 'kg' : 'lbs', avgReps: Math.round(avgReps) };
            }
            // Suggest +reps if weight is bodyweight (0) and avg reps progressing
            if (last3[0].weight === 0 && minReps >= 12) {
                return { type: 'reps', suggestedReps: Math.round(avgReps) + 2, avgReps: Math.round(avgReps) };
            }
            return null;
        }

        function showProgressiveOverloadBanner(exerciseName) {
            const banner = document.getElementById('progressiveOverloadBanner');
            if (!banner) return;
            const suggestion = getProgressiveSuggestion(exerciseName);
            if (!suggestion) { banner.style.display = 'none'; return; }

            if (suggestion.type === 'weight') {
                banner.innerHTML = `📈 <strong>Surcharge progressive</strong> — 3 séances à ${suggestion.currentW}${suggestion.unit} (moy. ${suggestion.avgReps} reps). Essaie <strong>${suggestion.suggestedW}${suggestion.unit}</strong> aujourd'hui !`;
            } else {
                banner.innerHTML = `📈 <strong>Surcharge progressive</strong> — Moy. ${suggestion.avgReps} reps. Vise <strong>${suggestion.suggestedReps} reps</strong> cette série !`;
            }
            banner.style.display = 'block';

            // Pre-fill weight suggestion
            if (suggestion.type === 'weight') {
                const wInput = document.getElementById('quickWeightInput');
                if (wInput && !wInput.value) wInput.value = suggestion.suggestedW;
            }
        }

