        function submitExerciseFeedback(exerciseName, exerciseDuration) {
            const reps = parseInt(document.getElementById('perfReps').value) || 10;
            const difficulty = selectedDifficulty || 3;
            
            const performance = {
                reps: reps,
                difficulty: difficulty,
                feedback: difficulty <= 2 ? "facile" : difficulty >= 4 ? "difficile" : "normal"
            };
            
            const progressionMessage = recordExercisePerformance(exerciseName, performance);
            
            if (currentFeedbackModal) {
                currentFeedbackModal.remove();
                currentFeedbackModal = null;
            }
            
            if (progressionMessage) {
                showProgressionNotification(progressionMessage);
            }
        }
        
        function skipExerciseFeedback() {
            if (currentFeedbackModal) {
                currentFeedbackModal.remove();
                currentFeedbackModal = null;
            }
        }
        
        function showProgressionNotification(progressionMsg) {
            const notification = document.createElement('div');
            notification.style.cssText = `
                position: fixed;
                top: 80px;
                right: 20px;
                background: ${progressionMsg.type === 'success' ? 'linear-gradient(135deg, #4ade80 0%, #22c55e 100%)' : 'linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%)'};
                color: white;
                padding: 20px 25px;
                border-radius: 15px;
                box-shadow: 0 8px 24px rgba(0,0,0,0.15);
                z-index: 10000;
                animation: slideInRight 0.5s ease-out;
                max-width: 350px;
                font-weight: bold;
                font-size: 1.1em;
            `;
            
            notification.innerHTML = progressionMsg.message;
            
            document.body.appendChild(notification);
            
            const style = document.createElement('style');
            style.textContent = `
                @keyframes slideInRight {
                    from { transform: translateX(400px); opacity: 0; }
                    to { transform: translateX(0); opacity: 1; }
                }
            `;
            if (!document.getElementById('progression-animations')) {
                style.id = 'progression-animations';
                document.head.appendChild(style);
            }
            
            if (progressionMsg.type === 'success' && 'vibrate' in navigator) {
                navigator.haptic.pr();
            }
            
            setTimeout(() => {
                notification.style.animation = 'slideInRight 0.5s ease-out reverse';
                setTimeout(() => notification.remove(), 500);
            }, 5000);
        }

        function updateStreak(stats) {
            const today = new Date().toDateString();
            const lastWorkout = stats.lastWorkout ? new Date(stats.lastWorkout).toDateString() : null;
            
            if (lastWorkout === today) {
                return stats.streak;
            } else {
                const yesterday = new Date();
                yesterday.setDate(yesterday.getDate() - 1);
                if (lastWorkout === yesterday.toDateString()) {
                    return stats.streak + 1;
                } else {
                    return 1;
                }
            }
        }

        // ========== MUSCLE RECOVERY TRACKING SYSTEM ==========
        
        function saveMusclesWorked(workout) {
            if (!workout || !workout.exercises) return;
            
            const musclesWorked = {};
            const now = new Date().toISOString();
            
            // Extraire tous les muscles de la séance
            workout.exercises.forEach(exercise => {
                if (!exercise.isRest && !exercise.isInfo) {
                    const exerciseFromDB = exerciseDatabase.find(ex => ex.name === exercise.name);
                    if (exerciseFromDB && exerciseFromDB.muscle) {
                        if (!musclesWorked[exerciseFromDB.muscle]) {
                            musclesWorked[exerciseFromDB.muscle] = {
                                muscle: exerciseFromDB.muscle,
                                lastWorked: now,
                                workoutCount: 1
                            };
                        }
                    }
                }
            });
            
            // Charger historique existant (profile-specific)
            const profileId = getCurrentProfileId();
            const saved = profileId ? getProfileData(profileId, 'muscleRecoveryTracking') : localStorage.getItem('muscleRecoveryTracking');
            let tracking = saved ? JSON.parse(saved) : {};
            
            // Mettre à jour avec nouvelle séance
            Object.keys(musclesWorked).forEach(muscle => {
                if (tracking[muscle]) {
                    tracking[muscle].lastWorked = now;
                    tracking[muscle].workoutCount++;
                } else {
                    tracking[muscle] = musclesWorked[muscle];
                }
            });
            
            // Sauvegarder (profile-specific)
            if (profileId) {
                setProfileData(profileId, 'muscleRecoveryTracking', JSON.stringify(tracking));
            } else {
                localStorage.setItem('muscleRecoveryTracking', JSON.stringify(tracking));
            }
        }
        
        function getMuscleRecoveryStatus(muscleName) {
            const profileId = getCurrentProfileId();
            const saved = profileId ? getProfileData(profileId, 'muscleRecoveryTracking') : localStorage.getItem('muscleRecoveryTracking');
            
            if (!saved) return { status: 'ready', hoursToRecovery: 0, percentage: 100 };
            
            const tracking = JSON.parse(saved);
            if (!tracking[muscleName]) return { status: 'ready', hoursToRecovery: 0, percentage: 100 };
            
            const lastWorked = new Date(tracking[muscleName].lastWorked);
            const now = new Date();
            const hoursSince = (now - lastWorked) / (1000 * 60 * 60);
            
            // Règle : 48h de récupération minimum
            const recoveryNeeded = 48;
            
            if (hoursSince >= recoveryNeeded) {
                return { status: 'ready', hoursToRecovery: 0, percentage: 100 };
            } else if (hoursSince >= recoveryNeeded * 0.75) {
                return { status: 'almost', hoursToRecovery: Math.ceil(recoveryNeeded - hoursSince), percentage: Math.round((hoursSince / recoveryNeeded) * 100) };
            } else if (hoursSince >= recoveryNeeded * 0.5) {
                return { status: 'recovering', hoursToRecovery: Math.ceil(recoveryNeeded - hoursSince), percentage: Math.round((hoursSince / recoveryNeeded) * 100) };
            } else {
                return { status: 'fatigued', hoursToRecovery: Math.ceil(recoveryNeeded - hoursSince), percentage: Math.round((hoursSince / recoveryNeeded) * 100) };
            }
        }
        
        function getAllMusclesRecoveryStatus() {
            const allMuscles = [
                'Pectoraux', 'Dos', 'Épaules', 'Biceps', 'Triceps', 'Trapèzes',
                'Abdominaux', 'Obliques', 'Quadriceps', 'Ischio-jambiers', 'Fessiers', 'Mollets', 'Avant-bras'
            ];
            
            const statuses = {};
            allMuscles.forEach(muscle => {
                statuses[muscle] = getMuscleRecoveryStatus(muscle);
            });
            
            return statuses;
        }
        
        function renderMuscleRecoveryStatus() {
            const container = document.getElementById('muscleRecoveryContainer');
            if (!container) return;
            const statuses = getAllMusclesRecoveryStatus();

            // Color per status
            const col = s => s === 'ready' ? '#22c55e' : s === 'almost' ? '#fbbf24' : s === 'recovering' ? '#f59e0b' : '#ef4444';
            const icon = s => s === 'ready' ? '✅' : s === 'almost' ? '⚡' : s === 'recovering' ? '⏳' : '🚫';
            const label = st => st.status === 'ready' ? 'Prêt' : `${st.hoursToRecovery}h`;

            // Build SVG body map (front + back simplified)
            const muscleMap = {
                // Front — [cx, cy, rx, ry, label_anchor]
                'Pectoraux':       { side:'front', cx:50, cy:105, rx:22, ry:12 },
                'Épaules':         { side:'front', cx:18, cy:90,  rx:8,  ry:8  },
                'Biceps':          { side:'front', cx:14, cy:115, rx:6,  ry:10 },
                'Abdominaux':      { side:'front', cx:50, cy:130, rx:14, ry:15 },
                'Obliques':        { side:'front', cx:32, cy:133, rx:7,  ry:12 },
                'Quadriceps':      { side:'front', cx:37, cy:185, rx:11, ry:20 },
                'Avant-bras':      { side:'front', cx:12, cy:140, rx:5,  ry:10 },
                'Mollets':         { side:'front', cx:38, cy:240, rx:7,  ry:14 },
                // Back
                'Dos':             { side:'back',  cx:50, cy:105, rx:22, ry:20 },
                'Trapèzes':        { side:'back',  cx:50, cy:80,  rx:16, ry:8  },
                'Triceps':         { side:'back',  cx:14, cy:115, rx:6,  ry:10 },
                'Ischio-jambiers': { side:'back',  cx:37, cy:185, rx:11, ry:20 },
                'Fessiers':        { side:'back',  cx:50, cy:155, rx:18, ry:14 },
            };

            const buildSide = (side) => {
                // Body outline
                let paths = `<g opacity="0.15"><ellipse cx="50" cy="62" rx="14" ry="18" fill="white"/>
                    <ellipse cx="50" cy="100" rx="22" ry="28" fill="white"/>
                    <rect x="28" y="128" width="44" height="32" rx="6" fill="white"/>
                    <rect x="33" y="160" width="14" height="65" rx="7" fill="white"/>
                    <rect x="53" y="160" width="14" height="65" rx="7" fill="white"/>
                    <rect x="10" y="82" width="11" height="55" rx="5" fill="white"/>
                    <rect x="79" y="82" width="11" height="55" rx="5" fill="white"/>
                    <rect x="7" y="135" width="9" height="45" rx="4" fill="white"/>
                    <rect x="84" y="135" width="9" height="45" rx="4" fill="white"/>
                </g>`;

                Object.entries(muscleMap).forEach(([muscle, pos]) => {
                    if (pos.side !== side) return;
                    const st = statuses[muscle] || { status: 'ready', percentage: 100 };
                    const c = col(st.status);
                    const opacity = st.status === 'ready' ? 0.6 : st.status === 'almost' ? 0.7 : 0.85;
                    paths += `<ellipse cx="${pos.cx}" cy="${pos.cy}" rx="${pos.rx}" ry="${pos.ry}" fill="${c}" opacity="${opacity}" stroke="${c}" stroke-width="1"/>`;
                    // Mirror left/right muscles
                    if (['Épaules','Biceps','Avant-bras','Triceps','Quadriceps','Ischio-jambiers','Mollets','Obliques'].includes(muscle)) {
                        const mirrorX = 100 - pos.cx;
                        paths += `<ellipse cx="${mirrorX}" cy="${pos.cy}" rx="${pos.rx}" ry="${pos.ry}" fill="${c}" opacity="${opacity}" stroke="${c}" stroke-width="1"/>`;
                    }
                });
                return paths;
            };

            const svgFront = `<svg viewBox="0 0 100 280" width="90" height="140" xmlns="http://www.w3.org/2000/svg">${buildSide('front')}</svg>`;
            const svgBack  = `<svg viewBox="0 0 100 280" width="90" height="140" xmlns="http://www.w3.org/2000/svg">${buildSide('back')}</svg>`;

            // Legend
            const legendHtml = `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px;margin-bottom:12px;justify-content:center;">
                <span style="font-size:0.7em;font-weight:600;color:#22c55e;">✅ Prêt</span>
                <span style="font-size:0.7em;font-weight:600;color:#fbbf24;">⚡ Bientôt prêt</span>
                <span style="font-size:0.7em;font-weight:600;color:#f59e0b;">⏳ En récupération</span>
                <span style="font-size:0.7em;font-weight:600;color:#ef4444;">🚫 Fatigué</span>
            </div>`;

            // Body maps side by side
            const mapsHtml = `
                <div style="display:flex;gap:16px;justify-content:center;margin-bottom:14px;">
                    <div style="text-align:center;">
                        <div style="font-size:0.65em;color:#94a3b8;font-weight:700;margin-bottom:4px;text-transform:uppercase;letter-spacing:1px;">Face</div>
                        ${svgFront}
                    </div>
                    <div style="text-align:center;">
                        <div style="font-size:0.65em;color:#94a3b8;font-weight:700;margin-bottom:4px;text-transform:uppercase;letter-spacing:1px;">Dos</div>
                        ${svgBack}
                    </div>
                </div>`;

            // Compact bar list
            let barsHtml = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">';
            Object.entries(statuses).forEach(([muscle, st]) => {
                barsHtml += `<div style="background:#1e293b;border-radius:8px;padding:6px 8px;border-left:3px solid ${col(st.status)};">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px;">
                        <span style="font-size:0.72em;font-weight:700;color:white;">${muscle}</span>
                        <span style="font-size:0.68em;color:${col(st.status)};font-weight:700;">${label(st)}</span>
                    </div>
                    <div style="height:3px;background:rgba(255,255,255,0.07);border-radius:99px;overflow:hidden;">
                        <div style="height:100%;width:${st.percentage}%;background:${col(st.status)};border-radius:99px;"></div>
                    </div>
                </div>`;
            });
            barsHtml += '</div>';

            container.innerHTML = legendHtml + mapsHtml + barsHtml;
        }
        
        function getReadyMuscles() {
            const statuses = getAllMusclesRecoveryStatus();
            return Object.keys(statuses).filter(muscle => statuses[muscle].status === 'ready');
        }
        
        function getFatiguedMuscles() {
            const statuses = getAllMusclesRecoveryStatus();
            return Object.keys(statuses).filter(muscle => 
                statuses[muscle].status === 'fatigued' || statuses[muscle].status === 'recovering'
            );
        }

        // Exercise database functions
        function displayExercises(exercises) {
            const grid = document.getElementById('exercisesGrid');
            const noResults = document.getElementById('noResults');
            const welcomeScreen = document.getElementById('exercisesWelcome');
            
            // Check if any filters are active
            const hasFilters = checkIfFiltersActive();
            
            // If no filters, show welcome screen
            if (!hasFilters) {
                grid.style.display = 'none';
                noResults.style.display = 'none';
                if (welcomeScreen) welcomeScreen.style.display = 'block';
                document.getElementById('filteredCount').textContent = '0';
                return;
            }
            
            // Hide welcome screen when filters are active
            if (welcomeScreen) welcomeScreen.style.display = 'none';
            
            grid.innerHTML = '';
            
            if (exercises.length === 0) {
                grid.style.display = 'none';
                noResults.style.display = 'block';
                return;
            }
            
            grid.style.display = 'grid';
            noResults.style.display = 'none';
            
            const blacklist = getExerciseBlacklist();
            favoriteExercises = getFavoriteExercises(); // Load favorites
            
            exercises.forEach((exercise) => {
                const isBlacklisted = blacklist.includes(exercise.name);
                const isFav = isFavorite(exercise.name);

                
                const card = document.createElement('div');
                card.className = `exercise-card ${isBlacklisted ? 'blacklisted' : ''}`;
                card.onclick = (e) => {
                    // Ne pas ouvrir détail si on clique sur un bouton
                    if (!e.target.closest('.blacklist-toggle') && !e.target.closest('.favorite-btn') && !e.target.closest('.youtube-btn')) {
                        showExerciseDetail(exercise);
                    }
                };
                
                const difficultyClass = `difficulty-${exercise.difficulty.toLowerCase().replace('é', 'e')}`;
                const svgStart = getExerciseSVG(exercise.name, exercise.muscle, 'start');
                const svgEnd = getExerciseSVG(exercise.name, exercise.muscle, 'end');
                
                card.innerHTML = `
                    <div class="exercise-image">
                        <div class="exercise-animation">
                            <div class="exercise-svg-container">
                                ${svgStart}
                                <div class="position-label position-start">Début</div>
                            </div>
                            <div class="arrow-indicator">→</div>
                            <div class="exercise-svg-container">
                                ${svgEnd}
                                <div class="position-label position-end">Fin</div>
                            </div>
                        </div>
                        <!-- Favorite button (top-right) -->
                        <button class="favorite-btn" 
                                onclick="toggleFavorite('${exercise.name.replace(/'/g, "\\'")}'); event.stopPropagation();"
                                style="position: absolute; top: 10px; right: 10px; background: ${isFav ? '#fbbf24' : '#ffffff80'}; border: none; border-radius: 50%; width: 40px; height: 40px; font-size: 1.3em; cursor: pointer; box-shadow: 0 2px 8px rgba(0,0,0,0.2); transition: all 0.2s; backdrop-filter: blur(10px);"
                                title="${isFav ? 'Retirer des favoris' : 'Ajouter aux favoris'}">
                            ${isFav ? '⭐' : '☆'}
                        </button>
                    </div>
                    <div class="exercise-card-content">
                        <div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 10px;">
                            <div style="flex: 1;">
                                <div class="exercise-title">${exercise.name}</div>
                                <div class="muscle-group">${exercise.muscle}</div>
                            </div>
                            <div class="difficulty-badge ${difficultyClass}">
                                ${exercise.difficulty}
                            </div>
                        </div>
                        <div class="exercise-description">${exercise.description}</div>
                        <div class="exercise-meta">
                            <span>🏋️ ${exercise.equipment.join(', ')}</span>
                            <span>📋 ${exercise.instructions.length} étapes</span>
                        </div>
                        
                        <!-- YouTube search button -->
                        <button class="youtube-btn" 
                                onclick="openYouTubeVideo(null, '${exercise.name.replace(/'/g, "\\'")}'); event.stopPropagation();"
                                style="width: 100%; margin-top: 10px; padding: 10px; background: #ff0000; color: white; border: none; border-radius: 8px; cursor: pointer; font-weight: bold; display: flex; align-items: center; justify-content: center; gap: 8px; transition: all 0.2s;">
                            <span style="font-size: 1.2em;">▶️</span>
                            <span>Rechercher sur YouTube</span>
                        </button>
                        
                        <button class="blacklist-toggle ${isBlacklisted ? 'active' : ''}" 
                                onclick="toggleExerciseBlacklist('${exercise.name.replace(/'/g, "\\'")}'); event.stopPropagation();" 
                                title="${isBlacklisted ? 'Réactiver cet exercice' : 'Désactiver cet exercice'}"
                                style="width: 100%; margin-top: 10px; padding: 8px; border: 2px solid ${isBlacklisted ? '#ef4444' : '#d1d5db'}; background: ${isBlacklisted ? '#fee2e2' : 'white'}; color: ${isBlacklisted ? '#ef4444' : '#666'}; border-radius: 8px; cursor: pointer; font-weight: bold; transition: all 0.2s;">
                            ${isBlacklisted ? '🚫 Désactivé' : '👁️ Actif'}
                        </button>
                    </div>
                `;
                
                grid.appendChild(card);
            });
            
            document.getElementById('filteredCount').textContent = exercises.length;
        }

        // ========== EXERCISE BLACKLIST SYSTEM ==========
        
        function getExerciseBlacklist() {
            const saved = localStorage.getItem('exerciseBlacklist');
            try { return saved ? JSON.parse(saved) : []; } catch(e) { return []; }
        }
        
        function saveExerciseBlacklist(blacklist) {
            localStorage.setItem('exerciseBlacklist', JSON.stringify(blacklist));
        }
        
        function toggleExerciseBlacklist(exerciseName) {
            let blacklist = getExerciseBlacklist();
            
            if (blacklist.includes(exerciseName)) {
                // Retirer de la blacklist
                blacklist = blacklist.filter(name => name !== exerciseName);
                speak("Exercice réactivé");
            } else {
                // Ajouter à la blacklist
                blacklist.push(exerciseName);
                speak("Exercice désactivé");
            }
            
            saveExerciseBlacklist(blacklist);
            
            // Rafraîchir affichage
            filterExercises();
        }
        
        function filterBlacklistedExercises(exercises) {
            const blacklist = getExerciseBlacklist();
            return exercises.filter(ex => !blacklist.includes(ex.name));
        }

        function checkIfFiltersActive() {
            const searchTerm = document.getElementById('searchInput').value;
            const muscleFilter = document.getElementById('muscleFilter').value;
            const difficultyFilter = document.getElementById('difficultyFilter').value;
            const equipmentFilter = document.getElementById('equipmentFilter').value;
            
            return searchTerm || muscleFilter || difficultyFilter || equipmentFilter || isShowingFavoritesOnly;
        }

        function filterExercises() {
            isShowingFavoritesOnly = false;
            const raw     = (document.getElementById('searchInput')?.value || '').toLowerCase().trim();
            const muscle  = document.getElementById('muscleFilter')?.value || '';
            const diff    = document.getElementById('difficultyFilter')?.value || '';
            const equip   = document.getElementById('equipmentFilter')?.value || '';

            // ── Fuzzy / multi-mot ───────────────────────────────────
            // Ex: "push up chest" → cherche chaque mot séparément
            const words = raw.split(/\s+/).filter(Boolean);

            const matchesSearch = ex => {
                if (!words.length) return true;
                const haystack = [
                    ex.name,
                    ex.description || '',
                    ex.muscle || '',
                    ex.equipment || '',
                    ex.difficulty || '',
                    (ex.tags || []).join(' ')
                ].join(' ').toLowerCase();
                return words.every(w => haystack.includes(w));
            };

            filteredExercises = exerciseDatabase.filter(ex => {
                if (!matchesSearch(ex))                                    return false;
                if (muscle && ex.muscle !== muscle)                        return false;
                if (diff   && ex.difficulty !== diff)                      return false;
                if (equip  && !ex.equipment.includes(equip))               return false;
                return true;
            });

            // Trier : correspondance exacte sur le nom en premier
            if (raw) {
                filteredExercises.sort((a, b) => {
                    const aName = a.name.toLowerCase().startsWith(raw) ? 0 : 1;
                    const bName = b.name.toLowerCase().startsWith(raw) ? 0 : 1;
                    return aName - bName;
                });
            }

            displayExercises(filteredExercises);
        }

        function quickFilter(type, value) {
            // Reset favorites-only mode
            isShowingFavoritesOnly = false;
            
            // Reset all filters first
            document.getElementById('searchInput').value = '';
            document.getElementById('muscleFilter').value = '';
            document.getElementById('difficultyFilter').value = '';
            document.getElementById('equipmentFilter').value = '';
            
            // Apply the selected filter
            if (type === 'muscle') {
                document.getElementById('muscleFilter').value = value;
            } else if (type === 'difficulty') {
                document.getElementById('difficultyFilter').value = value;
            } else if (type === 'equipment') {
                document.getElementById('equipmentFilter').value = value;
            }
            
            // Trigger filter
            filterExercises();
            
            // Scroll to results
            document.getElementById('exercisesGrid').scrollIntoView({ behavior: 'smooth', block: 'start' });
        }

        function resetFilters() {
            document.getElementById('searchInput').value = '';
            document.getElementById('muscleFilter').value = '';
            document.getElementById('difficultyFilter').value = '';
            document.getElementById('equipmentFilter').value = '';
            filterExercises();
        }

        function showExerciseDetail(exercise) {
            currentExerciseForModal = exercise;
            const modal = document.getElementById('exerciseModal');
            
            document.getElementById('modalTitle').textContent = exercise.name;
            document.getElementById('modalMuscle').textContent = exercise.muscle;
            document.getElementById('modalDescription').textContent = exercise.description;
            document.getElementById('modalTips').textContent = exercise.tips;
            
            const difficultyClass = `difficulty-${exercise.difficulty.toLowerCase().replace('é', 'e')}`;
            const svgStart = getExerciseSVG(exercise.name, exercise.muscle, 'start');
            const svgEnd = getExerciseSVG(exercise.name, exercise.muscle, 'end');
            
            document.getElementById('modalDifficulty').innerHTML = 
                `<div class="exercise-image" style="margin: 15px 0; height: 340px; border-radius: 12px;">
                    <div class="exercise-animation">
                        <div class="exercise-svg-container">
                            ${svgStart}
                            <div class="position-label position-start">Début</div>
                        </div>
                        <div class="arrow-indicator">→</div>
                        <div class="exercise-svg-container">
                            ${svgEnd}
                            <div class="position-label position-end">Fin</div>
                        </div>
                    </div>
                </div>
                <div class="difficulty-badge ${difficultyClass}" style="display: inline-block; margin: 10px 0;">${exercise.difficulty}</div>`;
            
            const equipmentContainer = document.getElementById('modalEquipment');
            if (!equipmentContainer) return;
            equipmentContainer.innerHTML = exercise.equipment.map(eq => 
                `<span class="equipment-tag">${eq}</span>`
            ).join('');
            
            const instructionsList = document.getElementById('modalInstructions');
            if (!instructionsList) return;
            instructionsList.innerHTML = '';
            exercise.instructions.forEach(instruction => {
                const li = document.createElement('li');
                li.textContent = instruction;
                instructionsList.appendChild(li);
            });
            
            modal.classList.add('active');
        }

        function closeExerciseModal() {
            document.getElementById('exerciseModal').classList.remove('active');
        }

        // Workout session functions
        function startWorkout(type) {
            // Workout engine - M.A. Lecompte
            currentWorkout = workoutPrograms[type];
            currentWorkout.type = 'predefined';
            currentWorkout.programType = type;
            currentExerciseIndex = 0;
            workoutStartTime = Date.now();
            
            // Afficher le badge de programme
            const badge = document.getElementById('workoutTypeBadge');
            if (badge) {
                const programNames = {
                    'hiit': '🔥 HIIT Intense',
                    'strength': '💪 Force',
                    'mobility': '🧘 Mobilité',
                    'cardio': '❤️ Cardio'
                };
                badge.innerHTML = programNames[type] || '🏋️ Programme';
                badge.style.background = 'linear-gradient(135deg, #16a34a 0%, #15803d 100%)';
                badge.style.display = 'block';
            }
            
            document.getElementById('workoutSelection').style.display = 'none';
            document.getElementById('exerciseView').classList.remove('hidden'); document.body.classList.add('in-session');
            
            renderExerciseProgressList();
            updateMusclesOverview();
            startExercise();
        }

        function updateMusclesOverview() {
            const musclesOverviewBadge = document.getElementById('musclesOverviewBadge');
            if (!musclesOverviewBadge || !currentWorkout) return;
            
            // Extraire tous les muscles uniques de la séance
            const musclesSet = new Set();
            
            currentWorkout.exercises.forEach(exercise => {
                // Chercher l'exercice dans la database
                const exerciseFromDB = exerciseDatabase.find(ex => ex.name === exercise.name);
                
                if (exerciseFromDB && exerciseFromDB.muscle) {
                    // Ne pas ajouter si c'est un exercice de repos/info
                    if (!exercise.isRest && !exercise.isInfo) {
                        musclesSet.add(exerciseFromDB.muscle);
                    }
                }
            });
            
            // Convertir Set en Array et afficher
            const musclesList = Array.from(musclesSet);
            
            if (musclesList.length > 0) {
                // Emojis par muscle
                const muscleEmojis = {
                    'Pectoraux': '💪',
                    'Dos': '🦸',
                    'Épaules': '🏋️',
                    'Biceps': '💪',
                    'Triceps': '🔱',
                    'Abdominaux': '🔥',
                    'Quadriceps': '🦵',
                    'Ischio-jambiers': '🦿',
                    'Fessiers': '🍑',
                    'Mollets': '👟',
                    'Cardio': '❤️',
                    'Corps entier': '🤸‍♂️'
                };
                
                // Créer la liste avec emojis
                const musclesWithEmojis = musclesList.map(muscle => {
                    const emoji = muscleEmojis[muscle] || '💪';
                    return `${emoji} ${muscle}`;
                });
                
                musclesOverviewBadge.innerHTML = `<strong>Muscles ciblés :</strong> ${musclesWithEmojis.join(' • ')}`;
                musclesOverviewBadge.style.display = 'block';
            } else {
                musclesOverviewBadge.style.display = 'none';
            }
        }

        function renderExerciseProgressList() {
            const container = document.getElementById('exerciseProgressItems');
            if (!container) return;
            container.innerHTML = '';
            
            // Calculate total duration - ensure duration is in seconds
            const totalSeconds = currentWorkout.exercises.reduce((sum, ex) => {
                const duration = typeof ex.duration === 'number' ? ex.duration : 60;
                return sum + duration;
            }, 0);
            const totalMinutes = Math.ceil(totalSeconds / 60);
            document.getElementById('totalDuration').textContent = totalMinutes;
            
            currentWorkout.exercises.forEach((exercise, index) => {
                const item = document.createElement('div');
                item.className = 'progress-item';
                item.id = `progress-item-${index}`;
                
                if (index < currentExerciseIndex) {
                    item.classList.add('completed');
                } else if (index === currentExerciseIndex) {
                    item.classList.add('current');
                } else {
                    item.classList.add('upcoming');
                }
                
                const minutes = Math.floor(exercise.duration / 60);
                const seconds = exercise.duration % 60;
                const durationText = minutes > 0 ? `${minutes}:${String(seconds).padStart(2, '0')} min` : `${seconds}s`;
                
                // Find exercise type from database to add badge
                const exerciseFromDB = exerciseDatabase.find(ex => ex.name === exercise.name);
                let exerciseNameHTML = exercise.name;
                
                if (exerciseFromDB) {
                    if (exerciseFromDB.type === 'warmup') {
                        exerciseNameHTML = `<span style="display: inline-block; background: #fbbf24; color: white; padding: 2px 6px; border-radius: 8px; font-size: 0.7em; margin-right: 5px;">🏃‍♂️</span>${exercise.name}`;
                    } else if (exerciseFromDB.type === 'stretch') {
                        exerciseNameHTML = `<span style="display: inline-block; background: #22c55e; color: white; padding: 2px 6px; border-radius: 8px; font-size: 0.7em; margin-right: 5px;">🧘</span>${exercise.name}`;
                    }
                }
                
                item.innerHTML = `
                    <div class="progress-checkbox">
                        ${index < currentExerciseIndex ? '✓' : index === currentExerciseIndex ? '▶' : ''}
                    </div>
                    <div class="progress-item-content">
                        <div class="progress-item-name">${exerciseNameHTML}</div>
                        <div class="progress-item-duration">${durationText}</div>
                    </div>
                `;
                
                container.appendChild(item);
            });
            
            updateProgressStats();
        }

        function updateProgressStats() {
            const allEx = currentWorkout.exercises;
            const realTotal = allEx.filter(ex => !ex.isRest && !ex.isInfo).length;
            let completed = 0;
            for (let i = 0; i < currentExerciseIndex && i < allEx.length; i++) {
                if (!allEx[i].isRest && !allEx[i].isInfo) completed++;
            }
            const remaining = realTotal - completed;
            
            document.getElementById('completedCount').textContent = completed;
            document.getElementById('remainingCount').textContent = remaining;
        }

        function updateExerciseProgressList() {
            // Update all items
            currentWorkout.exercises.forEach((exercise, index) => {
                const item = document.getElementById(`progress-item-${index}`);
                if (!item) return;
                
                // Remove all state classes
                item.classList.remove('completed', 'current', 'upcoming');
                
                // Add appropriate class
                if (index < currentExerciseIndex) {
                    item.classList.add('completed');
                } else if (index === currentExerciseIndex) {
                    item.classList.add('current');
                } else {
                    item.classList.add('upcoming');
                }
                
                // Update checkbox
                const checkbox = item.querySelector('.progress-checkbox');
                if (index < currentExerciseIndex) {
                    checkbox.textContent = '✓';
                } else if (index === currentExerciseIndex) {
                    checkbox.textContent = '▶';
                } else {
                    checkbox.textContent = '';
                }
            });
            
            updateProgressStats();
            
            // Scroll current item into view
            const currentItem = document.getElementById(`progress-item-${currentExerciseIndex}`);
            if (currentItem) {
                currentItem.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }
        }

        function startExercise() {
            if (currentExerciseIndex >= currentWorkout.exercises.length) {
                completeWorkout();
                return;
            }

            // Fermer l'overlay repos si un exercice normal démarre
            const _nextEx = currentWorkout.exercises[currentExerciseIndex];
            if (_nextEx && !_nextEx.isRest) hideRestOverlay();

            // Masquer immédiatement le tracker — sera ré-affiché seulement si reps mode
            var repsDiv = document.getElementById('repsTrackingInputs');
            if (repsDiv) repsDiv.style.display = 'none';

            const exercise = currentWorkout.exercises[currentExerciseIndex];
            
            // isInfo : panneaux d'info — skip automatique vers exercice suivant
            if (exercise.isInfo) {
                // Afficher un toast et passer directement
                showToast('📢 ' + exercise.name, 'info', 2000);
                currentExerciseIndex++;
                startExercise();
                return;
            }

            // FORCE rest periods to always be timer mode
            if (exercise.isRest || exercise.name === 'Repos' || exercise.name === 'Récupération') {
                exercise.mode = 'timer';
                exercise.isRest = true; // Ensure flag is set
            }
            
            // AUTO-FIX: If exercise doesn't have a mode, determine it now
            if (!exercise.mode && !exercise.isRest && !exercise.isInfo) {
                const workoutMode = currentWorkout.mode || 'timer';
                
                // Find exercise in database to check type
                const exerciseFromDB = exerciseDatabase.find(ex => ex.name === exercise.name);
                
                // Warmup and stretch always use timer, even in reps mode
                if (exerciseFromDB && (exerciseFromDB.type === 'warmup' || exerciseFromDB.type === 'stretch')) {
                    exercise.mode = 'timer';
                } else {
                    exercise.mode = determineExerciseMode(exercise.name, workoutMode);
                    exercise.exerciseType = getExerciseType(exercise.name);
                    
                    // Get last performance if reps mode
                    if (exercise.mode === 'reps') {
                        const lastPerf = getLastPerformance(exercise.name);
                        if (lastPerf) {
                            exercise.lastPerformance = lastPerf;
                        }
                    }
                }
            }
            
            // Set time remaining (even for reps mode, we keep the interface)
            timeRemaining = (exercise.duration && exercise.duration > 0) ? exercise.duration : 60;
            isPaused = false;

            // Vibration début exercice
            if (!exercise.isRest && !exercise.isInfo) {
                vibrate(100);
            }

            const _prog = getExerciseProgress();
            document.getElementById('exerciseNumber').textContent = (exercise && (exercise.isRest || exercise.isInfo))
                ? `Repos · ${_prog.current}/${_prog.total} exercices`
                : `Exercice ${_prog.current}/${_prog.total}`;
            
            // Safety check for exercise name
            const exerciseName = exercise.name || 'Exercice';
            
            // Find exercise type from database to add badge
            const exerciseFromDB = exerciseDatabase.find(ex => ex.name === exerciseName);
            let exerciseNameHTML = exerciseName;
            
            if (exerciseFromDB) {
                if (exerciseFromDB.type === 'warmup') {
                    exerciseNameHTML = `<span style="display: inline-block; background: #fbbf24; color: white; padding: 4px 12px; border-radius: 20px; font-size: 0.8em; margin-right: 10px; font-weight: bold;">🏃‍♂️ ÉCHAUFFEMENT</span>${exercise.name}`;
                } else if (exerciseFromDB.type === 'stretch') {
                    exerciseNameHTML = `<span style="display: inline-block; background: #22c55e; color: white; padding: 4px 12px; border-radius: 20px; font-size: 0.8em; margin-right: 10px; font-weight: bold;">🧘 ÉTIREMENT</span>${exercise.name}`;
                }
            }
            
            // Mettre à jour la top bar
            const _topTitle = document.getElementById('workoutTopTitle');
            if (_topTitle && currentWorkout) _topTitle.textContent = currentWorkout.name || '';

            // Animation de transition sur le nom de l'exercice
            const nameEl = document.getElementById('exerciseName');
            if (nameEl && currentExerciseIndex > 0 && !exercise.isRest) {
                nameEl.style.animation = 'none';
                nameEl.offsetHeight; // reflow
                nameEl.style.animation = 'slideInRight 0.35s cubic-bezier(0.22,1,0.36,1) both';
            }
            nameEl.innerHTML = exerciseNameHTML;
            
            // ✅ NEW: Display progression note if exists
            if (exercise.progressionNote && !exercise.isRest && !exercise.isInfo) {
                const progressionBadge = document.createElement('div');
                progressionBadge.style.cssText = 'display: inline-block; background: linear-gradient(135deg, #16a34a 0%, #15803d 100%); color: white; padding: 6px 14px; border-radius: 20px; font-size: 0.85em; margin-left: 10px; font-weight: bold; box-shadow: 0 2px 8px rgba(22,163,74,0.3);';
                progressionBadge.textContent = exercise.progressionNote;
                document.getElementById('exerciseName').appendChild(progressionBadge);
            }
            
            // AFFICHER LE MUSCLE SOLLICITÉ
            const swapBtn = document.getElementById('swapBtn');
            if (swapBtn) {
                swapBtn.style.display = (!exercise.isRest && !exercise.isInfo) ? 'flex' : 'none';
            }
            // Bouton Machine Occupée — visible si exercice machine et mode gym
            const occBtn = document.getElementById('machineOccupiedBtn');
            if (occBtn) {
                const isMachineExercise = (exercise.equipment||[]).some(e => ['Machine','Barre','Rameur','Câble'].includes(e));
                occBtn.style.display = (sessionMode === 'gym' && isMachineExercise && !exercise.isRest && !exercise.isInfo) ? 'flex' : 'none';
            }
            // Sync la rangée contextuelle
            syncContextualBtns();
            // Bouton YouTube — visible si l'exercice a une vidéo
            const ytBtn = document.getElementById('workoutYoutubeBtn');
            if (ytBtn) {
                ytBtn.style.display = (!exercise.isRest && !exercise.isInfo) ? 'inline-flex' : 'none';
            }
            const prevBtn = document.getElementById('prevBtn');
            if (prevBtn) {
                prevBtn.style.opacity = currentExerciseIndex > 0 ? '1' : '0.3';
                prevBtn.style.pointerEvents = currentExerciseIndex > 0 ? 'auto' : 'none';
            }
            const muscleBadge = document.getElementById('muscleBadge');
            if (muscleBadge) {
                if (exerciseFromDB && exerciseFromDB.muscle && !exercise.isRest && !exercise.isInfo) {
                    // Emojis par muscle
                    const muscleEmojis = {
                        'Pectoraux': '💪',
                        'Dos': '🦸',
                        'Épaules': '🏋️',
                        'Biceps': '💪',
                        'Triceps': '🔱',
                        'Abdominaux': '🔥',
                        'Quadriceps': '🦵',
                        'Ischio-jambiers': '🦿',
                        'Fessiers': '🍑',
                        'Mollets': '👟',
                        'Cardio': '❤️',
                        'Corps entier': '🤸‍♂️'
                    };
                    const emoji = muscleEmojis[exerciseFromDB.muscle] || '💪';
                    muscleBadge.innerHTML = `${emoji} ${exerciseFromDB.muscle}`;
                    muscleBadge.style.display = 'inline-block';
                } else {
                    muscleBadge.style.display = 'none';
                }
            }

            // AFFICHER L'ÉQUIPEMENT REQUIS
            const equipmentBadges = document.getElementById('equipmentBadges');
            if (equipmentBadges) {
                if (exerciseFromDB && exerciseFromDB.equipment && exerciseFromDB.equipment.length > 0 && !exercise.isRest && !exercise.isInfo) {
                    const equipIcons = {
                        'Poids du corps': '🤸',
                        'Haltères':       '🏋️',
                        'Barre':          '🥊',
                        'Kettlebell':     '⚫',
                        'Élastique':      '🎗️',
                        'Bande élastique':'🎗️',
                        'Banc':           '🪑',
                        'Barre de traction':'🦾',
                        'Corde à sauter': '🪢',
                        'TRX':            '🎽',
                        'Swiss Ball':     '⚽',
                        'Machine':        '⚙️',
                        'Medicine Ball':  '🏀',
                        'Barres parallèles':'🏗️',
                        'Roue abdominale':'🔄',
                        'Rameur':         '🚣',
                        'Tapis roulant':  '🏃',
                    };
                    equipmentBadges.innerHTML = exerciseFromDB.equipment.map(eq => {
                        const icon = equipIcons[eq] || '🏋️';
                        return `<span style="
                            display:inline-flex;align-items:center;gap:5px;
                            background:rgba(255,255,255,0.18);
                            border:1px solid rgba(255,255,255,0.3);
                            color:white;
                            padding:4px 10px;
                            border-radius:20px;
                            font-size:0.78em;
                            font-weight:600;
                            backdrop-filter:blur(6px);
                        ">${icon} ${eq}</span>`;
                    }).join('');
                    equipmentBadges.style.display = 'flex';
                } else {
                    equipmentBadges.innerHTML = '';
                    equipmentBadges.style.display = 'none';
                }
            }
            
            // SPECIAL DISPLAY FOR REST PERIODS — overlay plein écran
            if (exercise.isRest) {
                // Prochain exercice non-repos
                const nextEx = currentWorkout.exercises[currentExerciseIndex + 1];
                const nextReal = nextEx && !nextEx.isRest && !nextEx.isInfo ? nextEx : null;
                const nextName   = nextReal ? nextReal.name : null;
                const nextMuscle = nextReal ? (nextReal.muscle || '') : '';

                // Emoji par muscle
                const muscleEmoji = {
                    'Pectoraux': '🫀', 'Dos': '🦸', 'Épaules': '🏋️',
                    'Biceps': '💪', 'Triceps': '🔱', 'Quadriceps': '🦵',
                    'Ischio-jambiers': '🦵', 'Fessiers': '🍑', 'Mollets': '👟',
                    'Abdominaux': '🔥', 'Cardio': '❤️', 'Corps entier': '⚡',
                    'Avant-bras': '🤜', 'Obliques': '🌀', 'Trapèzes': '🏔️'
                };
                const emoji = nextMuscle ? (muscleEmoji[nextMuscle] || '💪') : '⏭️';

                // Remplir l'overlay
                const restCount   = $el('restCountDisplay');
                const restNext    = $el('restNextName');
                const restCard    = $el('restNextCard');
                const restEmoji   = $el('restNextEmoji');
                const restMuscle  = $el('restNextMuscle');
                const restArc     = document.getElementById('restRingArc');

                const CIRC = 553; // 2 * π * 88
                if (restCount) restCount.textContent = exercise.duration;
                if (restNext)  restNext.textContent  = nextName || 'Fin de séance';
                if (restEmoji) restEmoji.textContent  = emoji;
                if (restMuscle) {
                    restMuscle.textContent = nextMuscle || '';
                    restMuscle.style.display = nextMuscle ? 'inline-block' : 'none';
                }
                if (restCard) {
                    // Re-trigger card animation on each rest
                    restCard.style.animation = 'none';
                    restCard.offsetHeight; // reflow
                    restCard.style.animation = '';
                }
                if (restArc) restArc.style.strokeDashoffset = '0';

                // Stocker durée totale pour la barre + l'anneau
                window._restTotalDuration = exercise.duration;

                // Citation de la personnalité active
                const celebId = currentWorkout && currentWorkout._celebrity;
                if (celebId) {
                    setTimeout(() => _showCelebrityQuoteInRest(celebId), 300);
                } else {
                    document.getElementById('_celebQuote')?.remove();
                }

                // Afficher l'overlay
                const overlay = document.getElementById('restOverlay');
                if (overlay) overlay.classList.add('active');

                // Message motivationnel aléatoire
                setTimeout(() => showRestMotivationMessage(), 400);

                // Interval dédié : met à jour chiffre + anneau SVG
                clearInterval(window._restOverlayInterval);
                let restLeft = exercise.duration;
                window._restOverlayInterval = setInterval(() => {
                    if (isPaused) return;
                    restLeft--;
                    if (restCount) restCount.textContent = restLeft > 0 ? restLeft : 0;

                    // Anneau SVG : strokeDashoffset proportionnel
                    const pct = restLeft > 0 ? restLeft / window._restTotalDuration : 0;
                    if (restArc) restArc.style.strokeDashoffset = ((1 - pct) * CIRC).toFixed(1);

                    // Couleur d'urgence : vire au rouge sous 5s
                    if (restArc) {
                        restArc.style.stroke = restLeft <= 5 ? '#ef4444' : '#22c55e';
                    }
                    if (restCount) {
                        restCount.style.color = restLeft <= 5 ? '#ef4444' : 'white';
                    }
                    // Vibration d'alerte à 5s restantes
                    if (restLeft === 5) vibrate([30, 20, 30]);

                    if (restLeft <= 0) {
                        clearInterval(window._restOverlayInterval);
                        playRestEndSound();
                        hideRestOverlay();
                    }
                }, 1000);

                speak("Temps de repos");
                startTimer();
                return;
            } else {
                // Fermer l'overlay si on revient sur un exercice normal
                hideRestOverlay();
                const timerDisplay = document.getElementById('timerDisplay');
                timerDisplay.style.background = 'none';
            }
            
            // 🎤 Coach vocal enrichi — annonce exercice + muscle + motivation
            if (!exercise.isRest && !exercise.isInfo) {
                speakEnhancedExercise(exercise);
            }

            // 🚀 Surcharge progressive — suggestion au démarrage de l'exercice
            if (!exercise.isRest && !exercise.isInfo) {
                const exKey = exercise._baseName || exercise.name;
                showProgressiveOverloadBanner(exKey);
                // ❤️ Mettre à jour bouton favori
                updateSessionFavBtn(exKey);
            }
            
            // Update next exercise preview - skip rest periods
            const nextExercisePreview = document.getElementById('nextExercisePreview');
            const nextExerciseNameElement = document.getElementById('nextExerciseName');
            
            // Find next non-rest exercise
            let nextExerciseIndex = currentExerciseIndex + 1;
            let nextExercise = null;
            
            while (nextExerciseIndex < currentWorkout.exercises.length) {
                const candidate = currentWorkout.exercises[nextExerciseIndex];
                if (!candidate.isRest && !candidate.isInfo) {
                    nextExercise = candidate;
                    break;
                }
                nextExerciseIndex++;
            }
            
            if (nextExercise) {
                const nextExerciseName = nextExercise.name || 'Exercice';
                
                // Find next exercise type from database
                const nextExerciseFromDB = exerciseDatabase.find(ex => ex.name === nextExerciseName);
                let nextExerciseHTML = nextExerciseName;
                
                if (nextExerciseFromDB) {
                    if (nextExerciseFromDB.type === 'warmup') {
                        nextExerciseHTML = `<span style="display: inline-block; background: #fbbf24; color: white; padding: 3px 8px; border-radius: 12px; font-size: 0.7em; margin-right: 6px; font-weight: bold;">🏃‍♂️</span>${nextExercise.name}`;
                    } else if (nextExerciseFromDB.type === 'stretch') {
                        nextExerciseHTML = `<span style="display: inline-block; background: #22c55e; color: white; padding: 3px 8px; border-radius: 12px; font-size: 0.7em; margin-right: 6px; font-weight: bold;">🧘</span>${nextExercise.name}`;
                    }
                }
                
                nextExerciseNameElement.innerHTML = nextExerciseHTML;
                nextExercisePreview.style.display = 'block';
            } else {
                nextExercisePreview.style.display = 'none';
            }
            
            // Add exercise illustrations to timer
            const timerElement = document.querySelector('.timer');
            const existingImage = timerElement.querySelector('.exercise-timer-images');
            if (existingImage) existingImage.remove();
            
            // Try to guess muscle group from exercise name
            let muscleGuess = 'Corps entier';
            const nameLower = (exerciseName || '').toLowerCase();
            if (nameLower.includes('pompe')) muscleGuess = 'Pectoraux';
            else if (nameLower.includes('squat')) muscleGuess = 'Quadriceps';
            else if (nameLower.includes('planche')) muscleGuess = 'Abdominaux';
            else if (nameLower.includes('burpee') || nameLower.includes('jack') || nameLower.includes('jump')) muscleGuess = 'Cardio';
            else if (nameLower.includes('curl')) muscleGuess = 'Biceps';
            else if (nameLower.includes('traction')) muscleGuess = 'Dos';
            else if (nameLower.includes('fente')) muscleGuess = 'Quadriceps';
            
            const svgStart = getExerciseSVG(exerciseName, muscleGuess, 'start');
            const svgEnd = getExerciseSVG(exerciseName, muscleGuess, 'end');
            
            const imagesDiv = document.createElement('div');
            imagesDiv.className = 'exercise-timer-images';
            imagesDiv.style.cssText = 'display: flex; gap: 20px; align-items: center; justify-content: center; margin: 20px auto; max-width: 700px; width: 100%;';
            imagesDiv.innerHTML = `
                <div style="flex: 1; display: flex; flex-direction: column; align-items: center; min-width: 0;">
                    <div style="width: 100%; max-width: 260px; aspect-ratio: 1; opacity: 1;">${svgStart}</div>
                    <span style="font-size: 0.9em; margin-top: 8px; opacity: 0.8; font-weight: 600; color: #4ade80;">▶ Début</span>
                </div>
                <div style="font-size: 2em; opacity: 0.5; flex-shrink: 0;">→</div>
                <div style="flex: 1; display: flex; flex-direction: column; align-items: center; min-width: 0;">
                    <div style="width: 100%; max-width: 260px; aspect-ratio: 1; opacity: 1;">${svgEnd}</div>
                    <span style="font-size: 0.9em; margin-top: 8px; opacity: 0.8; font-weight: 600; color: #ef4444;">■ Fin</span>
                </div>
            `;
            
            const exerciseNameElement = document.getElementById('exerciseName');
            exerciseNameElement.parentNode.insertBefore(imagesDiv, exerciseNameElement.nextSibling);
            
            const instructions = document.getElementById('exerciseInstructions');
            if (!instructions) return;
            instructions.innerHTML = '';
            
            // Remove any existing reps-display from previous superset/circuit/AMRAP
            const instructionsContainer = instructions.parentElement;
            const existingReps = instructionsContainer.querySelector('.reps-display');
            if (existingReps) existingReps.remove();
            
            // Safety check for undefined instructions
            if (exercise.instructions && Array.isArray(exercise.instructions)) {
                exercise.instructions.forEach(inst => {
                    const li = document.createElement('li');
                    li.textContent = inst;
                    instructions.appendChild(li);
                });
            } else {
                // Fallback instructions
                const li = document.createElement('li');
                li.textContent = 'Effectuez l\'exercice correctement en suivant la bonne forme';
                instructions.appendChild(li);
            }

            updateProgress();
            updateTimerDisplay();
            updateExerciseProgressList();
            
            // Show/hide tracking inputs and modify controls based on mode
            const repsTrackingDiv = document.getElementById('repsTrackingInputs');
            const pauseBtn = document.getElementById('pauseBtn');
            
            if (exercise.mode === 'reps' && !exercise.isRest && !exercise.isInfo) {
                // REPS MODE: Show tracking inputs, hide pause button
                if (repsTrackingDiv) {
                    repsTrackingDiv.style.display = 'block';

                    // Init sets tracker for gym mode
                    initSetsTracker(exercise);

                    // Pre-fill with last performance if exists, or intelligent suggestion
                    const lastPerf = exercise.lastPerformance || getLastPerformance(exercise.name);
                    const intelligentReps = calculateIntelligentReps(exercise.name);
                    const repsInput = document.getElementById('quickRepsInput');
                    const weightInput = document.getElementById('quickWeightInput');
                    
                    if (repsInput) repsInput.value = '';
                    if (weightInput) weightInput.value = '';

                    // Reset completeSetBtn onclick
                    const csBtn = document.getElementById('completeSetBtn');
                    if (csBtn) { csBtn.onclick = completeCurrentSet; csBtn.disabled = false; }


                    
                    if (lastPerf) {
                        // Use last performance
                        if (repsInput) repsInput.placeholder = lastPerf.reps;
                        if (weightInput && lastPerf.weight) {
                            // Convert kg to lbs for placeholder
                            const lbs = Math.round(lastPerf.weight * 2.20462);
                            weightInput.placeholder = lbs;
                        }
                    } else {
                        // Use intelligent suggestion
                        if (repsInput) repsInput.placeholder = intelligentReps.minReps;
                    }
                    
                    // ✅ Render exercise notes
                    renderExerciseNoteDisplay(exercise.name);
                }
                if (pauseBtn) pauseBtn.style.display = 'none'; // Hide pause in reps mode
            } else {
                // TIMER MODE (y compris repos): Hide tracking inputs, show pause button
                if (repsTrackingDiv) repsTrackingDiv.style.display = 'none';
                if (pauseBtn) pauseBtn.style.display = ''; // Show pause in timer mode
            }
            
            // Scroll — centrer sur la zone d\'entraînement (timer + nom exercice)
            requestAnimationFrame(() => {
                const exView = document.getElementById('exerciseView');
                const timerArea = document.querySelector('.timer') || document.getElementById('timerDisplay');
                if (timerArea) {
                    const offset = timerArea.getBoundingClientRect().top + window.pageYOffset - 80;
                    window.scrollTo({ top: Math.max(0, offset), behavior: 'smooth' });
                } else if (exView) {
                    const offset = exView.getBoundingClientRect().top + window.pageYOffset - 20;
                    window.scrollTo({ top: Math.max(0, offset), behavior: 'smooth' });
                }
            });

            // Compte à rebours 3-2-1 seulement pour le 1er exercice ou après un repos
            const prevEx = currentExerciseIndex > 0 ? currentWorkout.exercises[currentExerciseIndex - 1] : null;
            const comingFromRest = !prevEx || prevEx.isRest;
            const isFirstEx = currentExerciseIndex === 0;
            if ((isFirstEx || comingFromRest) && !exercise.isRest && !exercise.isInfo) {
                showCountdown(exercise.name, () => startTimer());
            } else {
                startTimer();
            }
        }

        // ── RACCOURCIS CLAVIER ENTRAÎNEMENT ─────────────────────────
        document.addEventListener('keydown', function(e) {
            if (!currentWorkout) return;
            // Ne pas intercepter si focus sur un input
            if (['INPUT','TEXTAREA','SELECT'].includes(document.activeElement.tagName)) return;
            switch(e.code) {
                case 'Space':
                    e.preventDefault();
                    togglePause();
                    break;
                case 'ArrowRight':
                    e.preventDefault();
                    skipExercise();
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    goToPreviousExercise();
                    break;
                case 'KeyM':
                    toggleMute();
                    break;
                case 'Escape':
                    // Ne pas quitter accidentellement — juste pause
                    if (!isPaused) togglePause();
                    break;
            }
        });

        // ── SWIPE GESTURES ────────────────────────────────────────
        function showCountdown(exerciseName, callback) {
            // Ne pas afficher sur repos
            if (!exerciseName || exerciseName === 'Repos' || exerciseName === 'Récupération') {
                callback(); return;
            }
            const overlay = document.getElementById('countdownOverlay');
            const numEl   = document.getElementById('countdownNumber');
            const nameEl  = document.getElementById('countdownExerciseName');
            if (!overlay || !numEl) { callback(); return; }

            nameEl.textContent = exerciseName;
            overlay.classList.add('active');

            let count = 3;
            numEl.textContent = count;
            // Force re-animation
            numEl.style.animation = 'none';
            numEl.offsetHeight;
            numEl.style.animation = '';

            const tick = setInterval(() => {
                count--;
                if (count <= 0) {
                    clearInterval(tick);
                    overlay.classList.remove('active');
                    callback();
                } else {
                    numEl.textContent = count;
                    numEl.style.animation = 'none';
                    numEl.offsetHeight;
                    numEl.style.animation = 'countPop 0.5s cubic-bezier(0.34,1.56,0.64,1)';
                    speakCountdown(count);
                }
            }, 900);
        }

        function adjustRestTime(delta) {
            if (!currentWorkout) return;
            const ex = currentWorkout.exercises[currentExerciseIndex];
            if (!ex || !ex.isRest) return; // Seulement pendant un repos
            timeRemaining = Math.max(3, timeRemaining + delta);
            updateTimerDisplay();
            showToast(delta > 0 ? `+${delta}s ajoutés` : `${delta}s retirés`, 'info', 1000);
        }

        // ── OVERLAY REPOS — fonctions ────────────────────────────────────
        function hideRestOverlay() {
            clearInterval(window._restOverlayInterval);
            const ov = document.getElementById('restOverlay');
            if (ov) ov.classList.remove('active');
            // Reset active rest panel
            _activeRestVisible = false;
            const panel = document.getElementById('restActiveExercise');
            const btn   = document.getElementById('restActiveBtn');
            if (panel) panel.style.display = 'none';
            if (btn) { btn.textContent = '🧘 Repos actif — voir un étirement'; btn.style.background='rgba(99,102,241,0.12)'; btn.style.borderColor='rgba(99,102,241,0.25)'; btn.style.color='rgba(165,180,252,0.85)'; }
        }
        function skipRestOverlay() {
            hideRestOverlay();
            skipExercise();
        }
        function adjustRestOverlay(delta) {
            adjustRestTime(delta);
            const restCount = $el('restCountDisplay');
            if (restCount && timeRemaining > 0) restCount.textContent = Math.ceil(timeRemaining);
            // Recalcule l'anneau SVG
            const restArc = document.getElementById('restRingArc');
            if (restArc && window._restTotalDuration) {
                window._restTotalDuration = Math.max(window._restTotalDuration, timeRemaining);
                const pct = Math.min(1, timeRemaining / window._restTotalDuration);
                restArc.style.strokeDashoffset = ((1 - pct) * 553).toFixed(1);
            }
        }

        // ── WAKE LOCK ─────────────────────────────────────────────
        let wakeLock = null;
        async function requestWakeLock() {
            try {
                if ('wakeLock' in navigator) {
                    wakeLock = await navigator.wakeLock.request('screen');
                    wakeLock.addEventListener('release', () => { wakeLock = null; });
                }
            } catch(e) { }
        }
        function releaseWakeLock() {
            if (wakeLock) { wakeLock.release(); wakeLock = null; }
        }
        // Réactiver si on revient sur la page
        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'visible' && currentWorkout && !currentWorkout._completed) {
                requestWakeLock();
            }
        });

        function startTimer() {
            const exercise = currentWorkout.exercises[currentExerciseIndex];
            
            // Don't start countdown timer if in REPS mode
            if (exercise && exercise.mode === 'reps') {
                return; // Just display reps, no countdown
            }
            
            if (timerInterval) clearInterval(timerInterval);
            
            timerInterval = setInterval(() => {
                if (!isPaused) {
                    timeRemaining--;
                    updateTimerDisplay();
                    
                    // Play beep sound for last 5 seconds
                    if (timeRemaining <= 5 && timeRemaining > 0) {
                        playBeep();
                        vibrate(50); // Vibration légère countdown
                        speakCountdown(timeRemaining); // Voice countdown
                        // Add visual warning
                        const timerDisplay = document.getElementById('timerDisplay');
                        timerDisplay.classList.add('timer-countdown-warning');
                    } else {
                        const timerDisplay = document.getElementById('timerDisplay');
                        timerDisplay.classList.remove('timer-countdown-warning');
                    }
                    
                    if (timeRemaining <= 0) {
                        clearInterval(timerInterval);
                        vibrate(200);
                        playSound();
                        speak("Exercice terminé");
                        
                        // Auto-advance to next exercise (no feedback modal)
                        // 🎮 Gain XP RPG pour mode timer — capturer l'index AVANT incrément
                        if (rpgEnabled()) {
                            try {
                                const _timerEx = currentWorkout?.exercises?.[currentExerciseIndex];
                                if (_timerEx && !_timerEx.isRest && !_timerEx.isInfo) {
                                    rpgGainXP(_timerEx._baseName || _timerEx.name, 0, 0, _timerEx.duration || 0);
                                }
                            } catch(e) {}
                        }
                        currentExerciseIndex++;
                        setTimeout(() => startExercise(), 1000);
                    }
                }
            }, 1000);
        }

        function updateTimerDisplay() {
            const exercise = currentWorkout.exercises[currentExerciseIndex];
            const timerDisplay = document.getElementById('timerDisplay');
            
            // Repos et mode timer → afficher le compte à rebours normal (jamais intercepter)
            if (!exercise || exercise.isRest || exercise.mode === 'timer' || !exercise.mode) {
                // Sync overlay repos si actif
                if (exercise && exercise.isRest) {
                    const rc = $el('restCountDisplay');
                    if (rc) rc.textContent = Math.max(0, timeRemaining);
                    const restArc = document.getElementById('restRingArc');
                    if (restArc && window._restTotalDuration) {
                        const pct = Math.min(1, timeRemaining / window._restTotalDuration);
                        restArc.style.strokeDashoffset = ((1 - pct) * 553).toFixed(1);
                        restArc.style.stroke = timeRemaining <= 5 ? '#ef4444' : '#22c55e';
                    }
                    if (rc) rc.style.color = timeRemaining <= 5 ? '#ef4444' : 'white';
                }
                // Normal timer display
                timerDisplay.classList.remove('timer-countdown-warning');
                timerDisplay.style.fontSize = '';
                timerDisplay.innerHTML = '';
                const minutes = Math.floor(timeRemaining / 60);
                const seconds = timeRemaining % 60;
                timerDisplay.textContent =
                    `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
                return;
            }
            
            // REPS mode uniquement — afficher les reps suggérées
            if (exercise.mode === 'reps') {
                timerDisplay.classList.remove('timer-countdown-warning');
                const lastPerf = exercise.lastPerformance || getLastPerformance(exercise.name);
                const intelligentReps = calculateIntelligentReps(exercise.name);
                
                if (lastPerf) {
                    timerDisplay.textContent = `${lastPerf.reps} reps`;
                    if (lastPerf.weight) {
                        const lbs = Math.round(lastPerf.weight * 2.20462);
                        timerDisplay.textContent += ` × ${lbs} lbs`;
                    }
                    timerDisplay.style.fontSize = '2.5em';
                    timerDisplay.innerHTML = timerDisplay.textContent;
                } else {
                    timerDisplay.innerHTML = `<div style="font-size: 1em;">${intelligentReps.suggestion}</div>`;
                    timerDisplay.style.fontSize = '2.5em';
                }
                return;
            }
        }

        function updateProgress() {
            const allEx = currentWorkout.exercises;
            const realTotal = allEx.filter(ex => !ex.isRest && !ex.isInfo).length || 1;
            let realDone = 0;
            for (let i = 0; i < currentExerciseIndex && i < allEx.length; i++) {
                if (!allEx[i].isRest && !allEx[i].isInfo) realDone++;
            }
            const progress = (realDone / realTotal) * 100;
            document.getElementById('progressFill').style.width = `${progress}%`;
        }

        function toggleWeightUnit() {
            useKg = !useKg;
            localStorage.setItem('fitproUseKg', useKg);
            updateWeightUnitLabels();
            showToast(useKg ? '⚖️ Unité : kilogrammes (kg)' : '⚖️ Unité : livres (lbs)', 'info', 2000);
        }

        function showBusyGymModal() {
            const profileEquip = getLocationProfiles().find(p=>p.id===activeLocationId)?.equipment || selectedEquipment;
            const overlay = document.createElement('div');
            overlay.id = 'busyGymOverlay';
            overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:10300;display:flex;align-items:flex-end;justify-content:center;';

            // Initialiser busyGymEquipment depuis le profil si pas encore défini
            if (busyGymEquipment.length === 0) {
                busyGymEquipment = [...profileEquip];
            }
            if (busyGymMachines.length === 0) {
                busyGymMachines = [...selectedMachines];
            }

            const categories = [
                { label: '🏋️ Poids libres', ids: ['barbell','dumbbells','kettlebell','medicineball'] },
                { label: '🤸 Cardio', ids: ['treadmill','bike','elliptical','stairmaster','rower','jumprope','battleropes'] },
                { label: '📦 Accessoires', ids: ['bench','trx','parallelbars','abwheel','swissball','resistance'] },
                { label: '🧍 Corps', ids: ['bodyweight'] },
            ];

            const equipGrid = categories.map(cat => {
                const items = availableEquipment.filter(eq => cat.ids.includes(eq.id));
                if (items.length === 0) return '';
                const btns = items.map(eq => {
                    const sel = busyGymEquipment.includes(eq.id);
                    return `<button data-eqid="${eq.id}" onclick="toggleBusyEquip('${eq.id}',this)"
                        style="padding:8px 6px;border-radius:12px;border:2px solid ${sel?'#16a34a':'#e5e7eb'};
                        background:${sel?'linear-gradient(135deg,#16a34a,#15803d)':'white'};
                        cursor:pointer;text-align:center;font-size:0.72em;font-weight:700;color:${sel?'white':'#374151'};min-height:60px;">
                        <div style="width:34px;height:34px;margin:0 auto 3px;display:flex;align-items:center;justify-content:center;">${eq.svgIcon||'<span style="font-size:1.3em">'+eq.name[0]+'</span>'}</div>
                        <div style="line-height:1.2;">${eq.name}</div>
                    </button>`;
                }).join('');
                return `<div style="margin-bottom:14px;">
                    <div style="font-size:0.7em;font-weight:800;color:#6b7280;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">${cat.label}</div>
                    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;">${btns}</div>
                </div>`;
            }).join('');

            // Section machines détaillée
            const machineGrid = machineTypes.map(mt => {
                const sel = busyGymMachines.includes(mt.id);
                return `<button data-mtid="${mt.id}" onclick="toggleBusyMachine('${mt.id}',this)"
                    style="padding:8px 6px;border-radius:12px;border:2px solid ${sel?'#16a34a':'#e5e7eb'};
                    background:${sel?'linear-gradient(135deg,#16a34a,#15803d)':'white'};
                    cursor:pointer;text-align:center;font-size:0.72em;font-weight:700;color:${sel?'white':'#374151'};min-height:60px;">
                    <div style="width:34px;height:34px;margin:0 auto 3px;display:flex;align-items:center;justify-content:center;">${mt.svg?'<div style="width:34px;height:34px;filter:'+( sel?'brightness(10)':'none')+'">' + mt.svg + '</div>':mt.icon}</div>
                    <div style="line-height:1.2;">${mt.name.replace('Machines ','')}</div>
                </button>`;
            }).join('');

            overlay.innerHTML = `<div style="background:white;border-radius:22px 22px 0 0;padding:20px 16px;width:100%;max-width:480px;max-height:88vh;overflow-y:auto;">
                <div style="width:40px;height:4px;background:#e5e7eb;border-radius:99px;margin:0 auto 14px;"></div>
                <h3 style="margin:0 0 4px;color:#0F1014;">🏃 Salle bondée</h3>
                <p style="margin:0 0 14px;font-size:0.82em;color:#6b7280;">Coche les équipements <strong>disponibles maintenant</strong> — décoche ce qui est occupé.</p>

                <div style="margin-bottom:14px;">
                    <div style="font-size:0.7em;font-weight:800;color:#6b7280;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">🔧 Machines & Câbles</div>
                    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-bottom:8px;" id="busyMachineGrid">${machineGrid}</div>
                    <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:6px;">
                        <button onclick="selectAllBusyMachines(true)" style="padding:6px;border:1px solid #16a34a;border-radius:8px;background:#FFF3E0;color:#16a34a;font-size:0.75em;font-weight:700;cursor:pointer;">✓ Tout cocher</button>
                        <button onclick="selectAllBusyMachines(false)" style="padding:6px;border:1px solid #e5e7eb;border-radius:8px;background:#f9fafb;color:#6b7280;font-size:0.75em;font-weight:700;cursor:pointer;">✗ Tout décocher</button>
                    </div>
                </div>

                ${equipGrid}

                <button onclick="confirmBusyGym()" class="btn" style="width:100%;margin-bottom:8px;margin-top:4px;">✅ Générer avec cet équipement</button>
                <button onclick="document.getElementById('busyGymOverlay').remove()" class="btn btn-secondary" style="width:100%;">Annuler</button>
            </div>`;
            document.body.appendChild(overlay);
        }

        function toggleBusyMachine(id, btn) {
            const idx = busyGymMachines.indexOf(id);
            if (idx >= 0) {
                busyGymMachines.splice(idx, 1);
                btn.style.background = 'white'; btn.style.borderColor = '#e5e7eb'; btn.style.color = '#374151';
                const svgDiv = btn.querySelector('div > div');
                if (svgDiv) svgDiv.style.filter = 'none';
            } else {
                busyGymMachines.push(id);
                btn.style.background = 'linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor = '#16a34a'; btn.style.color = 'white';
                const svgDiv = btn.querySelector('div > div');
                if (svgDiv) svgDiv.style.filter = 'brightness(10)';
            }
        }

        function selectAllBusyMachines(select) {
            busyGymMachines = select ? machineTypes.map(m => m.id) : [];
            const grid = document.getElementById('busyMachineGrid');
            if (!grid) return;
            grid.querySelectorAll('button').forEach(btn => {
                if (select) {
                    btn.style.background = 'linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor = '#16a34a'; btn.style.color = 'white';
                    const svgDiv = btn.querySelector('div > div');
                    if (svgDiv) svgDiv.style.filter = 'brightness(10)';
                } else {
                    btn.style.background = 'white'; btn.style.borderColor = '#e5e7eb'; btn.style.color = '#374151';
                    const svgDiv = btn.querySelector('div > div');
                    if (svgDiv) svgDiv.style.filter = 'none';
                }
            });
        }
        function toggleBusyEquip(id, btn) {
            const idx = busyGymEquipment.indexOf(id);
            if (idx >= 0) {
                busyGymEquipment.splice(idx,1);
                btn.style.background = 'white'; btn.style.borderColor = '#e5e7eb'; btn.style.color = '#374151';
            } else {
                busyGymEquipment.push(id);
                btn.style.background = 'linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor = '#16a34a'; btn.style.color = 'white';
            }
        }
        function confirmBusyGym() {
            document.getElementById('busyGymOverlay').remove();
            if (busyGymEquipment.length === 0 && busyGymMachines.length === 0) { showToast('Sélectionne au moins un équipement', 'warning'); return; }
            busyGymMode = true;
            // Appliquer la sélection machines
            selectedMachines = [...busyGymMachines];
            const banner = document.getElementById('busyGymBanner');
            const activBtn = document.getElementById('activateBusyGymBtn');
            const totalCount = busyGymEquipment.length + busyGymMachines.length;
            if (banner) { banner.style.display = 'block'; document.getElementById('busyGymEquipCount').textContent = totalCount + ' équipement(s) disponibles'; }
            if (activBtn) activBtn.style.display = 'none';
            // Lancer directement la génération de séance avec les équipements disponibles
            showToast(`🏃 Salle bondée — génération en cours…`, 'info', 1500);
            setTimeout(() => startRandomWorkout(), 400);
        }
        function deactivateBusyGym() {
            busyGymMode = false; busyGymEquipment = []; busyGymMachines = [];
            // Rétablir la sélection machines du profil
            selectedMachines = [...(getLocationProfiles().find(p=>p.id===activeLocationId)?.machines || machineTypes.map(m=>m.id))];
            const banner = document.getElementById('busyGymBanner');
            const activBtn = document.getElementById('activateBusyGymBtn');
            if (banner) banner.style.display = 'none';
            if (activBtn && sessionMode === 'gym') activBtn.style.display = 'block';
            showToast('Mode salle bondée désactivé', 'info', 1500);
        }

        function renderLocationBtns() {
            const row = document.getElementById('locationBtnsRow');
            if (!row) return;
            const profiles = getLocationProfiles();
            row.innerHTML = profiles.map(loc => `
                <div style="flex-shrink:0;position:relative;text-align:center;">
                    <button data-location-id="${loc.id}" onclick="switchLocation('${loc.id}')"
                        style="padding:10px 14px;border-radius:14px;border:2px solid var(--border-color,#e5e7eb);
                               background:var(--card-bg,white);cursor:pointer;text-align:center;transition:all 0.2s;
                               min-width:90px;box-shadow:0 2px 6px rgba(0,0,0,0.06);width:100%;">
                        <div style="font-size:1.5em;margin-bottom:3px;">${loc.icon}</div>
                        <div data-loc-text="name" style="font-size:0.8em;font-weight:700;color:var(--text-primary,#0F1014);">${loc.name}</div>
                    </button>
                    <button onclick="showAddLocationModal('${loc.id}')"
                        style="position:absolute;top:-6px;right:-6px;width:20px;height:20px;border-radius:50%;
                               background:#16a34a;border:none;color:white;font-size:0.6em;cursor:pointer;
                               display:flex;align-items:center;justify-content:center;line-height:1;padding:0;
                               box-shadow:0 2px 6px rgba(22,163,74,0.4);">✏️</button>
                </div>`).join('') +
                `<button onclick="showAddLocationModal()"
                    style="flex-shrink:0;padding:10px 14px;border-radius:14px;border:2px dashed #d1d5db;
                           background:#f9fafb;cursor:pointer;min-width:60px;color:#9ca3af;font-size:1.3em;">+</button>`;
            _updateLocationBtns();
        }

        function showAddLocationModal(editId) {
            const editing = editId ? getLocationProfiles().find(p=>p.id===editId) : null;
            const overlay = document.createElement('div');
            overlay.id = 'addLocationOverlay';
            overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:10200;display:flex;align-items:flex-end;justify-content:center;';

            const currentEquip    = editing ? (editing.equipment || []) : [];
            const isHomeMode      = editing ? editing.mode === 'home' : false;
            const currentMachines = editing
                ? (editing.machines != null ? editing.machines : (isHomeMode ? [] : machineTypes.map(m=>m.id)))
                : machineTypes.map(m=>m.id);
            const currentMode     = editing ? editing.mode : 'gym';

            const icons = ['🏠','🏋️','🏢','🏨','🏫','🌳','🚪','⭐','🏃','💪','🔥','🎯'];
            const iconPicker = icons.map(ic =>
                `<button onclick="document.getElementById('locIconSel').textContent='${ic}';document.querySelectorAll('#locIconPicker button').forEach(b=>{b.style.background='#f9fafb';b.style.borderColor='#e5e7eb';});this.style.background='#FFF3E0';this.style.borderColor='#16a34a';"
                    style="padding:8px;border:2px solid ${editing?.icon===ic?'#16a34a':'#e5e7eb'};border-radius:10px;background:${editing?.icon===ic?'#FFF3E0':'#f9fafb'};font-size:1.4em;cursor:pointer;">${ic}</button>`
            ).join('');

            // Grille équipements généraux
            const equipCats = [
                { label:'🏋️ Poids libres', ids:['barbell','dumbbells','kettlebell','medicineball'] },
                { label:'🤸 Cardio', ids:['treadmill','bike','elliptical','stairmaster','rower','jumprope','battleropes'] },
                { label:'📦 Accessoires', ids:['bench','trx','parallelbars','abwheel','swissball','resistance'] },
                { label:'🧍 Corps', ids:['bodyweight'] },
            ];

            const equipGrid = equipCats.map(cat => {
                const items = availableEquipment.filter(eq => cat.ids.includes(eq.id));
                const btns = items.map(eq => {
                    const sel = currentEquip.includes(eq.id);
                    return `<button data-eqid="${eq.id}" onclick="toggleLocEquip('${eq.id}',this)"
                        style="padding:7px 5px;border-radius:10px;border:2px solid ${sel?'#16a34a':'#e5e7eb'};
                        background:${sel?'linear-gradient(135deg,#16a34a,#15803d)':'white'};
                        cursor:pointer;text-align:center;font-size:0.7em;font-weight:700;color:${sel?'white':'#374151'};min-height:56px;">
                        <div style="width:30px;height:30px;margin:0 auto 3px;display:flex;align-items:center;justify-content:center;">${eq.svgIcon||'<span style="font-size:1.2em">'+eq.name[0]+'</span>'}</div>
                        <div style="line-height:1.2;">${eq.name}</div>
                    </button>`;
                }).join('');
                return `<div style="margin-bottom:10px;">
                    <div style="font-size:0.68em;font-weight:800;color:#6b7280;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">${cat.label}</div>
                    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:5px;">${btns}</div>
                </div>`;
            }).join('');

            // Grille machines détaillée (machineTypes)
            const machineGrid = machineTypes.map(mt => {
                const sel = currentMachines.includes(mt.id);
                return `<button data-mtid="${mt.id}" onclick="toggleLocMachine('${mt.id}',this)"
                    style="padding:8px 5px;border-radius:10px;border:2px solid ${sel?'#16a34a':'#e5e7eb'};
                    background:${sel?'linear-gradient(135deg,#16a34a,#15803d)':'#f9fafb'};
                    cursor:pointer;text-align:center;font-size:0.7em;font-weight:700;color:${sel?'white':'#374151'};min-height:60px;">
                    <div style="width:34px;height:34px;margin:0 auto 3px;display:flex;align-items:center;justify-content:center;">
                        ${mt.svg ? '<div style="width:34px;height:34px;'+(sel?'filter:brightness(10)':'')+'">' + mt.svg + '</div>' : mt.icon}
                    </div>
                    <div style="line-height:1.2;">${mt.name.replace('Machines ','')}</div>
                </button>`;
            }).join('');

            overlay.innerHTML = `
            <div style="background:white;border-radius:22px 22px 0 0;padding:20px 16px;width:100%;max-width:480px;max-height:92vh;overflow-y:auto;">
                <div style="width:40px;height:4px;background:#e5e7eb;border-radius:99px;margin:0 auto 14px;"></div>
                <h3 style="margin:0 0 14px;color:#0F1014;">${editing ? '✏️ Modifier le lieu' : '📍 Nouveau lieu'}</h3>

                <!-- Icône + Nom -->
                <div style="display:flex;gap:10px;margin-bottom:12px;align-items:center;">
                    <div id="locIconSel" style="padding:10px;border:2px solid #e5e7eb;border-radius:10px;font-size:1.5em;min-width:48px;text-align:center;">${editing?.icon||'🏋️'}</div>
                    <input id="locNameInput" type="text" placeholder="Ex: Gym Énergie, Bureau, Maison…" maxlength="30" value="${editing?.name||''}"
                        style="flex:1;padding:10px 12px;border:2px solid #e5e7eb;border-radius:10px;font-size:0.95em;">
                </div>
                <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px;margin-bottom:14px;" id="locIconPicker">${iconPicker}</div>

                <!-- Mode -->
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:16px;">
                    <button id="locModeHome"
                        onclick="document.getElementById('locModeGym').style.cssText='padding:10px;border:2px solid #e5e7eb;border-radius:12px;background:#f9fafb;color:#374151;cursor:pointer;font-weight:700;';this.style.cssText='padding:10px;border:2px solid #16a34a;border-radius:12px;background:linear-gradient(135deg,#16a34a,#15803d);color:white;cursor:pointer;font-weight:700;';"
                        style="padding:10px;border:2px solid ${currentMode==='home'?'#16a34a':'#e5e7eb'};border-radius:12px;background:${currentMode==='home'?'linear-gradient(135deg,#16a34a,#15803d)':'#f9fafb'};color:${currentMode==='home'?'white':'#374151'};cursor:pointer;font-weight:700;">🏠 Maison</button>
                    <button id="locModeGym"
                        onclick="document.getElementById('locModeHome').style.cssText='padding:10px;border:2px solid #e5e7eb;border-radius:12px;background:#f9fafb;color:#374151;cursor:pointer;font-weight:700;';this.style.cssText='padding:10px;border:2px solid #16a34a;border-radius:12px;background:linear-gradient(135deg,#16a34a,#15803d);color:white;cursor:pointer;font-weight:700;';"
                        style="padding:10px;border:2px solid ${currentMode==='gym'?'#16a34a':'#e5e7eb'};border-radius:12px;background:${currentMode==='gym'?'linear-gradient(135deg,#16a34a,#15803d)':'#f9fafb'};color:${currentMode==='gym'?'white':'#374151'};cursor:pointer;font-weight:700;">🏋️ Gym</button>
                </div>

                <!-- Machines (section principale) -->
                <div style="font-size:0.78em;font-weight:700;color:#0F1014;margin-bottom:6px;">🔧 Machines disponibles</div>
                <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:5px;margin-bottom:8px;" id="locMachineGrid">${machineGrid}</div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:14px;">
                    <button onclick="selectAllLocMachines(true)" style="padding:6px;border:1px solid #16a34a;border-radius:8px;background:#FFF3E0;color:#16a34a;font-size:0.75em;font-weight:700;cursor:pointer;">✓ Toutes les machines</button>
                    <button onclick="selectAllLocMachines(false)" style="padding:6px;border:1px solid #e5e7eb;border-radius:8px;background:#f9fafb;color:#6b7280;font-size:0.75em;font-weight:700;cursor:pointer;">✗ Aucune machine</button>
                </div>

                <!-- Équipements généraux -->
                <div style="font-size:0.78em;font-weight:700;color:#0F1014;margin-bottom:8px;">⚙️ Autres équipements</div>
                <div id="locEquipGrid">${equipGrid}</div>

                <button onclick="confirmAddLocation('${editId||''}')" class="btn" style="width:100%;margin-top:12px;margin-bottom:8px;">✅ ${editing ? 'Enregistrer' : 'Créer ce lieu'}</button>
                <button onclick="document.getElementById('addLocationOverlay').remove()" class="btn btn-secondary" style="width:100%;">Annuler</button>
            </div>`;
            document.body.appendChild(overlay);
        }

        window._locEquip = [];
        function toggleLocEquip(id, btn) {
            if (!window._locEquip) window._locEquip = [];
            const idx = window._locEquip.indexOf(id);
            if (idx >= 0) {
                window._locEquip.splice(idx,1);
                btn.style.background='white'; btn.style.borderColor='#e5e7eb'; btn.style.color='#374151';
            } else {
                window._locEquip.push(id);
                btn.style.background='linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor='#16a34a'; btn.style.color='white';
            }
        }

        function toggleLocMachine(id, btn) {
            if (btn.style.background.includes('667eea') || btn.style.background.includes('linear-gradient')) {
                btn.style.background='#f9fafb'; btn.style.borderColor='#e5e7eb'; btn.style.color='#374151';
                const d = btn.querySelector('div > div'); if (d) d.style.filter='';
            } else {
                btn.style.background='linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor='#16a34a'; btn.style.color='white';
                const d = btn.querySelector('div > div'); if (d) d.style.filter='brightness(10)';
            }
        }

        function selectAllLocMachines(sel) {
            document.querySelectorAll('#locMachineGrid button[data-mtid]').forEach(btn => {
                if (sel) {
                    btn.style.background='linear-gradient(135deg,#16a34a,#15803d)'; btn.style.borderColor='#16a34a'; btn.style.color='white';
                    const d = btn.querySelector('div > div'); if (d) d.style.filter='brightness(10)';
                } else {
                    btn.style.background='#f9fafb'; btn.style.borderColor='#e5e7eb'; btn.style.color='#374151';
                    const d = btn.querySelector('div > div'); if (d) d.style.filter='';
                }
            });
        }

        function confirmAddLocation(editId) {
            const icon = document.getElementById('locIconSel')?.textContent?.trim() || '📍';
            const name = document.getElementById('locNameInput')?.value?.trim();
            if (!name) { showToast('Entrez un nom pour ce lieu', 'warning', 2000); return; }
            const modeBtn = document.getElementById('locModeGym');
            const mode = modeBtn?.style.background?.includes('667eea') ? 'gym' : 'home';

            // Équipements généraux sélectionnés
            const equip = [];
            let equipGridRendered = document.querySelectorAll('#locEquipGrid button[data-eqid]').length > 0;
            document.querySelectorAll('#locEquipGrid button[data-eqid]').forEach(btn => {
                if (btn.style.background.includes('667eea') || btn.style.background.includes('linear-gradient')) {
                    equip.push(btn.dataset.eqid);
                }
            });
            // Toujours respecter la sélection — au minimum bodyweight pour ne pas bloquer
            const finalEquip = equipGridRendered
                ? (equip.length > 0 ? equip : ['bodyweight'])
                : (editId ? (getLocationProfiles().find(p=>p.id===editId)?.equipment || ['bodyweight']) : ['bodyweight']);

            // Machines sélectionnées — on lit l'état des boutons directement
            // Note: machines vide ([]) est un état valide (ex: lieu Maison sans machines)
            const machines = [];
            let machineGridRendered = document.querySelectorAll('#locMachineGrid button[data-mtid]').length > 0;
            document.querySelectorAll('#locMachineGrid button[data-mtid]').forEach(btn => {
                if (btn.style.background.includes('667eea') || btn.style.background.includes('linear-gradient')) {
                    machines.push(btn.dataset.mtid);
                }
            });
            // Si la grille n'était pas rendue (modal non ouvert), garder les machines existantes
            const finalMachines = machineGridRendered
                ? machines   // respecter la sélection de l'utilisateur, même vide
                : (editId ? (getLocationProfiles().find(p=>p.id===editId)?.machines || []) : machineTypes.map(m=>m.id));

            const profiles = getLocationProfiles();
            if (editId) {
                const idx = profiles.findIndex(p=>p.id===editId);
                if (idx>=0) { profiles[idx] = {...profiles[idx], name, icon, mode, equipment: finalEquip, machines: finalMachines}; }
            } else {
                profiles.push({ id: 'loc_'+Date.now(), name, icon, mode, equipment: finalEquip, machines: finalMachines });
            }
            saveLocationProfiles(profiles);
            document.getElementById('addLocationOverlay').remove();
            renderLocationBtns();
            // Si on modifie le lieu actif, appliquer les nouveaux réglages immédiatement
            if (!editId || editId === activeLocationId) {
                selectedEquipment = [...finalEquip];
                localStorage.setItem('selectedEquipment', JSON.stringify(selectedEquipment));
                selectedMachines = [...finalMachines];
                saveEquipment();
                setSessionMode(mode);
            }
            showToast(`📍 ${icon} ${name} ${editId?'modifié':'créé'} !`, 'success', 2000);
        }

        function showManageLocationsModal() {
            const profiles = getLocationProfiles();
            const overlay = document.createElement('div');
            overlay.id = 'manageLocOverlay';
            overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:10200;display:flex;align-items:flex-end;justify-content:center;padding:0;';
            overlay.innerHTML = `
                <div style="background:white;border-radius:22px 22px 0 0;padding:24px 20px;width:100%;max-width:480px;max-height:80vh;overflow-y:auto;box-shadow:0 -8px 40px rgba(0,0,0,0.2);">
                    <div style="width:40px;height:4px;background:#e5e7eb;border-radius:99px;margin:0 auto 18px;"></div>
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
                        <h3 style="margin:0;color:#0F1014;">📍 Mes lieux</h3>
                        <button onclick="showAddLocationModal()" style="background:linear-gradient(135deg,#16a34a,#15803d);color:white;border:none;border-radius:10px;padding:7px 14px;font-size:0.85em;font-weight:700;cursor:pointer;">+ Ajouter</button>
                    </div>
                    ${profiles.map(loc => `
                    <div style="display:flex;align-items:center;gap:12px;padding:12px;border:2px solid ${loc.id===activeLocationId?'#16a34a':'#e5e7eb'};border-radius:14px;margin-bottom:8px;background:${loc.id===activeLocationId?'#FFF3E0':'white'};">
                        <div style="font-size:1.8em;">${loc.icon}</div>
                        <div style="flex:1;">
                            <div style="font-weight:700;color:#0F1014;">${loc.name}</div>
                            <div style="font-size:0.78em;color:#6b7280;">${loc.mode==='gym'?'🏋️ Gym':'🏠 Maison'} · ${loc.equipment.length} équipements</div>
                        </div>
                        <div style="display:flex;gap:6px;">
                            <button onclick="switchLocation('${loc.id}');document.getElementById('manageLocOverlay').remove();" style="background:#10b981;color:white;border:none;border-radius:8px;padding:6px 12px;font-size:0.82em;cursor:pointer;">${loc.id===activeLocationId?'✅ Actif':'Activer'}</button>
                            <button onclick="document.getElementById('manageLocOverlay').remove();showAddLocationModal('${loc.id}');" style="background:#FFF3E0;color:#16a34a;border:none;border-radius:8px;padding:6px 10px;font-size:0.82em;cursor:pointer;">✏️</button>
                            ${profiles.length > 1 ? `<button onclick="deleteLocation('${loc.id}')" style="background:#fee2e2;color:#ef4444;border:none;border-radius:8px;padding:6px 10px;font-size:0.82em;cursor:pointer;">🗑️</button>` : ''}
                        </div>
                    </div>`).join('')}
                    <button onclick="document.getElementById('manageLocOverlay').remove()" class="btn btn-secondary" style="width:100%;margin-top:8px;">Fermer</button>
                </div>`;
            document.body.appendChild(overlay);
        }

        function deleteLocation(locationId) {
            const profiles = getLocationProfiles().filter(p => p.id !== locationId);
            saveLocationProfiles(profiles);
            if (activeLocationId === locationId) switchLocation(profiles[0].id);
            document.getElementById('manageLocOverlay')?.remove();
            renderLocationBtns();
            showManageLocationsModal();
        }

        function setSessionMode(mode) {
            sessionMode = mode;
            localStorage.setItem('fitproSessionMode', mode);
            const home = document.getElementById('modeHomeBtn');
            const gym  = document.getElementById('modeGymBtn');
            const gymSection = document.getElementById('gymProgramsSection');
            const active   = 'linear-gradient(135deg,#16a34a,#15803d)';
            const inactiveStyle = 'background:#f9fafb;border-color:#e5e7eb;';

            [home, gym].forEach(btn => {
                if (!btn) return;
                const isActive = (btn.id === 'modeHomeBtn' && mode === 'home') ||
                                 (btn.id === 'modeGymBtn'  && mode === 'gym');
                btn.style.background   = isActive ? active   : '#f9fafb';
                btn.style.borderColor  = isActive ? '#16a34a' : '#e5e7eb';
                btn.style.color        = isActive ? 'white'  : '';
                btn.style.boxShadow    = isActive ? '0 4px 16px rgba(22,163,74,0.35)' : '0 2px 8px rgba(0,0,0,0.06)';
                // Update child text colors
                btn.querySelectorAll('div').forEach((el, i) => {
                    if (i === 1) el.style.color = isActive ? 'white' : '#374151';
                    if (i === 2) el.style.color = isActive ? 'rgba(255,255,255,0.8)' : '#6b7280';
                });
            });

            // Show/hide gym programs + sub-options
            if (gymSection) gymSection.style.display = mode === 'gym' ? 'block' : 'none';
            const gymSub = document.getElementById('gymSubOptions');
            if (gymSub) gymSub.style.display = mode === 'gym' ? 'grid' : 'none';

            // Init gym sub-option buttons state
            if (mode === 'gym') _updateGymSubBtns();

            const busyBtn = document.getElementById('activateBusyGymBtn');
            if (busyBtn) busyBtn.style.display = mode === 'gym' ? 'block' : 'none';
            if (mode !== 'gym') deactivateBusyGym();
            if (mode === 'gym') {
                showToast('🏋️ Mode Gym activé', 'success', 1800);
            } else {
                showToast('🏠 Mode Maison activé', 'success', 1800);
            }
        }

