        function startGymProgram(programId) {
            const program = gymPrograms[programId];
            if (!program) return;

            // Pick which day to do (PPL → ask, others → auto)
            const days = Object.values(program);
            if (days.length === 1) {
                buildGymWorkout(days[0]);
            } else {
                // Show day picker
                const opts = Object.entries(program).map(([key, day]) =>
                    `<button class="btn" style="margin-bottom:8px;text-align:left;" onclick="document.getElementById('gymDayModal').remove();buildGymWorkout(gymPrograms['${programId}']['${key}'])">
                        ${day.name}
                    </button>`
                ).join('');

                const modal = document.createElement('div');
                modal.id = 'gymDayModal';
                modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px;';
                modal.innerHTML = `<div style="background:white;border-radius:20px;padding:28px;max-width:400px;width:100%;max-height:80vh;overflow-y:auto;">
                    <h3 style="margin:0 0 18px;color:#16a34a;">🏋️ Choisir le jour</h3>
                    ${opts}
                    <button class="btn btn-secondary" style="width:100%;margin-top:6px;" onclick="this.closest('#gymDayModal').remove()">Annuler</button>
                </div>`;
                document.body.appendChild(modal);
            }
        }

        function buildGymWorkout(day) {
            const setsPerEx  = 3;
            const restSeconds = globalRestSeconds || 90;
            const exercises  = [];

            day.exercises.forEach(exName => {
                const dbEx = exerciseDatabase.find(e => e.name === exName);
                if (!dbEx) return;

                // Mode salle bondée : vérifier si l'exercice est faisable avec les équipements disponibles
                if (busyGymMode && busyGymEquipment.length > 0) {
                    const hasAvail = (dbEx.equipment||[]).some(e => {
                        const eq = availableEquipment.find(ae => ae.dbName === e);
                        return eq && busyGymEquipment.includes(eq.id);
                    });
                    if (!hasAvail) return; // skip cet exercice si équipement pas disponible
                }

                // Un seul exercice avec sets:3 — le tracker interne gère Série 1/3 → 2/3 → 3/3
                exercises.push({
                    ...dbEx,
                    _baseName: exName,
                    mode: 'reps',
                    sets: setsPerEx,
                    plannedSets: setsPerEx,
                    duration: 60
                });

                // Repos entre exercices (le repos inter-séries est géré par startSetRest)
                exercises.push({
                    name: 'Repos',
                    duration: restSeconds,
                    isRest: true,
                    mode: 'timer'
                });
            });

            // Retirer le dernier repos inutile
            if (exercises.length > 0 && exercises[exercises.length - 1].isRest) {
                exercises.pop();
            }

            // Si salle bondée a filtré tous les exercices, prévenir
            if (exercises.length === 0) {
                showToast('Aucun exercice disponible avec cet équipement. Essaie une séance intelligente.', 'warning', 3000);
                return;
            }

            const workout = {
                name: day.name + (busyGymMode ? ' 🏃' : ''),
                mode: 'reps',
                isGym: true,
                restBetweenSets: restSeconds,
                exercises,
                badgeHTML: '🏋️ Gym',
                badgeStyle: 'linear-gradient(135deg,#166534,#16a34a)'
            };

            showWorkoutPreparation(workout);
        }

        function previewAvailWeights(type, raw) {
            const weights = raw.split(/[\s,;]+/).map(Number).filter(n => n > 0 && n < 1000).sort((a,b)=>a-b);
            const preview = document.getElementById(type + 'Preview');
            if (!preview) return;
            preview.innerHTML = weights.map(w =>
                `<span style="background:#FFF3E0;color:#166534;border-radius:8px;padding:3px 10px;font-size:0.82em;font-weight:700;">${w}</span>`
            ).join('');
        }
        function saveAllAvailableWeights() {
            [['dumbbells','dumbbellWeightsInput'],['barbell','barbellWeightsInput'],['cable','cableWeightsInput']].forEach(([type, id]) => {
                const input = document.getElementById(id);
                if (!input) return;
                const weights = input.value.split(/[\s,;]+/).map(Number).filter(n => n > 0 && n < 1000).sort((a,b)=>a-b);
                if (weights.length > 0) saveAvailableWeights(type, weights);
            });
            showToast(`⚖️ Poids sauvegardés ! Les suggestions s'adaptent maintenant.`, 'success', 3000);
        }
        function loadAvailableWeightsUI() {
            [['dumbbells','dumbbellWeightsInput','dumbbellPreview'],
             ['barbell','barbellWeightsInput','barbellPreview'],
             ['cable','cableWeightsInput','cablePreview']].forEach(([type, inputId, previewId]) => {
                const weights = getAvailableWeights(type);
                const input = document.getElementById(inputId);
                const preview = document.getElementById(previewId);
                if (weights && input) input.value = weights.join(', ');
                if (weights && preview) previewAvailWeights(type, weights.join(', '));
            });
        }

