        function rpgCheckAchievements() {
            if (!rpgEnabled()) return;
            const unlocked = JSON.parse(localStorage.getItem('fitproAchievements')||'[]');
            const stats = loadStats();
            const data = rpgLoad();
            const newUnlocks = [];
            ACHIEVEMENTS.forEach(a => {
                if (unlocked.includes(a.id)) return;
                try { if (a.check(stats, data)) newUnlocks.push(a); } catch(e) {}
            });
            if (newUnlocks.length > 0) {
                const allUnlocked = [...unlocked, ...newUnlocks.map(a=>a.id)];
                localStorage.setItem('fitproAchievements', JSON.stringify(allUnlocked));
                newUnlocks.forEach((a,i) => {
                    setTimeout(() => {
                        showToast(`${a.emoji} Exploit débloqué : ${a.name} !`, 'success', 4000);
                    }, i * 1200);
                });
            }
        }

        // ── HOOK XP avec effets compétences + classe ──────────────────
        function rpgApplyXPMultipliers(baseXP, muscleName, exerciseType) {
            let mult = 1;
            const prestige = rpgGetPrestigeLevel();
            if (prestige > 0) mult += prestige * 0.10;  // +10% par prestige
            const effects = rpgGetActiveEffects();
            if (effects.xpAll) mult += effects.xpAll;
            if (effects.xpCompound && exerciseType === 'compound') mult += effects.xpCompound;
            const cls = rpgGetClass();
            if (cls && cls.bonusMuscles.includes(muscleName)) mult += cls.xpBonus;
            return Math.round(baseXP * mult);
        }

        // ── RANGS E→SSS ──────────────────────────────────────────────
        const RPG_RANKS = [
            { id:'E',   label:'E',   emoji:'⬛', color:'#6b7280', xpMin:0      },
            { id:'D',   label:'D',   emoji:'🟫', color:'#92400e', xpMin:500    },
            { id:'C',   label:'C',   emoji:'🟩', color:'#15803d', xpMin:2000   },
            { id:'B',   label:'B',   emoji:'🟦', color:'#1d4ed8', xpMin:5000   },
            { id:'A',   label:'A',   emoji:'🟪', color:'#166534', xpMin:10000  },
            { id:'S',   label:'S',   emoji:'🟨', color:'#d97706', xpMin:20000  },
            { id:'SS',  label:'SS',  emoji:'🔶', color:'#ea580c', xpMin:40000  },
            { id:'SSS', label:'SSS', emoji:'💠', color:'#be185d', xpMin:80000  },
        ];

        function rpgGetRank(totalXP) {
            let rank = RPG_RANKS[0];
            for (const r of RPG_RANKS) { if (totalXP >= r.xpMin) rank = r; }
            return rank;
        }
        function rpgNextRank(totalXP) {
            for (let i = RPG_RANKS.length - 1; i >= 0; i--) {
                if (totalXP < RPG_RANKS[i].xpMin) continue;
                return RPG_RANKS[i + 1] || null;
            }
            return RPG_RANKS[1];
        }

