        // ── QUÊTES QUOTIDIENNES ───────────────────────────────────────
        function rpgGetDailyQuests() {
            const today = new Date().toDateString();
            const key = 'fitproDailyQuests_' + today;
            try {
                const saved = localStorage.getItem(key);
                if (saved) {
                    const parsed = JSON.parse(saved);
                    // Recalculer le temps restant (pas stocké dans le cache)
                    const endOfDay = new Date(); endOfDay.setHours(23,59,59,0);
                    const msLeft = endOfDay - new Date();
                    const hLeft = Math.floor(msLeft/3600000);
                    const mLeft = Math.floor((msLeft%3600000)/60000);
                    parsed._timeLeft = hLeft + 'h ' + mLeft + 'm restantes';
                    return parsed;
                }
            } catch(e) {}
            // Générer 3 quêtes pour aujourd'hui
            const history = getWorkoutHistory();
            const todayWorkouts = history.filter(w => {
                const d = new Date(w.date || w.timestamp || w.id);
                return d.toDateString() === today;
            });
            const musclesTrainedToday = new Set();
            let setsToday = 0;
            todayWorkouts.forEach(w => {
                setsToday += (w.totalSets || (w.exercises||[]).length);
                (w.exercises||[]).forEach(ex => {
                    const db = exerciseDatabase.find(e=>e.name===(typeof ex==='string'?ex:ex.name));
                    if (db) musclesTrainedToday.add(db.muscle);
                });
            });
            const quests = [
                { id:'dq_workout',  name:'Compléter 1 séance aujourd\'hui', emoji:'🏋️', target:1, progress:Math.min(todayWorkouts.length,1), xpReward:80, done:todayWorkouts.length>=1 },
                { id:'dq_sets',     name:'Faire 15 séries au total',        emoji:'💪', target:15,progress:Math.min(setsToday,15), xpReward:60, done:setsToday>=15 },
                { id:'dq_muscles',  name:'Entraîner 2 muscles différents',  emoji:'🎯', target:2, progress:Math.min(musclesTrainedToday.size,2), xpReward:100, done:musclesTrainedToday.size>=2 },
            ];
            // Calculer temps restant (fin de journée)
            const endOfDay = new Date(); endOfDay.setHours(23,59,59,0);
            const msLeft = endOfDay - new Date();
            const hLeft = Math.floor(msLeft/3600000);
            const mLeft = Math.floor((msLeft%3600000)/60000);
            quests._timeLeft = `${hLeft}h ${mLeft}m restantes`;
            localStorage.setItem(key, JSON.stringify(quests));
            return quests;
        }

        function rpgAwardDailyQuest(questId, xpReward) {
            const today = new Date().toDateString();
            const awardKey = 'fitproDQAwarded_' + today;
            const awarded = JSON.parse(localStorage.getItem(awardKey)||'[]');
            if (awarded.includes(questId)) return;
            awarded.push(questId);
            localStorage.setItem(awardKey, JSON.stringify(awarded));
            // XP sur tous les muscles actifs
            const data = rpgLoad();
            const muscles = Object.keys(data.muscles);
            if (muscles.length > 0) {
                const per = Math.floor(xpReward / muscles.length);
                muscles.forEach(m => { data.muscles[m].xp = (data.muscles[m].xp||0) + per; });
                data.profile.xp = Object.values(data.muscles).reduce((s,m)=>s+m.xp,0);
                rpgSave(data);
            }
            showToast(`⚡ Quête quotidienne : +${xpReward} XP !`, 'success', 3000);
        }

