        function rpgGetDungeonStatus(dungeonId) {
            try {
                const s = localStorage.getItem('fitproDungeon_' + dungeonId);
                if (!s) return { available: true, lastCompleted: null };
                const data = JSON.parse(s);
                const dungeon = RPG_DUNGEONS.find(d=>d.id===dungeonId);
                const daysSince = (new Date() - new Date(data.lastCompleted)) / 86400000;
                return { available: daysSince >= dungeon.cooldownDays, lastCompleted: data.lastCompleted, daysSince };
            } catch(e) { return { available: true, lastCompleted: null }; }
        }

        function rpgCompleteDungeon(dungeonId) {
            const dungeon = RPG_DUNGEONS.find(d=>d.id===dungeonId);
            if (!dungeon) return;
            localStorage.setItem('fitproDungeon_' + dungeonId, JSON.stringify({ lastCompleted: new Date().toISOString() }));
            // XP masif sur tous les muscles
            const data = rpgLoad();
            const baseXP = 300 * dungeon.xpMult;
            const muscles = Object.keys(data.muscles);
            if (muscles.length > 0) {
                const per = Math.floor(baseXP / muscles.length);
                muscles.forEach(m => { data.muscles[m].xp = (data.muscles[m].xp||0) + per; });
                data.profile.xp = Object.values(data.muscles).reduce((s,m)=>s+m.xp,0);
                rpgSave(data);
            }
            launchConfetti();
            showToast(`💠 Donjon complété ! +${baseXP} XP (×${dungeon.xpMult}) !`, 'success', 5000);
            vibrate([200,100,200,100,400]);
        }

        function rpgStartDungeon(dungeonId) {
            const dungeon = RPG_DUNGEONS.find(d=>d.id===dungeonId);
            if (!dungeon) return;
            const status = rpgGetDungeonStatus(dungeonId);
            if (!status.available) {
                const daysLeft = Math.ceil(dungeon.cooldownDays - status.daysSince);
                showToast(`⏳ Donjon disponible dans ${daysLeft} jour(s)`, 'warning', 3000);
                return;
            }
            // Construire une séance avec les exercices du donjon
            const exs = dungeon.exercises.map(name => {
                const db = exerciseDatabase.find(e=>e.name===name);
                return db ? {...db, sets:5, mode:'reps'} : null;
            }).filter(Boolean);
            if (exs.length === 0) { showToast('Exercices non trouvés', 'error'); return; }
            currentWorkout = {
                name: dungeon.emoji + ' ' + dungeon.name,
                exercises: exs,
                mode: 'reps',
                restBetweenSets: 90,
                type: 'dungeon',
                _dungeonId: dungeonId,
                _dungeonXpMult: dungeon.xpMult
            };
            workoutStartTime = Date.now();
            currentExerciseIndex = 0;
            // Aller sur l'onglet Séances et lancer proprement
            switchTab('workouts');
            // S'assurer que tout est caché sauf exerciseView
            const _wsel = document.getElementById('workoutSelection');
            if (_wsel) _wsel.style.display = 'none';
            document.getElementById('completionView')?.classList.add('hidden');
            const ev = document.getElementById('exerciseView');
            ev.classList.remove('hidden');
            window.scrollTo(0,0);
            initProgressList();
            startExercise();
        }

