        // ── Helpers level/XP ────────────────────────────────────────
        function rpgXPForLevel(n) {
            // XP cumulatif pour atteindre le niveau n
            if (n <= 1) return 0;
            let total = 0;
            for (let i = 1; i < n; i++) total += Math.floor(RPG_LEVEL_BASE * Math.pow(i, RPG_LEVEL_EXP));
            return total;
        }
        function rpgXPThisLevel(n) {
            // XP nécessaire pour passer du niveau n au n+1
            return Math.floor(RPG_LEVEL_BASE * Math.pow(n, RPG_LEVEL_EXP));
        }
        function rpgLevelFromXP(xp) {
            let level = 1;
            while (rpgXPForLevel(level + 1) <= xp) level++;
            return level;
        }
        function rpgTitle(level) {
            let t = RPG_TITLES[0];
            for (const entry of RPG_TITLES) { if (level >= entry.min) t = entry; }
            return t;
        }

        // ── Storage ─────────────────────────────────────────────────
        function rpgLoad() {
            try { return JSON.parse(localStorage.getItem('fitproRPG') || 'null') || { muscles:{}, profile:{xp:0, lastActivity: new Date().toISOString()} }; }
            catch(e) { return { muscles:{}, profile:{xp:0, lastActivity: new Date().toISOString()} }; }
        }
        function rpgSave(data) { localStorage.setItem('fitproRPG', JSON.stringify(data)); }
        function rpgEnabled() { return localStorage.getItem('fitproGameMode') === '1'; }

        // ── Calcul XP d'une série ────────────────────────────────────
        function rpgXPForSet(exerciseName, reps, weightKg, isTimer, timerSeconds) {
            const ex = exerciseDatabase.find(e => e.name === exerciseName);
            const diffMult = ex?.difficulty === 'Avancé' ? 1.8 : ex?.difficulty === 'Intermédiaire' ? 1.4 : 1.0;
            // Timer mode : utiliser la durée de l'exercice si timerSeconds est 0
            if (isTimer || (reps === 0 && weightKg === 0)) {
                const secs = timerSeconds || ex?.duration || 30;
                return Math.max(2, Math.floor(secs / 8 * diffMult));
            }
            const vol = (reps || 1) * (1 + (weightKg || 0) / 20);
            return Math.max(1, Math.floor(vol * diffMult));
        }

        // ── Gain XP après une série ─────────────────────────────────
        function rpgGainXP(exerciseName, reps, weightKg, timerDuration) {
            if (!rpgEnabled()) return;
            const ex = exerciseDatabase.find(e => e.name === exerciseName);
            // Si exercice non trouvé (ex. généré par IA), on utilise des valeurs de fallback
            if (ex && (ex.type === 'info' || ex.isRest || ex.isInfo)) return;
            // muscle : fallback 'Corps entier' pour exercices généraux ou non trouvés
            const muscle = (ex && ex.muscle) ? ex.muscle : 'Corps entier';
            const isTimerMode = (reps === 0 && weightKg === 0);

            try {
                const _streak = loadStats()?.streak || 0;
                const _bonus = rpgStreakBonus(_streak);
                const _dur = timerDuration || (ex?.duration) || 0;
                const _baseXP = Math.round(rpgXPForSet(exerciseName, reps, weightKg, isTimerMode, _dur) * _bonus);
                const _exType = (typeof classifyExercise === 'function') ? classifyExercise({name:exerciseName}) : 'isolation';
                const xpGained = rpgApplyXPMultipliers(_baseXP, muscle, _exType);
                const data = rpgLoad();
                if (!data.muscles[muscle]) data.muscles[muscle] = { xp: 0, lastTrained: null };
                const prev = data.muscles[muscle].xp;
                data.muscles[muscle].xp += xpGained;
                data.muscles[muscle].lastTrained = new Date().toISOString();
                if (!data.profile) data.profile = { xp: 0, lastActivity: new Date().toISOString() };
                data.profile.xp = Object.values(data.muscles).reduce((s, m) => s + m.xp, 0);
                data.profile.lastActivity = new Date().toISOString();
                const prevLevel = rpgLevelFromXP(prev);
                const newLevel  = rpgLevelFromXP(data.muscles[muscle].xp);
                if (newLevel > prevLevel) {
                    try {
                        const log = JSON.parse(localStorage.getItem('fitproLevelUpLog') || '[]');
                        log.push({ muscle, level: newLevel, date: new Date().toISOString() });
                        if (log.length > 50) log.splice(0, log.length - 50);
                        localStorage.setItem('fitproLevelUpLog', JSON.stringify(log));
                    } catch(e) {}
                    rpgSave(data);
                    rpgShowLevelUp(muscle, newLevel);
                    rpgCheckMilestones(muscle, newLevel, data);
                } else {
                    rpgSave(data);
                }
                rpgShowXPPop(xpGained, muscle);
            } catch(err) {
                console.error('rpgGainXP error:', err);
            }
        }

        // ── Decay journalier ─────────────────────────────────────────
        function rpgApplyDecay() {
            if (!rpgEnabled()) return;
            const data = rpgLoad();
            const now = new Date();
            let changed = false;
            let decayAlerts = [];

            Object.entries(data.muscles).forEach(([muscle, info]) => {
                if (!info.lastTrained) return;
                const daysSince = (now - new Date(info.lastTrained)) / 86400000;
                const daysOverGrace = daysSince - RPG_GRACE_DAYS;

                if (daysOverGrace > 0 && info.xp > 0) {
                    const prevLevel = rpgLevelFromXP(info.xp);
                    const loss = Math.ceil(info.xp * RPG_DECAY_PCT * daysOverGrace);
                    info.xp = Math.max(0, info.xp - loss);
                    changed = true;
                } else if (daysSince >= RPG_GRACE_DAYS - 1 && daysSince < RPG_GRACE_DAYS) {
                    // Alerte : 1 jour avant le début du decay
                    decayAlerts.push(muscle);
                }
            });

            // Decay profil
            if (data.profile && data.profile.lastActivity) {
                const profileDays = (now - new Date(data.profile.lastActivity)) / 86400000;
                if (profileDays > RPG_PROFILE_GRACE && data.profile.xp > 0) {
                    const excess = profileDays - RPG_PROFILE_GRACE;
                    const loss = Math.ceil(data.profile.xp * RPG_PROFILE_DECAY * excess);
                    data.profile.xp = Math.max(0, data.profile.xp - loss);
                    changed = true;
                }
            }

            if (changed) rpgSave(data);

            // Afficher alertes decay
            if (decayAlerts.length > 0) {
                setTimeout(() => {
                    showToast(`⚠️ ${decayAlerts.slice(0,3).join(', ')} commencent à dégénérer demain !`, 'warning', 5000);
                }, 2000);
            }
        }

        // ── Jalons ──────────────────────────────────────────────────
        function rpgCheckMilestones(muscle, level, data) {
            const unlocked = JSON.parse(localStorage.getItem('fitproRPGMilestones') || '[]');
            RPG_MILESTONES.forEach(m => {
                const key = `muscle_${m.level}_${muscle}`;
                if (level >= m.level && !unlocked.includes(key)) {
                    unlocked.push(key);
                    localStorage.setItem('fitproRPGMilestones', JSON.stringify(unlocked));
                    setTimeout(() => showToast(`${m.badge} Jalon débloqué ! ${muscle} atteint le niveau ${m.level} (${m.label}) !`, 'success', 4000), 1500);
                }
            });
        }

