        // ── Rendu panel RPG ──────────────────────────────────────────
        function renderRPGPanel() {
            const section = document.getElementById('rpgSection');
            if (!section || !rpgEnabled()) { if(section) section.style.display='none'; return; }
            section.style.display = 'block';

            const data = rpgLoad();
            const profileXP = Object.values(data.muscles).reduce((s, m) => s + m.xp, 0);
            const profileLevel = rpgLevelFromXP(profileXP);
            const title = rpgTitle(profileLevel);
            const xpThis = rpgXPForLevel(profileLevel);
            const xpNext = rpgXPForLevel(profileLevel + 1);
            const pct = xpNext > xpThis ? Math.round((profileXP - xpThis) / (xpNext - xpThis) * 100) : 100;

            // Header profil
            document.getElementById('rpgTitleEmoji').textContent = title.emoji;
            document.getElementById('rpgProfileTitle').textContent = title.title;
            document.getElementById('rpgProfileLevel').textContent = profileLevel;
            document.getElementById('rpgProfileXPTotal').textContent = profileXP.toLocaleString();
            const bar = document.getElementById('rpgProfileBar');
            if (bar) bar.style.width = pct + '%';
            const nextEl = document.getElementById('rpgProfileNext');
            if (nextEl) nextEl.textContent = `${(profileXP - xpThis).toLocaleString()} / ${(xpNext - xpThis).toLocaleString()} XP vers niv.${profileLevel + 1}`;

            // Mise à jour settings preview
            const gEmoji = document.getElementById('gameTitleEmoji');
            const gTitle = document.getElementById('gameProfileTitle');
            const gLevel = document.getElementById('gameProfileLevel');
            const gXP    = document.getElementById('gameProfileXP');
            if (gEmoji) gEmoji.textContent = title.emoji;
            if (gTitle) gTitle.textContent = title.title;
            if (gLevel) gLevel.textContent = profileLevel;
            if (gXP)    gXP.textContent    = profileXP.toLocaleString();

            // Muscles — trier par niveau décroissant
            const muscles = Object.entries(data.muscles).sort((a, b) => b[1].xp - a[1].xp);
            const now = new Date();
            const grid = document.getElementById('rpgMuscleGrid');
            if (!grid) return;

            if (muscles.length === 0) {
                grid.innerHTML = '<p style="color:#6b7280;text-align:center;font-size:0.9em;padding:20px 0;">Commence une séance pour gagner de l\'XP !</p>';
            } else {
                grid.innerHTML = muscles.map(([muscle, info]) => {
                    const lv = rpgLevelFromXP(info.xp);
                    const xpLow  = rpgXPForLevel(lv);
                    const xpHigh = rpgXPForLevel(lv + 1);
                    const pct    = xpHigh > xpLow ? Math.round((info.xp - xpLow) / (xpHigh - xpLow) * 100) : 100;
                    const daysSince = info.lastTrained ? (now - new Date(info.lastTrained)) / 86400000 : 999;
                    const decaying  = daysSince >= RPG_GRACE_DAYS;
                    const warning   = daysSince >= RPG_GRACE_DAYS - 1 && !decaying;
                    const statusDot = decaying ? '🔴' : warning ? '🟡' : '🟢';
                    const barColor  = lv >= 20 ? 'linear-gradient(90deg,#fbbf24,#f59e0b)' :
                                     lv >= 10  ? 'linear-gradient(90deg,#4ade80,#166534)' :
                                                 'linear-gradient(90deg,#60a5fa,#3b82f6)';
                    const medal = lv >= 50 ? '💎' : lv >= 20 ? '🥇' : lv >= 10 ? '🥈' : lv >= 5 ? '🥉' : '';

                    return `<div style="background:#f8fafc;border-radius:12px;padding:12px 14px;border:1px solid #e5e7eb;">
                        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;">
                            <div style="font-weight:700;color:#0F1014;font-size:0.92em;">${statusDot} ${muscle} ${medal}</div>
                            <div style="font-size:0.8em;color:#16a34a;font-weight:800;">Niv. ${lv}</div>
                        </div>
                        <div style="background:#e5e7eb;border-radius:99px;height:6px;overflow:hidden;margin-bottom:4px;">
                            <div style="height:100%;background:${barColor};border-radius:99px;width:${pct}%;transition:width 0.8s ease;"></div>
                        </div>
                        <div style="font-size:0.72em;color:#6b7280;display:flex;justify-content:space-between;">
                            <span>${info.xp.toLocaleString()} XP</span>
                            <span>${decaying ? '⚠️ En déclin' : warning ? '⚡ Entraîne-toi demain' : `${Math.floor(daysSince)}j`}</span>
                        </div>
                    </div>`;
                }).join('');
            }

            // Jalons
            const unlocked = JSON.parse(localStorage.getItem('fitproRPGMilestones') || '[]');
            const milestonesCard = document.getElementById('rpgMilestonesCard');
            const milestonesList = document.getElementById('rpgMilestonesList');
            if (milestonesCard && milestonesList && unlocked.length > 0) {
                milestonesCard.style.display = 'block';
                const uniqueMilestones = [...new Set(unlocked.map(k => {
                    const parts = k.split('_');
                    return parts[1]; // level number
                }))];
                milestonesList.innerHTML = unlocked.map(key => {
                    const parts = key.split('_');
                    const level = parseInt(parts[1]);
                    const muscle = parts.slice(2).join('_');
                    const m = RPG_MILESTONES.find(m => m.level === level);
                    return m ? `<div style="background:#FFF3E0;border-radius:10px;padding:8px 12px;font-size:0.8em;font-weight:700;color:#166534;">${m.badge} ${muscle} niv.${level}</div>` : '';
                }).join('');
            }
        }

