        // ========== HAPTIC FEEDBACK (VIBRATION) ==========
        function vibrate(pattern) {
            if (isVibOff) return;
            if ('vibrate' in navigator) navigator.vibrate(pattern);
        }

        // Haptic presets sémantiques
        const haptic = {
            light:    ()  => vibrate(25),
            medium:   ()  => vibrate(60),
            heavy:    ()  => vibrate(120),
            success:  ()  => vibrate([40, 30, 100]),
            error:    ()  => vibrate([80, 40, 80, 40, 80]),
            repTick:  ()  => vibrate(20),
            setDone:  ()  => vibrate([40, 30, 100]),
            pr:       ()  => vibrate([80, 40, 120, 40, 200]),
            restEnd:  ()  => vibrate([60, 50, 60, 50, 150]),
            workout:  ()  => vibrate([100, 50, 100, 50, 100, 50, 300]),
            celebrity: (color) => {
                // Pattern unique selon la couleur/star — encode la teinte en rythme
                const patterns = {
                    '#ef4444': [100, 50, 200, 50, 100],  // Rock — lourd
                    '#16a34a': [80, 40, 80, 40, 160],    // Thor
                    '#f59e0b': [60, 30, 60, 30, 60, 30, 120], // Wolverine
                    '#06b6d4': [50, 25, 150, 25, 50],    // CBum
                    '#22c55e': [40, 20, 40, 20, 200],    // Ronaldo
                    '#a855f7': [70, 35, 70, 35, 140],    // WonderWoman
                };
                vibrate(patterns[color] || [80, 40, 160]);
            },
        };

        function completeWorkout() {
            clearInterval(timerInterval);
            releaseWakeLock();
            if (currentWorkout) currentWorkout._completed = true;
            saveSessionSets(); // Persister l'historique des séries
            
            // Vibration célébration
            vibrate([200, 100, 200, 100, 200]);
            
            // Calculate duration with safety limits
            const elapsedMs = Date.now() - workoutStartTime;
            const elapsedMinutes = Math.round(elapsedMs / 60000);
            
            // Safety: Max 3 hours, min 1 minute
            const totalMinutes = Math.max(1, Math.min(elapsedMinutes, 180));
            
            let stats = loadStats();
            stats.workouts++;
            stats.minutes += totalMinutes;
            stats.streak = updateStreak(stats);
            stats.lastWorkout = new Date().toISOString();
            saveStats(stats);
            
            // Save to history
            saveWorkoutToHistory(currentWorkout, (Date.now() - workoutStartTime) / 1000);
            
            // NOUVEAU : Sauvegarder muscles travaillés pour tracking récupération
            saveMusclesWorked(currentWorkout);

            // ⚔️ Tentative de drop d'équipement (mode aventure)
            try {
                if (typeof tryEquipmentDrop === 'function' && typeof getAdventureEnabled === 'function' && getAdventureEnabled()) {
                    // Déterminer le muscle principal de la séance
                    const realEx = (currentWorkout?.exercises || []).filter(e => !e.isRest && !e.isInfo);
                    const muscleCount = {};
                    realEx.forEach(ex => {
                        const db = exerciseDatabase.find(e => e.name === ex.name);
                        const m = db?.muscle || ex.muscle || 'Corps entier';
                        muscleCount[m] = (muscleCount[m] || 0) + 1;
                    });
                    const mainMuscle = Object.entries(muscleCount).sort((a,b) => b[1]-a[1])[0]?.[0] || 'Corps entier';
                    
                    const result = tryEquipmentDrop(mainMuscle);
                    if (result) {
                        // Délai pour afficher après l'écran de fin
                        setTimeout(() => showDropModal(result.item, result.rarity), 1800);
                    }
                }
            } catch(e) { console.warn('Adventure drop error:', e); }

            // ⚔️ Vérifier progression du défi actif
            try {
                if (typeof checkChallengeOnWorkoutComplete === 'function') {
                    checkChallengeOnWorkoutComplete();
                }
            } catch(e) { console.warn('Challenge check error:', e); }
            
            // CHECK IF THIS IS A PLAN SESSION AND MARK IT COMPLETE
            if (currentWorkout && currentWorkout.type === 'plan') {
                completePlanSession();
            }
            
            // ── Remplir l'écran de complétion enrichi ──
            document.getElementById('completionTime').textContent = totalMinutes;
            const realExercises = currentWorkout.exercises.filter(ex => !ex.isRest && !ex.isInfo);
            document.getElementById('completionExercises').textContent = realExercises.length;

            // Calories précises : formule MET × poids_kg × heures
            const profile = getUserProfile();
            // Convertir en kg si l'utilisateur utilise lbs
            let weightKg = (profile && profile.weight) ? profile.weight : 75;
            if (!useKg) weightKg = Math.round(weightKg * 0.453592 * 10) / 10;
            const wName = (currentWorkout.name || '').toLowerCase();
            const MET = wName.includes('hiit') ? 10 :
                        wName.includes('cardio') ? 8 :
                        wName.includes('mobility') || wName.includes('récup') || wName.includes('stretch') || wName.includes('étir') ? 3 :
                        wName.includes('force') || wName.includes('strength') ? 5 : 6;
            const kcal = Math.round(MET * weightKg * (totalMinutes / 60));
            document.getElementById('completionCalories').textContent = kcal;

            // Volume total (séries × reps × poids)
            let totalVolume = 0;
            const volDiv = document.getElementById('completionVolume');
            const volVal = document.getElementById('completionVolumeValue');
            try {
                const perfHistory = JSON.parse(localStorage.getItem('exercisePerformance') || '{}');
                realExercises.forEach(ex => {
                    const perf = perfHistory[ex.name];
                    if (perf && perf.history && perf.history.length > 0) {
                        const last = perf.history[perf.history.length - 1];
                        if (last && last.reps && last.weight) {
                            totalVolume += (last.reps * last.weight);
                        }
                    }
                });
            } catch(e) {}
            if (totalVolume > 0 && volDiv && volVal) {
                const unit = useKg ? 'kg' : 'lbs';
                volVal.textContent = totalVolume.toLocaleString() + ' ' + unit;
                volDiv.style.display = 'block';
            }

            // Nom séance
            const nameEl = document.getElementById('completionWorkoutName');
            if (nameEl) nameEl.textContent = currentWorkout.name || 'Séance terminée 💪';

            // Muscles travaillés
            const muscles = [...new Set(realExercises
                .map(ex => { const db = exerciseDatabase.find(e => e.name === ex.name); return db ? db.muscle : null; })
                .filter(Boolean))];
            const musclesDiv = document.getElementById('completionMuscles');
            const musclesList = document.getElementById('completionMusclesList');
            if (muscles.length > 0 && musclesDiv && musclesList) {
                musclesList.innerHTML = muscles.map(m =>
                    `<span style="background:rgba(255,255,255,0.18);color:white;padding:3px 10px;border-radius:20px;font-size:0.82em;font-weight:600;border:1px solid rgba(255,255,255,0.25);">${m}</span>`
                ).join('');
                musclesDiv.style.display = 'block';
            }

            // ── COMPARAISON STATS CÉLÉBRITÉ ───────────────────────────
            if (currentWorkout && currentWorkout._celebrity) {
                const celebStatCard = document.getElementById('completionCelebStats');
                if (celebStatCard) {
                    celebStatCard.innerHTML = buildCelebStatComparison(currentWorkout._celebrity, currentWorkout.exercises);
                    celebStatCard.style.display = 'block';
                }
            } else {
                const cs = document.getElementById('completionCelebStats');
                if (cs) cs.style.display = 'none';
            }

            // Streak
            const streakText = document.getElementById('completionStreakText');
            const streakSub = document.getElementById('completionStreakSub');
            if (streakText) {
                const freshStats = loadStats();
                const streak = freshStats.streak || 1;
                streakText.textContent = streak >= 7 ? `🔥 ${streak} jours consécutifs !` :
                                         streak >= 3 ? `🔥 ${streak} jours de suite !` : `Séance ${freshStats.workouts} complétée !`;
                if (streakSub) streakSub.textContent = streak >= 7 ? 'Vous êtes en feu !' :
                                                        streak >= 3 ? 'Belle régularité !' : 'Continuez comme ça !';
            }

            document.getElementById('exerciseView').classList.add('hidden'); document.body.classList.remove('in-session');
            document.body.classList.remove('session-fullscreen'); _sessionFullscreen = false;
            document.getElementById('completionView').classList.remove('hidden');
            window.scrollTo({ top: 0, behavior: 'smooth' });
            hideGlobalRestBanner();
            // 📊 Bilan enrichi
            buildEnrichedCompletion(currentWorkout, totalMinutes);
            // 🎯 Défi hebdo — générer si besoin + mettre à jour
            generateWeeklyChallenge();
            renderWeeklyChallenge(JSON.parse(localStorage.getItem('fitproWeeklyChallenge') || 'null'));
            // 🎉 Confettis !
            setTimeout(launchConfetti, 200);
            // Animer les stats
            document.querySelectorAll('#completionView [id^="completion"]').forEach((el, i) => {
                el.style.animationDelay = (i * 0.08) + 's';
                el.classList.add('completion-stat-animate');
            });

            // 🎮 RPG — après séance complète
            if (rpgEnabled()) {
                // Donjon complété ?
                if (currentWorkout && currentWorkout.type === 'dungeon' && currentWorkout._dungeonId) {
                    setTimeout(() => rpgCompleteDungeon(currentWorkout._dungeonId), 800);
                }
                // Vérifier quêtes quotidiennes
                setTimeout(() => {
                    const dq = rpgGetDailyQuests();
                    dq.forEach(q => { if (q.done) rpgAwardDailyQuest(q.id, q.xpReward); });
                }, 600);
                // Attaquer le boss de la semaine
                setTimeout(() => {
                    if (currentWorkout) {
                        const trainedMuscles = [...new Set((currentWorkout.exercises||[]).map(ex => {
                            const db = exerciseDatabase.find(e=>e.name===ex.name); return db?.muscle;
                        }).filter(Boolean))];
                        rpgDamageBoss(trainedMuscles);
                    }
                }, 1000);
                // Vérifier les exploits
                setTimeout(rpgCheckAchievements, 400);

                // Coffre de butin
                setTimeout(() => {
                    const loot = rpgRollLoot();
                    rpgOpenLootChest(loot);
                    rpgShowLootChest(loot);
                }, 2000);
                // Rang : vérifier si changement
                setTimeout(() => {
                    const data = rpgLoad();
                    const totalXP = Object.values(data.muscles).reduce((s,m)=>s+m.xp,0);
                    const newRank = rpgGetRank(totalXP);
                    const prevRank = localStorage.getItem('fitproLastRank') || 'E';
                    if (newRank.id !== prevRank) {
                        localStorage.setItem('fitproLastRank', newRank.id);
                        rpgShowRankUp(newRank);
                    }
                }, 1200);
            }
        }


