        // Clé localStorage pour la personnalité active
        const CELEBRITY_ACTIVE_KEY   = 'fitproActiveCelebrity';
        const CELEBRITY_START_KEY    = 'fitproActiveCelebStart';
        const CELEBRITY_SESSIONS_KEY = 'fitproCelebSessions';

        // Phases 12 semaines
        const CELEBRITY_PHASES = {
            phase1: { label:'Adaptation',    weeks:'1-4',  setsScale:0.75, restScale:1.25, color:'#10b981', desc:'Maîtriser les mouvements, adapter le corps.' },
            phase2: { label:'Progression',   weeks:'5-8',  setsScale:1.0,  restScale:1.0,  color:'#f59e0b', desc:'Programme exact de la personnalité.' },
            phase3: { label:'Intensification', weeks:'9-12', setsScale:1.25, restScale:0.85, color:'#ef4444', desc:'Volume maximum, repos réduits.' },
        };

        function getActiveCelebrity() {
            const id = localStorage.getItem(CELEBRITY_ACTIVE_KEY);
            return id ? CELEBRITY_PROGRAMS.find(p => p.id === id) || null : null;
        }

        function getCelebProgression(programId) {
            const startStr = localStorage.getItem(CELEBRITY_START_KEY + '_' + programId);
            if (!startStr) return { week:1, phaseKey:'phase1', phase:CELEBRITY_PHASES.phase1, totalWeeks:12, sessionsCompleted:0, pct:0 };
            const week = Math.min(12, Math.max(1, Math.floor((Date.now() - new Date(startStr)) / (7*86400000)) + 1));
            const phaseKey = week <= 4 ? 'phase1' : week <= 8 ? 'phase2' : 'phase3';
            const sessions = JSON.parse(localStorage.getItem(CELEBRITY_SESSIONS_KEY) || '{}');
            return { week, phaseKey, phase: CELEBRITY_PHASES[phaseKey], totalWeeks:12, sessionsCompleted: sessions[programId] || 0, pct: Math.round((week-1)/11*100) };
        }

        function recordCelebritySession(programId) {
            const sessions = JSON.parse(localStorage.getItem(CELEBRITY_SESSIONS_KEY) || '{}');
            sessions[programId] = (sessions[programId] || 0) + 1;
            lsSet(CELEBRITY_SESSIONS_KEY, JSON.stringify(sessions));
        }

        function scaleCelebExercise(ex, prog) {
            return { ...ex, sets: Math.max(1, Math.round(ex.sets * prog.phase.setsScale)), _rest: Math.round((ex.rest || ex._rest || 90) * prog.phase.restScale) };
        }

        function resetCelebrityProgram(programId) {
            localStorage.removeItem(CELEBRITY_START_KEY + '_' + programId);
            const sessions = JSON.parse(localStorage.getItem(CELEBRITY_SESSIONS_KEY) || '{}');
            delete sessions[programId];
            lsSet(CELEBRITY_SESSIONS_KEY, JSON.stringify(sessions));
            showToast('\u{1F504} Programme réinitialisé — Semaine 1', 'success', 2500);
            setActiveCelebrity(programId);
        }

        function renderCelebProgressCard(p, prog) {
            const phaseList = [
                { key:'phase1', label:'Adaptation',  weeks:'1-4',  color:'#10b981' },
                { key:'phase2', label:'Progression', weeks:'5-8',  color:'#f59e0b' },
                { key:'phase3', label:'Intensif.',   weeks:'9-12', color:'#ef4444' },
            ];
            const phaseBlocks = phaseList.map((ph, idx) => {
                const activeIdx = phaseList.findIndex(x => x.key === prog.phaseKey);
                const isActive = ph.key === prog.phaseKey, isDone = idx < activeIdx;
                return '<div style="flex:1;padding:8px 6px;border-radius:10px;text-align:center;border:' + (isActive?'2':'1') + 'px solid ' + (isActive?ph.color+'80':isDone?ph.color+'40':'rgba(255,255,255,0.08)') + ';background:' + (isActive?ph.color+'18':isDone?ph.color+'08':'rgba(255,255,255,0.02)') + ';">'
                    + '<div style="font-size:0.6em;font-weight:800;color:' + (isActive?ph.color:isDone?ph.color+'aa':'rgba(255,255,255,0.25)') + ';text-transform:uppercase;">' + (isDone?'\u2713 ':isActive?'\u25B6 ':'') + ph.label + '</div>'
                    + '<div style="font-size:0.55em;color:rgba(255,255,255,0.3);margin-top:1px;">sem. ' + ph.weeks + '</div></div>';
            }).join('');

            const dots = Array.from({length:12}, (_,i) => {
                const w=i+1, done=w<prog.week, cur=w===prog.week;
                const col = w<=4?'#10b981':w<=8?'#f59e0b':'#ef4444';
                return '<div style="width:' + (cur?16:8) + 'px;height:' + (cur?16:8) + 'px;border-radius:50%;flex-shrink:0;background:' + (done||cur?col:'rgba(255,255,255,0.12)') + ';border:' + (cur?'2px solid white':'none') + ';"></div>';
            }).join('');

            const scaleLabel = prog.phase.setsScale===0.75 ? '-25% séries' : prog.phase.setsScale===1.25 ? '+25% séries' : 'volume normal';

            return '<div style="background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:14px 16px;margin-bottom:14px;">'
                + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">'
                + '<div><div style="font-size:0.62em;color:rgba(255,255,255,0.35);font-weight:800;text-transform:uppercase;letter-spacing:1px;">\u{1F4C8} Programme 12 semaines</div>'
                + '<div style="font-size:1.05em;font-weight:900;color:' + prog.phase.color + ';margin-top:2px;">Semaine ' + prog.week + ' / 12 — ' + prog.phase.label + '</div></div>'
                + '<div style="text-align:right;"><div style="font-size:1.5em;font-weight:900;color:white;">' + prog.sessionsCompleted + '</div><div style="font-size:0.6em;color:rgba(255,255,255,0.35);">séances</div></div></div>'
                + '<div style="background:rgba(255,255,255,0.08);border-radius:99px;height:6px;overflow:hidden;margin-bottom:8px;"><div style="height:100%;background:linear-gradient(90deg,#10b981,#f59e0b,#ef4444);border-radius:99px;width:' + prog.pct + '%;transition:width 0.8s ease;"></div></div>'
                + '<div style="display:flex;align-items:center;gap:3px;justify-content:space-between;margin-bottom:10px;">' + dots + '</div>'
                + '<div style="display:flex;gap:6px;margin-bottom:10px;">' + phaseBlocks + '</div>'
                + '<div style="font-size:0.75em;color:rgba(255,255,255,0.5);line-height:1.4;">' + prog.phase.desc + ' <span style="color:' + prog.phase.color + ';font-weight:700;">(' + scaleLabel + ')</span></div>'
                + '<button onclick="if(confirm(\'Recommencer à la semaine 1 ?\')){resetCelebrityProgram(\'' + p.id + '\');document.getElementById(\'celebrityDetailOverlay\')?.remove();showCelebrityDetail(\'' + p.id + '\');}" style="margin-top:10px;width:100%;padding:8px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);border-radius:8px;color:rgba(255,255,255,0.3);font-size:0.72em;font-weight:700;cursor:pointer;">\u{1F504} Recommencer depuis la semaine 1</button>'
                + '</div>';
        }

        function setActiveCelebrity(programId) {
            if (programId) {
                localStorage.setItem(CELEBRITY_ACTIVE_KEY, programId);
                if (!localStorage.getItem(CELEBRITY_START_KEY + '_' + programId)) {
                    localStorage.setItem(CELEBRITY_START_KEY + '_' + programId, new Date().toISOString());
                }
            } else {
                localStorage.removeItem(CELEBRITY_ACTIVE_KEY);
            }
            if (typeof updateProfileDisplay === 'function') updateProfileDisplay();
            if (typeof updateHomeStats      === 'function') updateHomeStats();
            const planTab = document.getElementById('planningTab');
            if (planTab && planTab.classList.contains('active') && typeof renderWeeklyPlan === 'function') renderWeeklyPlan();
        }

        // ── 1. Plan hebdomadaire calqué sur la personnalité ────────────
        function applyCelebrityWeeklyPlan(program) {
            const dayNames = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

            // Mapper les splits de la personnalité sur les 7 jours
            const plan = dayNames.map((dayName, i) => {
                // Trouver le split correspondant à ce jour
                const split = program.splits.find(s => {
                    const d = s.day.toLowerCase();
                    return d === dayName.toLowerCase().slice(0, 3)
                        || d.startsWith(dayName.toLowerCase().slice(0, 3));
                });

                if (!split || split.name.includes('Repos') || split.name.includes('🛌') || split.name.includes('repos')) {
                    return {
                        day: dayName,
                        focus: split ? split.name.replace('🛌','').trim() : 'Repos',
                        intensity: split && (split.name.toLowerCase().includes('actif') || split.name.toLowerCase().includes('yoga') || split.name.toLowerCase().includes('surf')) ? 'low' : 'rest',
                        muscles: []
                    };
                }

                // Déduire les muscles du focus du split
                const muscles = _musclesFromSplitName(split.name);
                const intensity = _intensityFromSplitName(split.name);

                return {
                    day: dayName,
                    focus: `${program.emoji} ${split.name}`,
                    intensity,
                    muscles,
                    _celebrity: program.id
                };
            });

            saveWeeklyPlan(plan);
            renderWeeklyPlan();
            showToast(`📅 Plan de ${program.nickname} appliqué à ta semaine !`, 'success', 3500);
        }

        function _musclesFromSplitName(name) {
            const n = name.toLowerCase();
            const map = [
                [['poitrine','pectoraux','chest','push','bench'],       ['Pectoraux']],
                [['dos','back','pull','dorsaux'],                        ['Dos']],
                [['épaules','shoulder','militaire'],                     ['Épaules']],
                [['bras','biceps','triceps','curl','dips'],              ['Biceps','Triceps']],
                [['jambes','quadriceps','squat','lower','deadlift','dl'],['Quadriceps','Ischio-jambiers','Fessiers']],
                [['fessiers','glutes','hip'],                            ['Fessiers']],
                [['abdos','core','planche'],                             ['Abdominaux']],
                [['cardio','hiit','tabata'],                             ['Cardio']],
                [['corps entier','full body','fonctionnel'],             ['Pectoraux','Dos','Quadriceps','Épaules']],
            ];
            const muscles = [];
            for (const [keys, mList] of map) {
                if (keys.some(k => n.includes(k))) mList.forEach(m => { if (!muscles.includes(m)) muscles.push(m); });
            }
            return muscles.length ? muscles : ['Corps entier'];
        }

        function _intensityFromSplitName(name) {
            const n = name.toLowerCase();
            if (n.includes('repos') || n.includes('rest') || n.includes('🛌')) return 'rest';
            if (n.includes('yoga') || n.includes('mobilité') || n.includes('actif') || n.includes('léger') || n.includes('surf') || n.includes('rando')) return 'low';
            if (n.includes('force') && n.includes('5×5')) return 'high';
            if (n.includes('hiit') || n.includes('tabata') || n.includes('cardio') || n.includes('circuit')) return 'high';
            return 'moderate';
        }

        // ── 2. Exercices signature pendant la génération ──────────────
        function getCelebritySignatureExercises(programId) {
            const program = CELEBRITY_PROGRAMS.find(p => p.id === programId);
            if (!program) return [];
            return program.exercises.map(e => e.name);
        }

        // Prioriser les exercices signature dans le pool de génération
        function prioritizeCelebrityExercises(exercisePool, programId) {
            const signature = getCelebritySignatureExercises(programId);
            if (!signature.length) return exercisePool;
            return [...exercisePool].sort((a, b) => {
                const aIsSig = signature.includes(a.name) ? 0 : 1;
                const bIsSig = signature.includes(b.name) ? 0 : 1;
                return aIsSig - bIsSig;
            });
        }

        // ── 3. Citation aléatoire pendant le repos ────────────────────
        function _showCelebrityQuoteInRest(programId) {
            const quotes = CELEBRITY_QUOTES[programId];
            const program = CELEBRITY_PROGRAMS.find(p => p.id === programId);
            if (!quotes || !program) return;

            // Supprimer ancienne citation
            document.getElementById('_celebQuote')?.remove();

            const q = quotes[Math.floor(Math.random() * quotes.length)];
            const div = document.createElement('div');
            div.id = '_celebQuote';
            div.style.cssText = `
                max-width:320px;width:90%;margin-top:20px;padding:14px 18px;
                background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.12);
                border-radius:16px;text-align:center;animation:restFadeIn 0.5s ease;
            `;
            div.innerHTML = `
                <div style="font-size:1.6em;margin-bottom:6px;">${program.emoji}</div>
                <div style="font-size:0.82em;font-style:italic;color:#e2e8f0;line-height:1.5;">${q}</div>
                <div style="font-size:0.65em;color:#6b7280;margin-top:6px;font-weight:700;letter-spacing:1px;">— ${program.nickname}</div>
            `;
            document.getElementById('restOverlay')?.appendChild(div);
        }

        function startCelebrityProgram(programId) {
            const program = CELEBRITY_PROGRAMS.find(p => p.id === programId);
            if (!program) return;
            document.getElementById('celebrityOverlay')?.remove();
            document.getElementById('celebrityDetailOverlay')?.remove();

            // Activer cette personnalité
            setActiveCelebrity(programId);

            // Appliquer le plan hebdomadaire
            applyCelebrityWeeklyPlan(program);

            // Récupérer la phase courante
            const prog = getCelebProgression(programId);

            const exercises = program.exercises.map(ex => {
                const db = exerciseDatabase.find(e => e.name === ex.name);
                if (!db) return null;
                const base = {
                    ...db,
                    sets:     ex.sets,
                    reps:     ex.reps     || null,
                    duration: ex.duration || db.duration || 45,
                    mode:     ex.mode     || 'reps',
                    _rest:    ex.rest     || program.rest || 90,
                    note:     ex.note     || ''
                };
                // Appliquer le scaling de phase
                return scaleCelebExercise(base, prog);
            }).filter(Boolean);

            if (exercises.length === 0) {
                showToast('⚠️ Exercices introuvables — vérifiez la base de données', 'warning', 3000);
                return;
            }

            currentWorkout = {
                name:            program.emoji + ' ' + program.nickname + ' — ' + program.name + ' (Sem.' + prog.week + ')',
                exercises,
                mode:            'mixed',
                restBetweenSets: program.rest || 90,
                type:            'celebrity',
                _celebrity:      program.id,
                _celebrityColor: program.color,
                _celebPhase:     prog.phaseKey,
            };
            workoutStartTime = Date.now();
            currentExerciseIndex = 0;

            // Enregistrer la séance pour le suivi
            recordCelebritySession(programId);
            switchTab('workouts');
            document.getElementById('completionView')?.classList.add('hidden');
            const ws = document.getElementById('workoutSelection');
            if (ws) ws.style.display = 'none';
            document.getElementById('exerciseView').classList.remove('hidden'); document.body.classList.add('in-session');
            window.scrollTo(0, 0);
            initProgressList();
            startExercise();
        }




        function backToHome() {
            window._overrideSessionMuscles = null; // nettoyer si abandon
            // Clear ALL timers
            clearInterval(timerInterval);
            clearInterval(cardioInterval);
            if (amrapTimerInterval) {
                clearInterval(amrapTimerInterval);
                amrapTimerInterval = null;
            }
            
            // Reset ALL workout variables
            currentWorkout = null;
            currentSupersetWorkout = null;
            currentCircuitWorkout = null;
            currentAMRAPWorkout = null;
            cardioMode = null;
            cardioInterval = null;
            cardioTimeElapsed = 0;
            currentExerciseIndex = 0;
            isPaused = false;
            hideGlobalRestBanner();
            const progressContainer = document.getElementById('exerciseProgressItems');
            if (progressContainer) progressContainer.innerHTML = '';
            
            // Hide exercise and completion views
            document.getElementById('exerciseView').classList.add('hidden'); document.body.classList.remove('in-session');
            const _cv = document.getElementById('completionView');
            if (_cv) { _cv.classList.add('hidden'); _cv.style.display = ''; }
            
            // Show workout selection
            const workoutSelection = document.getElementById('workoutSelection');
            if (workoutSelection) {
                workoutSelection.style.display = '';
            }
            
            // Reload stats and recovery status
            loadStats();
            renderMuscleRecoveryStatus();  // Rafraîchir état récupération
            
            // Switch to workouts tab
            switchTab('workouts');
            updateHomeStats();
        }

        function playSound() {
            if (isMuted) return;
            try {
                const audioContext = new (window.AudioContext || window.webkitAudioContext)();
                const oscillator = audioContext.createOscillator();
                const gainNode = audioContext.createGain();
                
                oscillator.connect(gainNode);
                gainNode.connect(audioContext.destination);
                
                oscillator.frequency.value = 800;
                oscillator.type = 'sine';
                
                gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
                gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.3);
                
                oscillator.start(audioContext.currentTime);
                oscillator.stop(audioContext.currentTime + 0.3);
            } catch (e) {
            }
        }

        // ── Système sonore ─────────────────────────────────────────
        let _audioCtx = null;
        function _getAudioCtx() {
            if (!_audioCtx || _audioCtx.state === 'closed') {
                _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
            }
            if (_audioCtx.state === 'suspended') _audioCtx.resume();
            return _audioCtx;
        }

        function _tone(freq, dur, vol = 0.25, type = 'sine', delay = 0) {
            if (isMuted) return;
            try {
                const ctx  = _getAudioCtx();
                const osc  = ctx.createOscillator();
                const gain = ctx.createGain();
                osc.connect(gain);
                gain.connect(ctx.destination);
                osc.type = type;
                osc.frequency.setValueAtTime(freq, ctx.currentTime + delay);
                gain.gain.setValueAtTime(vol, ctx.currentTime + delay);
                gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + delay + dur);
                osc.start(ctx.currentTime + delay);
                osc.stop(ctx.currentTime + delay + dur + 0.05);
            } catch(e) {}
        }

        // Bip court countdown (5 dernières secondes)
        function playBeep() { _tone(1000, 0.09, 0.2); }

        // Bip de fin de repos — 3 bips ascendants
        function playRestEndSound() {
            _tone(600,  0.12, 0.3, 'sine', 0);
            _tone(800,  0.12, 0.3, 'sine', 0.15);
            _tone(1050, 0.2,  0.4, 'sine', 0.30);
            haptic.restEnd();
        }

        // Tick léger sur chaque répétition comptée
        function playRepTick() {
            _tone(440, 0.04, 0.12, 'square');
            haptic.repTick();
        }

        // Son de fin de série
        function playSetDone() {
            _tone(520, 0.08, 0.2, 'sine', 0);
            _tone(780, 0.15, 0.25, 'sine', 0.1);
            haptic.setDone();
        }

        // Fanfare Personal Record
        function playPRFanfare() {
            _tone(523, 0.1, 0.35, 'triangle', 0);
            _tone(659, 0.1, 0.35, 'triangle', 0.1);
            _tone(784, 0.1, 0.35, 'triangle', 0.2);
            _tone(1047,0.3, 0.4,  'triangle', 0.3);
            vibrate([100, 50, 100, 50, 200]);
        }

        // Close modal on click outside
        document.getElementById('exerciseModal').addEventListener('click', function(e) {
            if (e.target === this) {
                closeExerciseModal();
            }
        });

        // Initialize
        // ========== EXERCISE SEARCH ==========
        function filterExercisesBySearch() {
            const query = document.getElementById('exerciseSearch').value.toLowerCase().trim();
            const resultsContainer = document.getElementById('searchResults');
            const statsContainer = document.getElementById('searchStats');
            
            if (query.length < 2) {
                resultsContainer.innerHTML = '';
                statsContainer.innerHTML = '';
                return;
            }
            
            const matches = exerciseDatabase.filter(ex => 
                ex.name.toLowerCase().includes(query) ||
                ex.muscle.toLowerCase().includes(query) ||
                ex.equipment.toLowerCase().includes(query)
            );
            
            if (matches.length === 0) {
                resultsContainer.innerHTML = `
                    <div style="text-align: center; padding: 30px; color: #999;">
                        <div style="font-size: 3em; margin-bottom: 10px;">🤷</div>
                        <p>Aucun exercice trouvé pour "${query}"</p>
                        <p style="font-size: 0.9em; margin-top: 10px;">Essayez un autre terme de recherche</p>
                    </div>
                `;
                statsContainer.innerHTML = '';
                return;
            }
            
            const displayMatches = matches.slice(0, 15);
            statsContainer.innerHTML = `✨ ${matches.length} exercice${matches.length > 1 ? 's' : ''} trouvé${matches.length > 1 ? 's' : ''}${matches.length > 15 ? ' (15 premiers affichés)' : ''}`;
            
            let html = '<div style="display: grid; gap: 10px;">';
            displayMatches.forEach(ex => {
                const exerciseIndex = exerciseDatabase.indexOf(ex);
                const badge = ex.type === 'warmup' ? '🏃‍♂️' : ex.type === 'stretch' ? '🧘' : '';
                const typeLabel = ex.type === 'warmup' ? ' <span style="background: #e0f2fe; color: #0369a1; padding: 2px 8px; border-radius: 12px; font-size: 0.8em;">Échauffement</span>' : 
                                 ex.type === 'stretch' ? ' <span style="background: #f0fdf4; color: #15803d; padding: 2px 8px; border-radius: 12px; font-size: 0.8em;">Étirement</span>' : '';
                
                html += `
                    <div class="exercise-result-item" onclick="showExerciseDetail(${exerciseIndex})"
                         style="padding: 15px; background: linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%); 
                                border-radius: 10px; cursor: pointer; transition: all 0.3s; 
                                border-left: 4px solid #16a34a;">
                        <div style="display: flex; justify-content: space-between; align-items: start;">
                            <div style="flex: 1;">
                                <strong style="font-size: 1.1em; color: #333;">${badge} ${ex.name}</strong>${typeLabel}
                                <div style="font-size: 0.9em; color: #666; margin-top: 8px; display: flex; gap: 15px; flex-wrap: wrap;">
                                    <span>💪 ${ex.muscle}</span>
                                    <span>🏋️ ${ex.equipment}</span>
                                </div>
                            </div>
                            <div style="color: #16a34a; font-size: 1.5em;">▶</div>
                        </div>
                    </div>
                `;
            });
            html += '</div>';
            
            resultsContainer.innerHTML = html;
        }

        // Load voices for speech synthesis (fixes language issues)
        if ('speechSynthesis' in window) {
            // Chrome needs this to load voices
            speechSynthesis.addEventListener('voiceschanged', function() {
                // Voices are now loaded
            });
            // Trigger voice loading
            speechSynthesis.getVoices();
        }


        // ========== PROGRAM MANAGEMENT SYSTEM ==========
        
        let currentEditingProgram = null;
        let programExercisesBuffer = [];
        let tempSelectedExercises = [];
        
        // Get all programs from localStorage
        function getPrograms() {
            const saved = localStorage.getItem('myPrograms');
            try { return saved ? JSON.parse(saved) : []; } catch(e) { return []; }
        }
        
        // Save programs to localStorage
        function savePrograms(programs) {
            localStorage.setItem('myPrograms', JSON.stringify(programs));
            renderProgramsList();
        }
        
        // Render programs list
        function renderProgramsList() {
            const container = document.getElementById('myProgramsList');
            const programs = getPrograms();
            
            if (programs.length === 0) {
                container.innerHTML = `
                    <div style="grid-column: 1/-1; text-align: center; padding: 40px 20px; color: #999;">
                        <div style="font-size: 3em; margin-bottom: 15px;">📚</div>
                        <p style="font-size: 1.1em; margin-bottom: 10px;">Aucun programme créé</p>
                        <p style="font-size: 0.9em;">Cliquez sur "Créer un programme" pour commencer</p>
                    </div>
                `;
                return;
            }
            
            container.innerHTML = programs.map((program, index) => `
                <div class="card" style="padding: 20px; position: relative; transition: all 0.3s;">
                    <div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 15px;">
                        <div style="flex: 1;">
                            <h3 style="color: #16a34a; margin: 0 0 8px 0;">${program.name}</h3>
                            <p style="color: #666; font-size: 0.9em; margin: 0;">
                                ${program.exercises.length} exercice(s) • 
                                ~${Math.round(program.exercises.length * 1.5)} min
                            </p>
                        </div>
                        <div style="display: flex; gap: 8px;">
                            <button onclick="event.stopPropagation(); editProgram(${index})" 
                                    class="btn" 
                                    style="padding: 8px 12px; font-size: 0.9em; background: linear-gradient(135deg, #4ade80 0%, #22c55e 100%);"
                                    title="Modifier">
                                ✏️
                            </button>
                            <button onclick="event.stopPropagation(); duplicateProgram(${index})" 
                                    class="btn" 
                                    style="padding: 8px 12px; font-size: 0.9em; background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%);"
                                    title="Dupliquer">
                                📋
                            </button>
                            <button onclick="event.stopPropagation(); deleteProgram(${index})" 
                                    class="btn" 
                                    style="padding: 8px 12px; font-size: 0.9em; background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%);"
                                    title="Supprimer">
                                🗑️
                            </button>
                        </div>
                    </div>
                    
                    <div style="margin-bottom: 15px; padding: 12px; background: #f8f9fa; border-radius: 8px; max-height: 150px; overflow-y: auto;">
                        ${program.exercises.slice(0, 5).map(ex => `
                            <div style="display: flex; align-items: center; padding: 4px 0; color: #666; font-size: 0.9em;">
                                <span style="width: 20px;">•</span>
                                <span style="flex: 1;">${ex.name}</span>
                                <span style="color: #999; font-size: 0.85em;">${ex.muscle}</span>
                            </div>
                        `).join('')}
                        ${program.exercises.length > 5 ? `
                            <div style="text-align: center; color: #999; font-size: 0.85em; margin-top: 8px;">
                                + ${program.exercises.length - 5} autres exercice(s)
                            </div>
                        ` : ''}
                    </div>
                    
                    <button onclick="startProgramWorkout(${index})" 
                            class="btn" 
                            style="width: 100%; background: linear-gradient(135deg, #16a34a 0%, #15803d 100%);">
                        ▶️ Lancer le programme
                    </button>
                </div>
            `).join('');
        }
        
        // Show create program modal
        function showCreateProgramModal() {
            currentEditingProgram = null;
            programExercisesBuffer = [];
            document.getElementById('programEditorTitle').textContent = '➕ Créer un programme';
            document.getElementById('programName').value = '';
            updateProgramExercisesList();
            document.getElementById('programEditorModal').classList.add('active');
        }
        
        // Edit program
        function editProgram(index) {
            const programs = getPrograms();
            const program = programs[index];
            
            currentEditingProgram = index;
            programExercisesBuffer = [...program.exercises];
            
            document.getElementById('programEditorTitle').textContent = '✏️ Modifier le programme';
            document.getElementById('programName').value = program.name;
            updateProgramExercisesList();
            document.getElementById('programEditorModal').classList.add('active');
        }
        
        // Duplicate program
        function duplicateProgram(index) {
            const programs = getPrograms();
            const program = programs[index];
            
            const newProgram = {
                name: program.name + ' (Copie)',
                exercises: [...program.exercises],
                createdAt: new Date().toISOString()
            };
            
            programs.push(newProgram);
            savePrograms(programs);
            speak('Programme dupliqué');
        }
        
        // Delete program
        function deleteProgram(index) {
            const programs = getPrograms();
            const program = programs[index];
            
            showConfirm(`Supprimer le programme "${program.name}" ? Cette action est irréversible.`, function() {
                programs.splice(index, 1);
                savePrograms(programs);
                speak('Programme supprimé');
                showToast(`🗑️ Programme supprimé`, 'success', 2000);
            }, null, { title: 'Supprimer le programme ?', icon: '🗑️', confirmLabel: 'Supprimer', danger: true });
        }
        
        // Save program
        function saveProgram() {
            const name = document.getElementById('programName').value.trim();
            
            if (!name) {
                showAlert('Veuillez donner un nom à votre programme.', 'warning', 'Nom requis');
                return;
            }
            
            if (programExercisesBuffer.length === 0) {
                showAlert('Veuillez ajouter au moins un exercice.', 'warning', 'Exercice requis');
                return;
            }
            
            const programs = getPrograms();
            
            const programData = {
                name: name,
                exercises: programExercisesBuffer,
                createdAt: currentEditingProgram === null ? new Date().toISOString() : programs[currentEditingProgram].createdAt,
                updatedAt: new Date().toISOString()
            };
            
            if (currentEditingProgram === null) {
                // Creating new program
                programs.push(programData);
                speak('Programme créé');
            } else {
                // Updating existing program
                programs[currentEditingProgram] = programData;
                speak('Programme mis à jour');
            }
            
            savePrograms(programs);
            closeProgramEditor();
        }
        
        // Close program editor
        function closeProgramEditor() {
            document.getElementById('programEditorModal').classList.remove('active');
            currentEditingProgram = null;
            programExercisesBuffer = [];
        }
        
        // Update program exercises list display
        function updateProgramExercisesList() {
            const container = document.getElementById('programExercisesList');
            
            if (programExercisesBuffer.length === 0) {
                container.innerHTML = '<p style="text-align: center; color: #999;">Aucun exercice ajouté</p>';
                return;
            }
            
            container.innerHTML = programExercisesBuffer.map((ex, index) => {
                // Rest period
                if (ex.type === 'rest') {
                    return `
                        <div style="display: flex; align-items: center; gap: 10px; padding: 12px; background: #fff4e6; border-radius: 8px; margin-bottom: 8px; border: 2px solid #fed7aa;">
                            <div style="display: flex; flex-direction: column; gap: 4px;">
                                <button onclick="moveProgramExercise(${index}, -1)" 
                                        class="btn" 
                                        style="padding: 4px 8px; font-size: 0.8em; background: #f59e0b;"
                                        ${index === 0 ? 'disabled style="opacity: 0.3;"' : ''}>
                                    ⬆️
                                </button>
                                <button onclick="moveProgramExercise(${index}, 1)" 
                                        class="btn" 
                                        style="padding: 4px 8px; font-size: 0.8em; background: #f59e0b;"
                                        ${index === programExercisesBuffer.length - 1 ? 'disabled style="opacity: 0.3;"' : ''}>
                                    ⬇️
                                </button>
                            </div>
                            <div style="flex: 1; display: flex; align-items: center; gap: 10px;">
                                <span style="font-size: 1.5em;">😴</span>
                                <div>
                                    <div style="font-weight: bold; color: #92400e;">Repos</div>
                                    <div style="font-size: 0.85em; color: #78350f;">
                                        <input type="number" 
                                               value="${ex.duration || 60}" 
                                               onchange="updateProgramRestDuration(${index}, this.value)"
                                               min="15"
                                               max="300"
                                               step="15"
                                               style="width: 60px; padding: 4px; border: 1px solid #fed7aa; border-radius: 4px;">
                                        secondes
                                    </div>
                                </div>
                            </div>
                            <button onclick="removeProgramExercise(${index})" 
                                    class="btn" 
                                    style="padding: 8px 12px; background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%);">
                                🗑️
                            </button>
                        </div>
                    `;
                }
                // Regular exercise
                return `
                    <div style="display: flex; align-items: center; gap: 10px; padding: 12px; background: white; border-radius: 8px; margin-bottom: 8px; border: 2px solid #e0e0e0;">
                        <div style="display: flex; flex-direction: column; gap: 4px;">
                            <button onclick="moveProgramExercise(${index}, -1)" 
                                    class="btn" 
                                    style="padding: 4px 8px; font-size: 0.8em; background: #16a34a;"
                                    ${index === 0 ? 'disabled style="opacity: 0.3;"' : ''}>
                                ⬆️
                            </button>
                            <button onclick="moveProgramExercise(${index}, 1)" 
                                    class="btn" 
                                    style="padding: 4px 8px; font-size: 0.8em; background: #16a34a;"
                                    ${index === programExercisesBuffer.length - 1 ? 'disabled style="opacity: 0.3;"' : ''}>
                                ⬇️
                            </button>
                        </div>
                        <div style="flex: 1;">
                            <div style="font-weight: bold; color: #333;">${ex.name || 'Exercice'}</div>
                            <div style="font-size: 0.85em; color: #666;">${ex.muscle || 'Muscle inconnu'} • ${ex.difficulty || 'Intermédiaire'}</div>
                        </div>
                        <button onclick="removeProgramExercise(${index})" 
                                class="btn" 
                                style="padding: 8px 12px; background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%);">
                            🗑️
                        </button>
                    </div>
                `;
            }).join('');
        }
        
        // Move exercise up or down
        function moveProgramExercise(index, direction) {
            const newIndex = index + direction;
            if (newIndex < 0 || newIndex >= programExercisesBuffer.length) return;
            
            const temp = programExercisesBuffer[index];
            programExercisesBuffer[index] = programExercisesBuffer[newIndex];
            programExercisesBuffer[newIndex] = temp;
            
            updateProgramExercisesList();
        }
        
        // Remove exercise from program
        function removeProgramExercise(index) {
            programExercisesBuffer.splice(index, 1);
            updateProgramExercisesList();
        }
        
        // Add rest period to program
        function addRestToProgram() {
            programExercisesBuffer.push({
                type: 'rest',
                duration: 60
            });
            updateProgramExercisesList();
            speak('Repos ajouté');
        }
        
        // Update rest duration
        function updateProgramRestDuration(index, value) {
            const duration = parseInt(value) || 60;
            programExercisesBuffer[index].duration = Math.max(15, Math.min(300, duration));
        }
        
        // Show exercise picker
        function showExercisePicker() {
            tempSelectedExercises = [];
            document.getElementById('exercisePickerModal').classList.add('active');
            renderPickerExercises();
        }
        
        // Close exercise picker
        function closeExercisePicker() {
            document.getElementById('exercisePickerModal').classList.remove('active');
            tempSelectedExercises = [];
        }
        
        // Render picker exercises
        function renderPickerExercises() {
            const container = document.getElementById('pickerExercisesList');
            if (!container) return;
            
            const muscleFilter = document.getElementById('pickerMuscleFilter')?.value || '';
            const equipmentFilter = document.getElementById('pickerEquipmentFilter')?.value || '';
            const searchTerm = document.getElementById('pickerSearchInput')?.value.toLowerCase() || '';
            const blacklist = getExerciseBlacklist();
            
            // Filter exercises
            let exercises = exerciseDatabase.filter(ex => {
                if (ex.type !== 'exercise') return false;
                if (blacklist.includes(ex.name)) return false;
                if (muscleFilter && ex.muscle !== muscleFilter) return false;
                if (equipmentFilter && !ex.equipment.includes(equipmentFilter)) return false;
                if (searchTerm && !ex.name.toLowerCase().includes(searchTerm) && !ex.muscle.toLowerCase().includes(searchTerm)) return false;
                return true;
            });
            
            container.innerHTML = exercises.map(ex => {
                const isSelected = tempSelectedExercises.find(e => e.name === ex.name);
                const alreadyInProgram = programExercisesBuffer.find(e => e.name === ex.name);
                
                return `
                    <div onclick="togglePickerExercise(${JSON.stringify(ex).replace(/"/g, '&quot;')})" 
                         class="card" 
                         style="padding: 15px; cursor: pointer; border: 2px solid ${isSelected ? '#16a34a' : alreadyInProgram ? '#f59e0b' : '#e0e0e0'}; background: ${isSelected ? '#FFF3E0' : alreadyInProgram ? '#fef3c7' : 'white'}; transition: all 0.2s;">
                        <div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 8px;">
                            <div style="flex: 1;">
                                <div style="font-weight: bold; color: #333; margin-bottom: 4px;">${ex.name}</div>
                                <div style="font-size: 0.85em; color: #666;">${ex.muscle}</div>
                            </div>
                            <div style="font-size: 1.3em;">
                                ${isSelected ? '✅' : alreadyInProgram ? '⚠️' : ''}
                            </div>
                        </div>
                        <div style="font-size: 0.8em; color: #999;">
                            ${ex.difficulty} • ${ex.equipment.join(', ')}
                        </div>
                        ${alreadyInProgram ? '<div style="font-size: 0.75em; color: #f59e0b; margin-top: 4px;">Déjà dans le programme</div>' : ''}
                    </div>
                `;
            }).join('');
            
            // Show message if no exercises found
            if (exercises.length === 0) {
                container.innerHTML = `
                    <div style="text-align: center; padding: 40px; color: #666;">
                        <div style="font-size: 3em; margin-bottom: 15px;">🔍</div>
                        <h3 style="margin-bottom: 10px;">Aucun exercice trouvé</h3>
                        <p style="margin-bottom: 20px;">Essayez de :</p>
                        <ul style="text-align: left; display: inline-block; list-style: none; padding: 0;">
                            <li style="margin-bottom: 8px;">✓ Changer les filtres (muscle, équipement)</li>
                            <li style="margin-bottom: 8px;">✓ Vider la recherche</li>
                            <li style="margin-bottom: 8px;">✓ Sélectionner vos équipements (onglet Équipements)</li>
                        </ul>
                    </div>
                `;
            }
            
            document.getElementById('pickerSelectedCount').textContent = 
                `${tempSelectedExercises.length} exercice(s) sélectionné(s)`;
        }
        
        // Filter picker exercises
        function filterPickerExercises() {
            renderPickerExercises();
        }
        
        // Toggle exercise selection
        function togglePickerExercise(exerciseData) {
            const exercise = typeof exerciseData === 'string' ? JSON.parse(exerciseData) : exerciseData;
            const index = tempSelectedExercises.findIndex(e => e.name === exercise.name);
            
            if (index > -1) {
                tempSelectedExercises.splice(index, 1);
            } else {
                tempSelectedExercises.push(exercise);
            }
            
            renderPickerExercises();
        }
        
        // Confirm exercise selection
        function confirmExerciseSelection() {
            if (tempSelectedExercises.length === 0) {
                showAlert('Veuillez sélectionner au moins un exercice.', 'warning', 'Sélection requise');
                return;
            }
            
            // Check if auto-insert rest is enabled
            const autoInsertRest = document.getElementById('autoInsertRest')?.checked || false;
            const restDuration = parseInt(document.getElementById('autoRestDuration')?.value) || 60;
            
            // Add selected exercises to program buffer with optional rest periods
            tempSelectedExercises.forEach((ex, index) => {
                // Add the exercise (avoid duplicates)
                if (!programExercisesBuffer.find(e => e.name === ex.name && e.type === 'exercise')) {
                    programExercisesBuffer.push({
                        ...ex,
                        type: 'exercise',
                        duration: 60
                    });
                    
                    // Add rest period after exercise (except for the last one)
                    if (autoInsertRest && index < tempSelectedExercises.length - 1) {
                        programExercisesBuffer.push({
                            type: 'rest',
                            duration: restDuration
                        });
                    }
                }
            });
            
            updateProgramExercisesList();
            closeExercisePicker();
            
            const message = autoInsertRest 
                ? `${tempSelectedExercises.length} exercice(s) et ${tempSelectedExercises.length - 1} repos ajoutés`
                : `${tempSelectedExercises.length} exercice(s) ajouté(s)`;
            speak(message);
        }
        
        // Helper function to ensure exercise has all required properties
        function ensureExerciseProperties(exercise) {
            if (!exercise) return null;
            
            // If it's a rest period, ensure it's properly formatted
            if (exercise.type === 'rest' || exercise.isRest) {
                return {
                    name: "Repos",
                    duration: exercise.duration || 60,
                    isRest: true,
                    mode: 'timer',
                    type: 'rest'
                };
            }
            
            // Try to find full data in database
            const fullExercise = exerciseDatabase.find(ex => ex.name === exercise.name);
            
            if (fullExercise) {
                // Found in database - use complete data
                return {
                    ...fullExercise,
                    duration: exercise.duration || fullExercise.duration || 60
                };
            }
            
            // Not found in database - ensure minimum required properties
            return {
                name: exercise.name || "Exercice",
                muscle: exercise.muscle || "Corps entier",
                difficulty: exercise.difficulty || "Intermédiaire",
                duration: exercise.duration || 60,
                type: exercise.type || 'exercise',
                equipment: exercise.equipment || ["Poids du corps"],
                instructions: exercise.instructions || [
                    "Positionnez-vous correctement",
                    "Effectuez le mouvement avec contrôle",
                    "Respirez de manière régulière",
                    "Concentrez-vous sur la forme"
                ],
                tips: exercise.tips || "Concentrez-vous sur la bonne forme d'exécution",
                description: exercise.description || ""
            };
        }
        
        // Start program workout
        function startProgramWorkout(index) {
            const programs = getPrograms();
            const program = programs[index];
            
            if (!program || program.exercises.length === 0) {
                showAlert('Ce programme ne contient aucun exercice.', 'warning', 'Programme vide');
                return;
            }
            
            const workout = {
                name: program.name,
                type: 'program',
                exercises: []
            };
            
            // Build workout with full exercise data
            program.exercises.forEach((ex) => {
                const fullExercise = ensureExerciseProperties(ex);
                if (fullExercise) {
                    workout.exercises.push(fullExercise);
                }
            });
            
            currentWorkout = workout;
            currentExerciseIndex = 0;
            workoutStartTime = Date.now();
            
            // Show badge
            const badge = document.getElementById('workoutTypeBadge');
            if (badge) {
                badge.style.display = 'block';
                badge.innerHTML = `💪 ${program.name}`;
                badge.style.background = 'linear-gradient(135deg, #a855f7 0%, #9333ea 100%)';
            }
            
            switchTab('workouts');
            document.getElementById('workoutSelection').style.display = 'none';
            document.getElementById('exerciseView').classList.remove('hidden'); document.body.classList.add('in-session');
            
            renderExerciseProgressList();
            updateMusclesOverview();
            startExercise();
            
            speak(`Démarrage du programme ${program.name}`);
        }


        // ========== MULTI-PROFILE MANAGEMENT SYSTEM ==========
        
        let currentEditingProfileId = null;
        let selectedAvatar = '👤';
        
        // Get all profiles
        function getAllProfiles() {
            const saved = localStorage.getItem('allProfiles');
            if (!saved) {
                // First time - migrate existing data to default profile
                const defaultProfile = {
                    id: 'profile_' + Date.now(),
                    name: 'Mon Profil',
                    avatar: '👤',
                    createdAt: new Date().toISOString()
                };
                localStorage.setItem('allProfiles', JSON.stringify([defaultProfile]));
                localStorage.setItem('currentProfileId', defaultProfile.id);
                migrateExistingDataToProfile(defaultProfile.id);
                return [defaultProfile];
            }
            return JSON.parse(saved);
        }
        
        // Migrate existing data to a profile
        function migrateExistingDataToProfile(profileId) {
            const keysToMigrate = [
                'workoutHistory', 'myPrograms', 'weeklyPlan', 'userProfile',
                'exerciseBlacklist', 'userEquipment', 'selectedMuscles',
                'fitnessIndex', 'muscleRecoveryTracking', 'manualWeeklyPlan'
            ];
            
            keysToMigrate.forEach(key => {
                const data = localStorage.getItem(key);
                if (data) {
                    localStorage.setItem(`profile_${profileId}_${key}`, data);
                    // Keep original for backward compatibility
                }
            });
        }
        
        // Get current profile ID
        function getCurrentProfileId() {
            const id = localStorage.getItem('currentProfileId');
            if (!id) {
                const profiles = getAllProfiles();
                if (profiles.length > 0) {
                    localStorage.setItem('currentProfileId', profiles[0].id);
                    return profiles[0].id;
                }
                return null;
            }
            return id;
        }
        
        // Get current profile
        function getCurrentProfile() {
            const id = getCurrentProfileId();
            if (!id) return null;
            const profiles = getAllProfiles();
            return profiles.find(p => p.id === id);
        }
        
        // Save profiles
        function saveProfiles(profiles) {
            localStorage.setItem('allProfiles', JSON.stringify(profiles));
            renderAllProfilesLists();
        }
        
        // Get profile-specific data
        function getProfileData(profileId, key) {
            // Check profile-specific key first
            try {
            const profileKey = `profile_${profileId}_${key}`;
            const data = localStorage.getItem(profileKey);
            
            // If profile-specific data doesn't exist and we're on current profile,
            // check for legacy key
            if (!data && profileId === getCurrentProfileId()) {
                const legacyData = localStorage.getItem(key);
                if (legacyData) {
                    // Migrate to profile-specific
                    localStorage.setItem(profileKey, legacyData);
                    return legacyData;
                }
            }
            
            return data;
            } catch(e) { return null; }
        }
        
        // Set profile-specific data
        function setProfileData(profileId, key, data) {
            const profileKey = `profile_${profileId}_${key}`;
            if (data === null) {
                localStorage.removeItem(profileKey);
            } else {
                lsSet(profileKey, typeof data === 'string' ? data : JSON.stringify(data));
            }
            
            // Also update legacy key if current profile
            if (profileId === getCurrentProfileId()) {
                if (data === null) {
                    localStorage.removeItem(key);
                } else {
                    lsSet(key, typeof data === 'string' ? data : JSON.stringify(data));
                }
            }
        }
        
        // Switch to a profile
        function switchProfile(profileId) {
            // updateHomeStats appelé automatiquement après reload
            const profiles = getAllProfiles();
            const profile = profiles.find(p => p.id === profileId);
            
            if (!profile) {
                showAlert('Profil introuvable.', 'error', 'Erreur');
                return;
            }
            
            // Save current profile ID
            localStorage.setItem('currentProfileId', profileId);
            
            // Load all profile-specific data into main keys
            const keysToLoad = [
                'workoutHistory', 'myPrograms', 'weeklyPlan', 'userProfile',
                'exerciseBlacklist', 'userEquipment', 'selectedMuscles',
                'fitnessIndex', 'muscleRecoveryTracking', 'manualWeeklyPlan',
                'warmupEnabled', 'stretchEnabled', 'voiceEnabled', 'countdownVoiceEnabled',
                'darkMode', 'advancedMode'
            ];
            
            keysToLoad.forEach(key => {
                const data = getProfileData(profileId, key);
                if (data) {
                    localStorage.setItem(key, data);
                } else {
                    localStorage.removeItem(key);
                }
            });
            
            // Reload the app
            speak(`Profil ${profile.name} activé`);
            location.reload();
        }
        
        // Create new profile
        function createProfile(name, avatar) {
            if (!name || !name.trim()) {
                showAlert('Veuillez entrer un nom pour ce profil.', 'warning', 'Nom requis');
                return false;
            }
            
            const profiles = getAllProfiles();
            
            // Check for duplicate name
            if (profiles.some(p => p.name.toLowerCase() === name.trim().toLowerCase())) {
                showAlert('Un profil avec ce nom existe déjà.', 'warning', 'Nom déjà utilisé');
                return false;
            }
            
            const newProfile = {
                id: 'profile_' + Date.now(),
                name: name.trim(),
                avatar: avatar || '👤',
                createdAt: new Date().toISOString()
            };
            
            profiles.push(newProfile);
            saveProfiles(profiles);
            speak(`Profil ${newProfile.name} créé`);
            
            return newProfile;
        }
        
        // Delete profile
        function deleteProfile(profileId) {
            const profiles = getAllProfiles();
            const profile = profiles.find(p => p.id === profileId);
            
            if (!profile) return;
            
            // Can't delete if only one profile
            if (profiles.length === 1) {
                showAlert('Impossible de supprimer le dernier profil.', 'warning', 'Action impossible');
                return;
            }
            
            // Can't delete current profile
            if (profileId === getCurrentProfileId()) {
                showAlert('Basculez vers un autre profil avant de supprimer celui-ci.', 'warning', 'Profil actif');
                return;
            }
            
            showConfirm(`Supprimer le profil "${profile.name}" ? Toutes les données seront perdues.`, function() {
                const index = profiles.findIndex(p => p.id === profileId);
                profiles.splice(index, 1);
                saveProfiles(profiles);
                const keysToDelete = [
                    'workoutHistory', 'myPrograms', 'weeklyPlan', 'userProfile',
                    'exerciseBlacklist', 'userEquipment', 'selectedMuscles',
                    'fitnessIndex', 'muscleRecoveryTracking', 'manualWeeklyPlan'
                ];
                keysToDelete.forEach(key => { localStorage.removeItem(`profile_${profileId}_${key}`); });
                speak('Profil supprimé');
                showToast(`Profil "${profile.name}" supprimé`, 'success', 2000);
            }, null, { title: 'Supprimer le profil ?', icon: '🗑️', confirmLabel: 'Supprimer', danger: true });
        }
        
