        function checkDeloadSuggestion() {
            const history = getWorkoutHistory();
            if (history.length < 6) return null;
            const now = new Date();
            // Compter les semaines consécutives avec 3+ séances
            let consecutiveHardWeeks = 0;
            for (let w = 0; w < 6; w++) {
                const wStart = new Date(now); wStart.setDate(now.getDate() - (w+1)*7);
                const wEnd   = new Date(now); wEnd.setDate(now.getDate() - w*7);
                const count  = history.filter(h => { const d=new Date(h.date); return d>=wStart && d<wEnd; }).length;
                if (count >= 3) consecutiveHardWeeks++;
                else break;
            }
            if (consecutiveHardWeeks >= 3) {
                return { weeks: consecutiveHardWeeks, suggestion: 'Semaine de déload recommandée — réduire volume de 40-50%' };
            }
            return null;
        }

