        // ══════════════════════════════════════════════════════════
        //  SWAP EXERCISE — Remplacement pendant séance
        // ══════════════════════════════════════════════════════════

        function getEquipmentNames() {
            // Délégue à getSelectedEquipmentNames (source de vérité unique)
            if (typeof getSelectedEquipmentNames === 'function') {
                return getSelectedEquipmentNames();
            }
            // Fallback si appelé avant init
            const saved = localStorage.getItem('selectedEquipment');
            const ids = saved ? JSON.parse(saved) : ['bodyweight'];
            const map = {
                'bodyweight':'Poids du corps','dumbbells':'Haltères','barbell':'Barre',
                'resistance':'Élastique','kettlebell':'Kettlebell','machine':'Machine',
                'trx':'TRX','medicineball':'Medicine Ball','swissball':'Swiss Ball',
                'pullupbar':'Barres parallèles','bench':'Banc','jumpRope':'Corde à sauter'
            };
            return ids.map(id => map[id]).filter(Boolean);
        }

        function findSwapAlternatives(currentExercise) {
            if (!currentExercise || currentExercise.isRest || currentExercise.isInfo) return null;

            const currentName   = typeof currentExercise === 'string' ? currentExercise : currentExercise.name;
            const exFromDB      = exerciseDatabase.find(e => e.name === currentName);
            if (!exFromDB) return null;

            const targetMuscle  = exFromDB.muscle;
            const currentEquip  = exFromDB.equipment || [];
            const userEquip     = getEquipmentNames();
            const alreadyUsed   = new Set((currentWorkout ? currentWorkout.exercises : []).map(e => e.name || e));

            // Candidats : même muscle, exercice réel, pas l'exo actuel, pas déjà dans la séance
            const candidates = exerciseDatabase.filter(e =>
                e.muscle === targetMuscle &&
                e.type === 'exercise' &&
                e.name !== currentName &&
                !alreadyUsed.has(e.name)
            );

            // Score de correspondance équipement
            function equipScore(ex) {
                const exEquip = ex.equipment || [];
                // Exact match
                if (exEquip.every(eq => currentEquip.includes(eq))) return 3;
                // Sous-ensemble de l'équipement user
                if (exEquip.every(eq => userEquip.includes(eq))) return 2;
                // Au moins un en commun avec user
                if (exEquip.some(eq => userEquip.includes(eq))) return 1;
                return 0;
            }

            // Trier : score équip DESC, puis même difficulté en priorité
            const diffOrder = ['Débutant','Intermédiaire','Avancé'];
            const currentDiffIdx = diffOrder.indexOf(exFromDB.difficulty);

            candidates.sort((a, b) => {
                const sa = equipScore(a), sb = equipScore(b);
                if (sb !== sa) return sb - sa;
                // Même difficulté en priorité
                const da = Math.abs(diffOrder.indexOf(a.difficulty) - currentDiffIdx);
                const db = Math.abs(diffOrder.indexOf(b.difficulty) - currentDiffIdx);
                return da - db;
            });

            return {
                current: exFromDB,
                sameEquip:  candidates.filter(e => equipScore(e) === 3).slice(0, 5),
                userEquip:  candidates.filter(e => equipScore(e) === 2).slice(0, 4),
                otherEquip: candidates.filter(e => equipScore(e) <= 1).slice(0, 3),
            };
        }

        function triggerDropSet() {
            if (!currentWorkout) return;
            // Drop set: ajouter une mini-série supplémentaire avec 70% du poids actuel
            const ex = currentWorkout.exercises[currentExerciseIndex];
            if (!ex || ex.isRest || ex.isInfo) return;
            if (!isPaused) togglePause();
            const lastWeight = (() => {
                const inp = document.getElementById('quickWeightInput');
                return inp && inp.value ? parseFloat(inp.value) : null;
            })();
            const dropWeight = lastWeight ? Math.round(lastWeight * 0.7 * 2)/2 : null;
            const msg = dropWeight
                ? `⬇️ Drop Set — Réduire à ${dropWeight} ${useKg?'kg':'lbs'} et faire max reps jusqu'à l'échec !`
                : `⬇️ Drop Set — Réduire le poids de ~30% et faire max reps jusqu'à l'échec !`;
            showAlert(msg, 'info', 'Drop Set');
            togglePause(); // Reprendre
        }

        function triggerRestPause() {
            if (!currentWorkout) return;
            const ex = currentWorkout.exercises[currentExerciseIndex];
            if (!ex || ex.isRest || ex.isInfo) return;
            // Rest-Pause: 15s de repos puis continuer
            if (!isPaused) togglePause();
            let countdown = 15;
            showToast(`⏸ Rest-Pause — reprise dans ${countdown}s`, 'info', 1000);
            const ticker = setInterval(() => {
                countdown--;
                if (countdown <= 0) {
                    clearInterval(ticker);
                    togglePause();
                    vibrate([100,50,100]);
                    showToast('⏸ → Reprends maintenant !', 'success', 2000);
                } else if (countdown <= 5) {
                    showToast(`▶️ ${countdown}...`, 'info', 900);
                }
            }, 1000);
        }


        // Liste programme — toggle collapse
        let _progressListOpen = false;
        function toggleProgressList() {
            _progressListOpen = !_progressListOpen;
            const body = document.getElementById('progressListBody');
            const icon = document.getElementById('progressListToggleIcon');
            if (body) {
                if (_progressListOpen) {
                    body.classList.remove('collapsed');
                    body.style.maxHeight = body.scrollHeight + 200 + 'px';
                    if (icon) icon.style.transform = 'rotate(0deg)';
                } else {
                    body.style.maxHeight = '0';
                    body.classList.add('collapsed');
                    if (icon) icon.style.transform = 'rotate(180deg)';
                }
            }
        }

        // Initialiser la liste comme fermée sur mobile
        function initProgressList() {
            const body = document.getElementById('progressListBody');
            const icon = document.getElementById('progressListToggleIcon');
            if (window.innerWidth <= 640) {
                _progressListOpen = false;
                if (body) { body.style.maxHeight = '0'; body.classList.add('collapsed'); }
                if (icon) icon.style.transform = 'rotate(180deg)';
            } else {
                _progressListOpen = true;
                if (body) { body.style.maxHeight = '2000px'; }
            }
        }


        function toggleProgressListPopup() {
            const existing = document.getElementById('progressPopup');
            if (existing) { existing.remove(); return; }
            const el = document.createElement('div');
            el.id = 'progressPopup';
            el.style.cssText = 'position:fixed;inset:0;z-index:20001;background:rgba(0,0,0,0.6);display:flex;align-items:flex-end;';
            const card = document.getElementById('exerciseProgressListCard');
            const title = document.querySelector('#exerciseProgressListCard h4')?.textContent || 'Programme';
            const items = document.getElementById('exerciseProgressItems')?.innerHTML || '';
            const stats = document.querySelector('.progress-stats')?.outerHTML || '';
            el.innerHTML = `<div style="background:#0F1014;border-radius:20px 20px 0 0;padding:20px;width:100%;max-height:70vh;overflow-y:auto;padding-bottom:calc(20px + env(safe-area-inset-bottom,0px));">
                <div style="width:36px;height:3px;background:rgba(255,255,255,0.2);border-radius:99px;margin:0 auto 14px;"></div>
                <h4 style="margin:0 0 12px;color:white;">📋 Programme</h4>
                <div style="color:rgba(255,255,255,0.7);font-size:0.85em;">${stats}${items}</div>
                <button onclick="document.getElementById('progressPopup').remove()" style="margin-top:14px;width:100%;padding:12px;background:rgba(255,255,255,0.1);border:1px solid rgba(255,255,255,0.2);border-radius:10px;color:white;font-weight:700;cursor:pointer;">Fermer</button>
            </div>`;
            el.onclick = e => { if(e.target===el) el.remove(); };
            document.body.appendChild(el);
        }

        function toggleWorkoutOptionsPanel() {
            const panel = document.getElementById('workoutOptionsPanel');
            if (!panel) return;
            panel.style.display = panel.style.display === 'none' ? 'block' : 'none';
            // Fermer si clic ailleurs
            if (panel.style.display === 'block') {
                setTimeout(() => {
                    document.addEventListener('click', function closer(e) {
                        if (!panel.contains(e.target) && e.target.id !== 'workoutOptionsBtn') {
                            panel.style.display = 'none';
                        }
                        document.removeEventListener('click', closer);
                    });
                }, 50);
            }
        }

        function toggleMobileInstructions() {
            const box = document.getElementById('exerciseDescriptionBox');
            if (!box) return;
            const visible = box.style.display !== 'none' && box.style.display !== '';
            box.style.display = visible ? 'none' : 'block';
        }

        function toggleMobileProgram() {
            const card = document.getElementById('exerciseProgressListCard');
            if (!card) return;
            const visible = card.style.display !== 'none';
            card.style.display = visible ? 'none' : 'block';
            const btn = document.getElementById('showProgramBtn');
            if (btn) btn.textContent = visible ? '📋 Programme de la séance' : '✖️ Fermer programme';
        }

        function initMobileWorkoutUI() {
            const isMobile = window.innerWidth <= 640;
            const optBtn   = document.getElementById('workoutOptionsBtn');
            const progBtn  = document.getElementById('showProgramBtn');
            if (optBtn)  optBtn.style.display  = isMobile ? 'flex' : 'none';
            if (progBtn) progBtn.style.display  = isMobile ? 'block' : 'none';
        }

        function openWorkoutYoutube() {
            if (!currentWorkout) return;
            const ex = currentWorkout.exercises[currentExerciseIndex];
            if (!ex || ex.isRest || ex.isInfo) return;
            // Mettre en pause automatiquement
            if (!isPaused) togglePause();
            openYouTubeVideo(null, ex.name);
        }

        function goToPreviousExercise() {
            if (setRestInterval) { clearInterval(setRestInterval); setRestInterval = null; }
            hideGlobalRestBanner();
            if (!currentWorkout || currentExerciseIndex <= 0) {
                showToast('Déjà au premier exercice', 'info', 1500);
                return;
            }
            clearInterval(timerInterval);
            currentExerciseIndex--;

            // Remonter en sautant les repos ET les panneaux d'info
            while (currentExerciseIndex > 0 && 
                   (currentWorkout.exercises[currentExerciseIndex].isRest || 
                    currentWorkout.exercises[currentExerciseIndex].isInfo)) {
                currentExerciseIndex--;
            }

            // Si on atterrit encore sur un isRest/isInfo à l'index 0 — rester au 1er exercice réel
            if (currentWorkout.exercises[currentExerciseIndex].isRest ||
                currentWorkout.exercises[currentExerciseIndex].isInfo) {
                showToast('Déjà au premier exercice', 'info', 1500);
                currentExerciseIndex = 0;
            }

            isPaused = false;
            startExercise();
            showToast('↩️ Exercice précédent', 'info', 1200);
        }

        function showMachineOccupiedSwap() {
            if (!currentWorkout) return;
            const exercise = currentWorkout.exercises[currentExerciseIndex];
            if (!exercise || exercise.isRest || exercise.isInfo) return;
            // Pause auto
            if (!isPaused) { isPaused = true; const pb = document.getElementById('pauseBtn'); if(pb) pb.innerHTML = '▶️ Reprendre'; }
            // Chercher alternatifs SANS cette machine (même muscle, équipement différent)
            const sameMuscle = exerciseDatabase.filter(ex =>
                ex.type === 'exercise' &&
                ex.muscle === exercise.muscle &&
                ex.name !== exercise.name &&
                !ex.name.includes(exercise.name) &&
                !currentWorkout.exercises.some(e => e._baseName === ex.name || e.name === ex.name)
            );
            // Trier: poids du corps en premier (pas besoin de machine)
            const bodyFirst = [
                ...sameMuscle.filter(ex => (ex.equipment||[]).includes('Poids du corps')),
                ...sameMuscle.filter(ex => !(ex.equipment||[]).includes('Poids du corps'))
            ].slice(0, 8);

            const overlay = document.createElement('div');
            overlay.id = 'occupiedOverlay';
            overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:10300;display:flex;align-items:flex-end;justify-content:center;';
            overlay.innerHTML = `
                <div style="background:white;border-radius:22px 22px 0 0;padding:22px 18px;width:100%;max-width:480px;max-height:75vh;overflow-y:auto;box-shadow:0 -8px 40px rgba(0,0,0,0.25);">
                    <div style="text-align:center;margin-bottom:14px;">
                        <div style="font-size:1.5em;">🚫</div>
                        <h3 style="margin:6px 0 4px;color:#0F1014;">Machine occupée</h3>
                        <p style="margin:0;font-size:0.85em;color:#6b7280;">Alternatives pour <strong>${exercise._baseName || exercise.name}</strong> (${exercise.muscle}) :</p>
                    </div>
                    ${bodyFirst.length === 0
                        ? '<p style="text-align:center;color:#6b7280;padding:20px;">Aucune alternative trouvée</p>'
                        : bodyFirst.map(alt => `
                        <div onclick="confirmOccupiedSwap('${alt.name.replace(/'/g,"\'")}');document.getElementById('occupiedOverlay').remove();"
                            style="padding:12px 14px;border:2px solid #e5e7eb;border-radius:14px;margin-bottom:8px;cursor:pointer;display:flex;align-items:center;gap:12px;transition:all 0.15s;"
                            onmouseover="this.style.borderColor='#16a34a'" onmouseout="this.style.borderColor='#e5e7eb'">
                            <div style="flex:1;">
                                <div style="font-weight:700;color:#0F1014;font-size:0.92em;">${alt.name}</div>
                                <div style="font-size:0.75em;color:#6b7280;margin-top:2px;">${(alt.equipment||[]).join(' · ')} · ${alt.difficulty||''}</div>
                            </div>
                            <div style="color:#16a34a;font-size:1.2em;">→</div>
                        </div>`).join('')
                    }
                    <button onclick="document.getElementById('occupiedOverlay').remove();if(!isPaused)togglePause();"
                        class="btn btn-secondary" style="width:100%;margin-top:6px;">Annuler — Attendre la machine</button>
                </div>`;
            document.body.appendChild(overlay);
        }

        function confirmOccupiedSwap(exerciseName) {
            const dbEx = exerciseDatabase.find(e => e.name === exerciseName);
            if (!dbEx || !currentWorkout) return;
            const ex = currentWorkout.exercises[currentExerciseIndex];
            const orig = ex._baseName || ex.name;
            currentWorkout.exercises[currentExerciseIndex] = {
                ...dbEx,
                _swappedFrom: orig,
                _occupiedSwap: true,
                mode: ex.mode || dbEx.mode,
                duration: ex.duration || 45
            };
            isPaused = false;
            startExercise();
            showToast(`🔄 ${orig} → ${exerciseName}`, 'success', 2500);
        }

        function showSwapExercise() {
            if (!currentWorkout) return;
            const exercise = currentWorkout.exercises[currentExerciseIndex];
            if (!exercise || exercise.isRest || exercise.isInfo) return;

            // Pause auto
            if (!isPaused) { isPaused = true; document.getElementById('pauseBtn').innerHTML = '▶️ Reprendre'; }

            const result = findSwapAlternatives(exercise);
            if (!result) {
                showAlert('Aucune alternative trouvée pour cet exercice.', 'info', 'Remplacement impossible');
                return;
            }

            // Update modal title
            document.getElementById('swapModalTitle').textContent = '🔄 Remplacer : ' + result.current.name;
            document.getElementById('swapModalSub').textContent =
                '💪 ' + result.current.muscle + ' · alternatives classées par équipement disponible';

            // Build content
            const box = document.getElementById('swapModalContent');
            let html = '';

            function renderSection(title, badge, badgeClass, items) {
                if (!items.length) return '';
                let s = '<div class="swap-section-title">' + title + '</div>';
                items.forEach(ex => {
                    const svg = getExerciseSVG(ex.name, ex.muscle, 'start');
                    const diffColors = {'Débutant':'#10b981','Intermédiaire':'#f59e0b','Avancé':'#ef4444'};
                    const dc = diffColors[ex.difficulty] || '#6b7280';
                    s += `<div class="swap-card" onclick="confirmSwapExercise('${ex.name.replace(/'/g,"\\'")}')">
                        <div class="swap-card-img">${svg}</div>
                        <div class="swap-card-info">
                            <div class="swap-card-name">${ex.name}</div>
                            <div class="swap-card-meta">
                                <span style="color:${dc};font-weight:700;">${ex.difficulty}</span>
                                <span>🏋️ ${(ex.equipment||[]).join(', ')}</span>
                            </div>
                            <div style="margin-top:5px;">
                                <span class="swap-badge ${badgeClass}">${badge}</span>
                            </div>
                        </div>
                        <div style="color:#d1d5db;font-size:1.3em;">›</div>
                    </div>`;
                });
                return s;
            }

            html += renderSection('✅ Même équipement que l\'exercice actuel', 'Équipement identique', 'swap-badge-same', result.sameEquip);
            html += renderSection('🎒 Avec ton équipement disponible', 'Équipement différent', 'swap-badge-other', result.userEquip);
            html += renderSection('📦 Autres alternatives (équipement requis)', 'Équipement à prévoir', 'swap-badge-diff', result.otherEquip);

            if (!html) {
                html = '<div class="swap-empty"><div style="font-size:2.5em;margin-bottom:10px;">🤷</div><div>Aucune alternative disponible pour ce muscle.</div></div>';
            }

            box.innerHTML = html;
            document.getElementById('swapModal').classList.add('active');
        }

        function closeSwapModal() {
            document.getElementById('swapModal').classList.remove('active');
        }

        function confirmSwapExercise(newExName) {
            closeSwapModal();

            const newExFromDB = exerciseDatabase.find(e => e.name === newExName);
            if (!newExFromDB || !currentWorkout) return;

            const oldEx   = currentWorkout.exercises[currentExerciseIndex];
            const oldName = oldEx.name || oldEx;

            // Remplacer dans le tableau de la séance
            currentWorkout.exercises[currentExerciseIndex] = {
                ...oldEx,
                name:         newExFromDB.name,
                duration:     newExFromDB.duration || oldEx.duration || 60,
                muscle:       newExFromDB.muscle,
                difficulty:   newExFromDB.difficulty,
                instructions: newExFromDB.instructions,
                tips:         newExFromDB.tips,
                equipment:    newExFromDB.equipment,
                mode:         oldEx.mode || 'timer',
                isRest:       false,
                isInfo:       false,
                _swappedFrom: oldName
            };

            showToast('🔄 "' + newExName + '" remplace "' + oldName + '"', 'success', 3500);

            // Recharger l'exercice courant
            clearInterval(timerInterval);
            startExercise();
        }

        // ══════════════════════════════════════════════════════════
        //  PWA — Service Worker + Bannière d'installation
        // ══════════════════════════════════════════════════════════

        // ── NAV COLLAPSIBLE MOBILE ────────────────────────────────
        function toggleMobileNav() {
            const nav = document.getElementById('mobileNavBar');
            const btn = document.getElementById('navCollapseBtn');
            if (!nav) return;
            const collapsed = nav.classList.toggle('nav-collapsed');
            if (btn) btn.innerHTML = collapsed ? '⌄' : '⌃';
            localStorage.setItem('navCollapsed', collapsed);
        }
        function initMobileNav() {
            if (window.innerWidth > 640) return;
            const nav = document.getElementById('mobileNavBar');
            const btn = document.getElementById('navCollapseBtn');
            if (!nav || !btn) return;
            // Restore saved state
            const saved = localStorage.getItem('navCollapsed') === 'true';
            if (saved) { nav.classList.add('nav-collapsed'); btn.innerHTML = '⌄'; }
            // Auto-expand when tab changes
        }
        // Auto-expand nav when switching tabs on mobile
        const _origSwitchTab = typeof switchTab === 'function' ? switchTab : null;

        // ── Service Worker robuste — offline-first ─────────────────
        function registerServiceWorker() {
            if (!('serviceWorker' in navigator)) return;

            const CACHE_VER = 'fitpro-v3';
            const swCode = `
const CACHE = '${CACHE_VER}';

// ── Install : mise en cache de la page principale ──────────
self.addEventListener('install', e => {
    e.waitUntil(
        caches.open(CACHE)
            .then(c => c.addAll([location.href]))
            .then(() => self.skipWaiting())
            .catch(() => self.skipWaiting()) // Ne jamais bloquer l'install
    );
});

// ── Activate : purge des anciens caches ───────────────────
self.addEventListener('activate', e => {
    e.waitUntil(
        caches.keys()
            .then(keys => Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k))))
            .then(() => self.clients.claim())
    );
});

// ── Fetch : Stale-While-Revalidate pour navigation ────────
self.addEventListener('fetch', e => {
    const req = e.request;

    // Ignorer les requêtes non-GET et les API externes
    if (req.method !== 'GET') return;
    if (!req.url.startsWith(self.location.origin)) return;

    e.respondWith(
        caches.open(CACHE).then(cache => {
            return cache.match(req).then(cached => {
                // Lancer la mise à jour en arrière-plan
                const fetchPromise = fetch(req).then(fresh => {
                    if (fresh && fresh.status === 200) {
                        cache.put(req, fresh.clone());
                    }
                    return fresh;
                }).catch(() => null);

                // Retourner immédiatement le cache si disponible (offline-first)
                return cached || fetchPromise || new Response(
                    '<h1>Mode hors-ligne</h1><p>L\'application sera disponible dès le retour en ligne.</p>',
                    { headers: { 'Content-Type': 'text/html' } }
                );
            });
        })
    );
});

// ── Message : forcer mise à jour du cache ────────────────
self.addEventListener('message', e => {
    if (e.data === 'SKIP_WAITING') self.skipWaiting();
});
`;
            const blob = new Blob([swCode], { type: 'application/javascript' });
            const swUrl = URL.createObjectURL(blob);
            navigator.serviceWorker.register(swUrl)
                .then(reg => {
                    // Vérifier si une mise à jour est disponible
                    reg.addEventListener('updatefound', () => {
                        const newSW = reg.installing;
                        if (newSW) {
                            newSW.addEventListener('statechange', () => {
                                if (newSW.state === 'installed' && navigator.serviceWorker.controller) {
                                    showToast('🔄 Mise à jour disponible — rechargez la page', 'info', 6000);
                                }
                            });
                        }
                    });
                })
                .catch(() => { /* SW non supporté dans ce contexte */ });
        }

        // ── Bannière d'installation ────────────────────────────────
        let deferredInstallPrompt = null;

        function initPWAInstall() {
            // Capturer l'événement beforeinstallprompt
            window.addEventListener('beforeinstallprompt', e => {
                e.preventDefault();
                deferredInstallPrompt = e;
                showInstallBanner();
            });

            // Cacher la bannière si déjà installée
            window.addEventListener('appinstalled', () => {
                hideInstallBanner();
                showToast('🎉 FitPro Elite installé sur votre appareil !', 'success', 4000);
            });

            // Sur iOS : pas de beforeinstallprompt — montrer guide manuel
            const isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent);
            const isStandalone = window.navigator.standalone;
            const dismissed = localStorage.getItem('pwaBannerDismissed');
            if (isIOS && !isStandalone && !dismissed) {
                setTimeout(() => showIOSBanner(), 2500);
            }
        }

        function showInstallBanner() {
            const dismissed = localStorage.getItem('pwaBannerDismissed');
            if (dismissed) return;
            const banner = document.getElementById('pwaInstallBanner');
            if (banner) { banner.style.display = 'flex'; }
        }

        function hideInstallBanner() {
            const banner = document.getElementById('pwaInstallBanner');
            if (banner) banner.style.display = 'none';
        }

        function installPWA() {
            if (!deferredInstallPrompt) return;
            deferredInstallPrompt.prompt();
            deferredInstallPrompt.userChoice.then(result => {
                if (result.outcome === 'accepted') {
                    showToast('🎉 Installation en cours…', 'success', 3000);
                }
                deferredInstallPrompt = null;
                hideInstallBanner();
            });
        }

        function dismissInstallBanner() {
            hideInstallBanner();
            localStorage.setItem('pwaBannerDismissed', '1');
        }

        function showIOSBanner() {
            const dismissed = localStorage.getItem('pwaBannerDismissed');
            if (dismissed) return;
            const banner = document.getElementById('pwaIOSBanner');
            if (banner) banner.style.display = 'flex';
        }

        function dismissIOSBanner() {
            const banner = document.getElementById('pwaIOSBanner');
            if (banner) banner.style.display = 'none';
            localStorage.setItem('pwaBannerDismissed', '1');
        }

        // ── localStorage sécurisé avec auto-purge ─────────────────
        const _lsOrig = { get: localStorage.getItem.bind(localStorage), set: localStorage.setItem.bind(localStorage), remove: localStorage.removeItem.bind(localStorage) };
        function lsGet(key) { try { return _lsOrig.get(key); } catch(e) { return null; } }

        function _lsPurge() {
            // 1. Historique séances — garder 100 max, retirer workoutData des anciennes
            const profileId = getCurrentProfileId?.() || null;
            const histKey = profileId ? `profile_${profileId}_workoutHistory` : 'workoutHistory';
            try {
                const hist = JSON.parse(_lsOrig.get(histKey) || '[]');
                if (hist.length > 100) {
                    // Garder 100 entrées; supprimer workoutData des 50+ anciennes pour libérer de l'espace
                    hist.slice(50).forEach(h => delete h.workoutData);
                    const pruned = hist.slice(0, 100);
                    _lsOrig.set(histKey, JSON.stringify(pruned));
                }
            } catch(e2) {}

            // 2. Progression exercices — retenir seulement les 20 dernières perf par exercice
            try {
                const progKey = 'exerciseProgression';
                const prog = JSON.parse(_lsOrig.get(progKey) || '{}');
                let changed = false;
                Object.keys(prog).forEach(ex => {
                    if (prog[ex].history && prog[ex].history.length > 20) {
                        prog[ex].history = prog[ex].history.slice(-20);
                        changed = true;
                    }
                });
                if (changed) _lsOrig.set(progKey, JSON.stringify(prog));
            } catch(e3) {}

            // 3. Performance exercices — idem
            try {
                const perfKey = 'exercisePerformance';
                const perf = JSON.parse(_lsOrig.get(perfKey) || '{}');
                let changed = false;
                Object.keys(perf).forEach(ex => {
                    if (perf[ex].history && perf[ex].history.length > 20) {
                        perf[ex].history = perf[ex].history.slice(-20);
                        changed = true;
                    }
                });
                if (changed) _lsOrig.set(perfKey, JSON.stringify(perf));
            } catch(e4) {}
        }

        function lsSet(key, val) {
            try {
                _lsOrig.set(key, val);
                return true;
            } catch(e) {
                if (e.name === 'QuotaExceededError' || e.code === 22) {
                    // Auto-purge puis réessayer
                    try {
                        _lsPurge();
                        _lsOrig.set(key, val);
                        return true;
                    } catch(e2) {
                        showToast('⚠️ Stockage plein — nettoyage en cours…', 'warning', 4000);
                        // Purge agressive : vider l'historique ancien
                        try {
                            const histKey = 'workoutHistory';
                            const hist = JSON.parse(_lsOrig.get(histKey) || '[]');
                            const stripped = hist.slice(0, 30).map(h => { const c = {...h}; delete c.workoutData; return c; });
                            _lsOrig.set(histKey, JSON.stringify(stripped));
                            _lsOrig.set(key, val);
                            return true;
                        } catch(e3) {}
                    }
                }
                return false;
            }
        }

        // Purge préventive au démarrage (si > 80% quota estimé)
        function lsCheckQuota() {
            try {
                let total = 0;
                for (let i = 0; i < localStorage.length; i++) {
                    const k = localStorage.key(i);
                    total += (k.length + (localStorage.getItem(k) || '').length) * 2; // UTF-16
                }
                const MB = total / 1024 / 1024;
                if (MB > 4) { // > 4 MB sur quota 5 MB → purger
                    _lsPurge();
                    showToast(`ℹ️ Nettoyage automatique du stockage (${MB.toFixed(1)} MB)`, 'info', 3000);
                }
            } catch(e) {}
        }

        // ── Helper DOM null-safe ───────────────────────────────────
        // $el(id) — getElementById avec guard silencieux
        function $el(id) { return document.getElementById(id) || null; }

        // $set(id, prop, val) — assign une propriété sans crasher
        function $set(id, prop, val) {
            const el = $el(id);
            if (!el) return;
            const parts = prop.split('.');
            let obj = el;
            for (let i = 0; i < parts.length - 1; i++) {
                if (obj == null) return;
                obj = obj[parts[i]];
            }
            if (obj != null) obj[parts[parts.length - 1]] = val;
        }

        // $html(id, html) — innerHTML null-safe
        function $html(id, html) { const e = $el(id); if (e) e.innerHTML = html; }

        // $text(id, txt) — textContent null-safe
        function $text(id, txt) { const e = $el(id); if (e) e.textContent = txt; }

        // $show(id) / $hide(id) — display null-safe
        function $show(id, display='') { const e = $el(id); if (e) e.style.display = display || ''; }
        function $hide(id) { const e = $el(id); if (e) e.style.display = 'none'; }

        // ── Skeleton loading helper ────────────────────────────────
        function showSkeleton(containerId, rows = 3, type = 'card') {
            const el = $el(containerId);
            if (!el) return;
            if (type === 'card') {
                el.innerHTML = Array(rows).fill(
                    `<div class="skeleton skeleton-card"></div>`
                ).join('');
            } else {
                el.innerHTML = `
                    <div class="card" style="padding:18px;">
                        <div class="skeleton skeleton-title"></div>
                        ${Array(rows).fill(`<div class="skeleton skeleton-row"></div><div class="skeleton skeleton-row short"></div>`).join('')}
                    </div>`;
            }
        }

        // ── Helper: widget dernière performance ────────────────────
        function _buildLastPerfWidget(lastPerf, exerciseName) {
            if (!lastPerf) {
                return `<div style="background:rgba(245,158,11,0.1);padding:13px 16px;border-radius:14px;margin:14px 0;border:1px solid rgba(245,158,11,0.3);display:flex;align-items:center;gap:12px;">
                    <div style="font-size:1.5em;">✨</div>
                    <div>
                        <div style="color:#fbbf24;font-weight:700;font-size:0.9em;">Première fois pour cet exercice</div>
                        <div style="color:#94a3b8;font-size:0.8em;margin-top:2px;">Enregistrez votre performance pour suivre vos progrès !</div>
                    </div>
                </div>`;
            }
            const allPerfs = (typeof getExerciseHistory === 'function') ? getExerciseHistory(exerciseName) : [];
            const prev = allPerfs && allPerfs.length >= 2 ? allPerfs[allPerfs.length - 2] : null;
            let trend = '';
            if (prev && lastPerf.weight && prev.weight) {
                trend = lastPerf.weight > prev.weight
                    ? ' <span style="color:#4ade80;font-size:0.75em;">▲</span>'
                    : lastPerf.weight < prev.weight
                    ? ' <span style="color:#f87171;font-size:0.75em;">▼</span>' : '';
            }
            const reuseClick = [
                "var ri=document.getElementById('repsInput');if(ri)ri.value='" + lastPerf.reps + "';",
                lastPerf.weight ? "var wi=document.getElementById('weightInput');if(wi)wi.value='" + lastPerf.weight + "';" : '',
                "if(typeof playRepTick==='function')playRepTick();"
            ].join('');
            return `<div style="background:rgba(34,197,94,0.1);padding:14px 16px;border-radius:14px;margin:14px 0;border:1px solid rgba(34,197,94,0.3);display:flex;align-items:center;gap:14px;">
                <div style="font-size:1.8em;flex-shrink:0;">📊</div>
                <div style="flex:1;">
                    <div style="font-size:0.72em;color:#6b7280;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Dernière fois</div>
                    <div style="font-size:1.2em;font-weight:800;color:#4ade80;">${lastPerf.reps} reps${lastPerf.weight ? ' × ' + lastPerf.weight + ' kg' + trend : ''}</div>
                    <div style="font-size:0.75em;color:#6b7280;margin-top:2px;">${new Date(lastPerf.date).toLocaleDateString('fr-FR',{day:'numeric',month:'short'})}</div>
                </div>
                <div style="font-size:0.72em;color:#34d399;background:rgba(34,197,94,0.15);border:1px solid rgba(34,197,94,0.3);border-radius:8px;padding:5px 10px;font-weight:700;cursor:pointer;" onclick="${reuseClick}">↺ Réutiliser</div>
            </div>`;
        }

        // ── Ajuster le repos pour un exercice précis ───────────────
        function showRestTimeAdjuster() {
            const ex = currentWorkout && currentWorkout.exercises[currentExerciseIndex];
            if (!ex || ex.isRest) return;
            const exName = ex._baseName || ex.name;
            const current = (exerciseRestOverrides && exerciseRestOverrides[exName]) || globalRestSeconds || 90;
            const opts = [30, 45, 60, 90, 120, 150, 180];

            // Remove any existing overlay
            document.getElementById('_restAdjOverlay')?.remove();

            const ov = document.createElement('div');
            ov.id = '_restAdjOverlay';
            ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.75);z-index:10200;display:flex;align-items:flex-end;justify-content:center;';

            const btnHTML = opts.map(s => {
                const isActive = s === current;
                return `<button
                    data-secs="${s}"
                    style="flex:1;min-width:60px;padding:12px 6px;border-radius:12px;
                        border:2px solid ${isActive ? '#16a34a' : '#2E2F35'};
                        background:${isActive ? 'rgba(22,163,74,0.2)' : '#222328'};
                        color:${isActive ? '#4ade80' : '#e2e8f0'};
                        font-weight:700;cursor:pointer;font-size:0.9em;"
                    onclick="document.getElementById('_restAdjOverlay').__pickRest(${s})"
                >${s}s</button>`;
            }).join('');

            ov.innerHTML = `
                <div style="background:#1A1B20;border-radius:22px 22px 0 0;padding:22px 20px;width:100%;max-width:480px;border-top:1px solid #252830;">
                    <div style="width:40px;height:4px;background:#2E2F35;border-radius:99px;margin:0 auto 16px;"></div>
                    <h3 style="margin:0 0 4px;color:#e2e8f0;font-size:1.1em;">⏱️ Repos après cet exercice</h3>
                    <p style="margin:0 0 14px;color:#94a3b8;font-size:0.82em;word-break:break-word;">${exName.replace(/'/g,'&#39;')}</p>
                    <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:18px;">${btnHTML}</div>
                    <button onclick="document.getElementById('_restAdjOverlay').remove()"
                        style="width:100%;padding:12px;border-radius:12px;border:none;background:rgba(255,255,255,0.06);color:#94a3b8;cursor:pointer;font-size:0.9em;">
                        Annuler
                    </button>
                </div>`;

            // Attach the handler as a DOM property to avoid inline-string escaping issues
            ov.__pickRest = function(secs) {
                exerciseRestOverrides[exName] = secs;
                lsSet('fitproExRestOverrides', JSON.stringify(exerciseRestOverrides));
                ov.remove();
                showToast('⏱️ Repos ' + secs + 's — ' + exName, 'success', 2500);
            };

            // Close on backdrop tap
            ov.addEventListener('click', function(e) { if (e.target === ov) ov.remove(); });

            document.body.appendChild(ov);
        }

