        function getCelebDailyTip(celebId, dayOfWeek) {
            const tips = CELEBRITY_DAILY_TIPS[celebId] || DEFAULT_DAILY_TIPS;
            return { ...tips[dayOfWeek % tips.length], isQuote: false };
        }

        // Comparer les performances utilisateur vs les benchmarks de la star
        function buildCelebStatComparison(celebId, sessionExercises) {
            const program = CELEBRITY_PROGRAMS.find(p => p.id === celebId);
            if (!program) return '';
            const benchmarks = CELEBRITY_BENCHMARK[celebId];
            if (!benchmarks) return '';

            // Récupérer les meilleures perfs de l'utilisateur
            let perfs = {};
            try { perfs = JSON.parse(localStorage.getItem('exercisePerformance') || '{}'); } catch(e) {}

            const comparisons = [];
            for (const [exName, starWeight] of Object.entries(benchmarks)) {
                if (starWeight === null) continue; // Exercice au poids du corps
                const userPerf = perfs[exName];
                const userBest = userPerf ? (useKg ? userPerf.maxWeight : Math.round(userPerf.maxWeight * 2.205)) : null;
                if (!userBest || userBest <= 0) continue;

                const ratio = Math.min(100, Math.round(userBest / starWeight * 100));
                const barColor = ratio >= 80 ? '#4ade80' : ratio >= 50 ? '#f59e0b' : '#16a34a';
                const label = ratio >= 100 ? '🏆 Niveau star !' : ratio >= 80 ? '🔥 Presque là !' : ratio >= 50 ? '📈 En progression' : '💪 À travailler';
                comparisons.push({ exName, starWeight, userBest, ratio, barColor, label });
            }

            if (comparisons.length === 0) {
                return `<div style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);border-radius:14px;padding:14px 16px;text-align:center;">
                    <div style="font-size:1.5em;margin-bottom:6px;">${program.emoji}</div>
                    <div style="font-size:0.82em;color:#94a3b8;">Complète plus de séances pour voir ta comparaison avec ${program.nickname} !</div>
                </div>`;
            }

            const rows = comparisons.slice(0, 4).map(c => `
                <div style="margin-bottom:10px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">
                        <div style="font-size:0.78em;color:#e2e8f0;font-weight:600;">${c.exName}</div>
                        <div style="font-size:0.7em;color:${c.barColor};font-weight:800;">${c.label}</div>
                    </div>
                    <div style="background:rgba(255,255,255,0.08);border-radius:99px;height:8px;overflow:hidden;">
                        <div style="height:100%;background:${c.barColor};border-radius:99px;width:${c.ratio}%;transition:width 1s ease;"></div>
                    </div>
                    <div style="display:flex;justify-content:space-between;font-size:0.65em;color:#6b7280;margin-top:3px;">
                        <span>Toi : ${c.userBest} ${useKg?'kg':'lbs'}</span>
                        <span>${program.nickname} : ${c.starWeight} kg (${c.ratio}%)</span>
                    </div>
                </div>`).join('');

            return `<div style="background:linear-gradient(135deg,${program.color}15,${program.color}08);border:1px solid ${program.color}40;border-radius:14px;padding:14px 16px;">
                <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;">
                    <div style="font-size:1.6em;">${program.emoji}</div>
                    <div>
                        <div style="font-size:0.65em;color:${program.color};font-weight:800;text-transform:uppercase;letter-spacing:1px;">Comparaison avec ${program.nickname}</div>
                        <div style="font-size:0.78em;color:#94a3b8;">Tes meilleures performances vs sa référence</div>
                    </div>
                </div>
                ${rows}
            </div>`;
        }

        // ── ONBOARDING — 4 écrans ─────────────────────────────────────
        function showOnboarding() {
            if (localStorage.getItem('fitproOnboardingDone') === '1') return;
            document.getElementById('_onboardingOverlay')?.remove();

            const screens = [
                {
                    emoji: '🏋️', title: 'Bienvenue dans FitPro Elite',
                    text: 'Ton coach fitness personnel. Lance une séance IA en 1 tap depuis l\'onglet <strong style="color:#16a34a;">Séances</strong> — l\'IA choisit les exercices selon tes muscles, ton niveau et ton historique.',
                    btn: 'Suivant →'
                },
                {
                    emoji: '📅', title: 'Ton plan hebdomadaire',
                    text: 'L\'onglet <strong style="color:#16a34a;">Accueil</strong> affiche ton planning de la semaine. Il s\'adapte automatiquement à tes séances complétées et à ton niveau de fatigue.',
                    btn: 'Suivant →'
                },
                {
                    emoji: '🎮', title: 'Gagne de l\'XP en t\'entraînant',
                    text: 'Active le <strong style="color:#16a34a;">Mode Jeu</strong> dans Réglages. Chaque série complétée donne de l\'XP, fait monter tes muscles de niveau et débloque des compétences.',
                    btn: 'Suivant →'
                },
                {
                    emoji: '🌟', title: 'Entraîne-toi comme une star',
                    text: 'Dans <strong style="color:#16a34a;">Séances → Programmes Stars</strong>, choisis une personnalité (The Rock, CBum, Beyoncé…). Son plan hebdo et ses exercices s\'activent automatiquement.',
                    btn: 'C\'est parti ! 🚀'
                },
            ];

            let current = 0;

            const ov = document.createElement('div');
            ov.id = '_onboardingOverlay';
            ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.9);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';

            function render(idx) {
                const s = screens[idx];
                const isLast = idx === screens.length - 1;
                ov.innerHTML = `
                    <div style="background:#0D0D0D;border-radius:24px 24px 0 0;padding:30px 24px 36px;width:100%;max-width:480px;border-top:3px solid #16a34a;">
                        <!-- Indicateurs -->
                        <div style="display:flex;gap:6px;justify-content:center;margin-bottom:28px;">
                            ${screens.map((_,i) => `<div style="height:4px;border-radius:99px;flex:1;background:${i<=idx?'#16a34a':'rgba(255,255,255,0.15)'}; transition:background 0.3s;"></div>`).join('')}
                        </div>
                        <div style="text-align:center;margin-bottom:24px;">
                            <div style="font-size:3.5em;margin-bottom:16px;">${s.emoji}</div>
                            <h2 style="color:white;font-size:1.3em;font-weight:900;margin:0 0 14px;">${s.title}</h2>
                            <p style="color:#94a3b8;font-size:0.9em;line-height:1.7;margin:0;">${s.text}</p>
                        </div>
                        <button onclick="window._onboardNext()" style="width:100%;padding:16px;background:linear-gradient(135deg,#16a34a,#15803d);color:white;border:none;border-radius:14px;font-size:1em;font-weight:900;cursor:pointer;margin-bottom:12px;">
                            ${s.btn}
                        </button>
                        ${!isLast ? `<button onclick="window._onboardSkip()" style="width:100%;padding:10px;background:transparent;border:none;color:rgba(255,255,255,0.3);font-size:0.85em;cursor:pointer;">Passer</button>` : ''}
                    </div>`;
            }

            window._onboardNext = function() {
                if (current < screens.length - 1) {
                    current++;
                    render(current);
                    haptic.light();
                } else {
                    window._onboardSkip();
                }
            };
            window._onboardSkip = function() {
                localStorage.setItem('fitproOnboardingDone', '1');
                ov.style.animation = 'restFadeIn 0.3s ease reverse';
                setTimeout(() => ov.remove(), 280);
            };

            render(0);
            document.body.appendChild(ov);
        }

        // Ajouter un sélecteur de thème dans les réglages (injecté dynamiquement)
        function addThemeSelectorToSettings() {
            const existing = document.getElementById('_themeSelector');
            if (existing) return;
            // Chercher la section apparence dans les réglages
            const darkToggle = document.querySelector('[onclick*="toggleDarkMode"]');
            if (!darkToggle) return;
            const parent = darkToggle.closest('.card, div');
            if (!parent) return;

            const pref = localStorage.getItem('darkModePreference') || 'dark';
            const sel  = document.createElement('div');
            sel.id     = '_themeSelector';
            sel.style.cssText = 'margin-top:10px;';
            sel.innerHTML = `
                <div style="font-size:0.78em;color:#94a3b8;margin-bottom:8px;font-weight:600;">Thème</div>
                <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;">
                    ${[['dark','🌙','Sombre'],['light','☀️','Clair'],['auto','🔄','Auto']].map(([mode,icon,label]) =>
                        `<button onclick="setThemeMode('${mode}');document.querySelectorAll('[data-theme-btn]').forEach(b=>b.style.background='rgba(255,255,255,0.05)');this.style.background='rgba(22,163,74,0.2)';this.style.borderColor='rgba(22,163,74,0.5)';"
                         data-theme-btn="${mode}"
                         style="padding:10px 6px;border-radius:10px;border:1px solid ${mode===pref?'rgba(22,163,74,0.5)':'rgba(255,255,255,0.12)'};background:${mode===pref?'rgba(22,163,74,0.2)':'rgba(255,255,255,0.05)'};color:#e2e8f0;font-size:0.82em;font-weight:700;cursor:pointer;">
                             ${icon} ${label}
                         </button>`
                    ).join('')}
                </div>`;
            darkToggle.parentNode.insertBefore(sel, darkToggle.nextSibling);
        }

