        // ========== THEME SYSTEM ==========
        // Thèmes supprimés — couleur violet fixe
        
        
        function checkAutoDarkMode() {
            const savedPref = localStorage.getItem('darkModePreference'); // 'dark' | 'light' | 'auto'
            if (savedPref === 'light') {
                document.body.classList.remove('dark-mode');
                return;
            }
            if (savedPref === 'dark' || !savedPref) {
                document.body.classList.add('dark-mode');
                return;
            }
            // 'auto' — suit le thème système
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            document.body.classList.toggle('dark-mode', prefersDark);
        }

        function initSystemThemeListener() {
            const mq = window.matchMedia('(prefers-color-scheme: dark)');
            mq.addEventListener('change', e => {
                if (localStorage.getItem('darkModePreference') === 'auto') {
                    document.body.classList.toggle('dark-mode', e.matches);
                }
            });
        }

        function checkStreakMilestone() {
            const stats = loadStats();
            const streak = stats.streak || 0;
            
            // Check if user just hit 30-day streak
            if (streak === 30) {
                const lastCelebration = localStorage.getItem('last30DayCelebration');
                const today = new Date().toDateString();
                
                if (lastCelebration !== today) {
                    localStorage.setItem('last30DayCelebration', today);
                    setTimeout(() => showFireworksCelebration(), 1000);
                }
            }
        }
        
        function showFireworksCelebration() {
            // Create overlay
            const overlay = document.createElement('div');
            overlay.className = 'celebration-overlay';
            overlay.innerHTML = `
                <div class="celebration-message">
                    <div style="font-size: 5em; margin-bottom: 20px;">🎉</div>
                    <h1 style="color: var(--primary-color); margin-bottom: 15px;">INCROYABLE !</h1>
                    <h2 style="margin-bottom: 20px;">30 jours consécutifs ! 🔥</h2>
                    <p style="font-size: 1.1em; color: #666; margin-bottom: 30px;">
                        Vous avez accompli quelque chose d'extraordinaire !<br>
                        Votre détermination est inspirante ! 💪
                    </p>
                    <button onclick="closeFireworksCelebration()" class="btn" 
                            style="background: linear-gradient(135deg, var(--primary-color) 0%, var(--primary-dark) 100%); padding: 15px 40px; font-size: 1.1em;">
                        🎆 Merci !
                    </button>
                </div>
            `;
            document.body.appendChild(overlay);
            
            // Create fireworks container
            const fireworksContainer = document.createElement('div');
            fireworksContainer.className = 'fireworks-container';
            fireworksContainer.id = 'fireworksContainer';
            document.body.appendChild(fireworksContainer);
            
            // Launch fireworks with context-aware colors
            const celebMode = getActiveCelebrity() ? 'celebrity' : 'normal';
            launchFireworks(celebMode);
            
            // Play celebration sound (if available)
            speak('Félicitations pour votre série de 30 jours !');
        }
        
        function launchFireworks(mode) {
            const container = document.getElementById('fireworksContainer');
            if (!container) return;

            // Palette selon le contexte
            let colors;
            if (mode === 'pr') {
                colors = ['#fbbf24','#f59e0b','#fcd34d','#fffbeb','#FFD700'];
            } else if (mode === 'celebrity') {
                const celeb = getActiveCelebrity();
                const base  = celeb ? celeb.color : '#16a34a';
                colors = [base, '#ffffff', base + 'aa', '#f59e0b', base];
                haptic.celebrity(base);
            } else {
                colors = ['#16a34a','#15803d','#ef4444','#f59e0b','#10b981','#06b6d4','#ec4899'];
            }

            let fireworkCount = 0;
            const maxFireworks = mode === 'pr' ? 20 : 30;

            const fireworkInterval = setInterval(() => {
                if (fireworkCount >= maxFireworks) { clearInterval(fireworkInterval); return; }
                const x = Math.random() * window.innerWidth;
                const y = Math.random() * (window.innerHeight * 0.6) + 50;
                createFireworkExplosion(x, y, colors[Math.floor(Math.random() * colors.length)]);
                fireworkCount++;
            }, mode === 'pr' ? 150 : 200);
        }
        
        function createFireworkExplosion(x, y, color) {
            const container = document.getElementById('fireworksContainer');
            if (!container) return;
            
            // Create multiple particles
            const particleCount = 30;
            for (let i = 0; i < particleCount; i++) {
                const particle = document.createElement('div');
                particle.className = 'firework';
                particle.style.left = x + 'px';
                particle.style.top = y + 'px';
                particle.style.background = color;
                
                // Random direction
                const angle = (Math.PI * 2 * i) / particleCount;
                const velocity = 50 + Math.random() * 50;
                const tx = Math.cos(angle) * velocity;
                const ty = Math.sin(angle) * velocity;
                
                particle.style.setProperty('--tx', tx + 'px');
                particle.style.setProperty('--ty', ty + 'px');
                
                container.appendChild(particle);
                
                // Remove after animation
                setTimeout(() => particle.remove(), 1000);
            }
        }
        
        function closeFireworksCelebration() {
            const overlay = document.querySelector('.celebration-overlay');
            const fireworks = document.getElementById('fireworksContainer');
            if (overlay) overlay.remove();
            if (fireworks) fireworks.remove();
        }